import {
  AddExpressionMenu,
  CopyExpression,
  DataGridActionViewSource,
  DdxData,
  ddxFormatter,
  DeleteExpression,
  DownloadActionMenu,
  FormExpressionBuilder,
  getDialogResizePaperPropsSx,
  ModelExpression,
  PasteMenu,
  RuleDisplayComponent,
  useDdxValues,
} from "@solvasam/bizcomponents";
import { ICellRendererParams } from "@textile/ag-grid";
import {
  ActionMenu,
  AsyncDataGridPanel,
  AsyncFormDialog,
  AsyncFormDialogProps,
  ColDefOverride,
  DataGridActionAdd,
  DataGridActionDelete,
  DataGridActionEdit,
  DataGridActionRefresh,
  DataGridDataServiceSource,
  DataGridQuickSearch,
  FabricAsyncOperation,
  FormDataServiceSource,
  FormTextField,
  useDialogActionCode,
} from "@textile/biz-components";
import { SxProps, Typography, useMediaQuery, useTheme } from "@textile/mui";
import { FunctionComponent, memo, useMemo } from "react";

import { ModelExpressionRule } from "../../screen.types";

const RulesFormDialog: FunctionComponent<
  Partial<AsyncFormDialogProps> & { ddxdata: DdxData }
> = memo((props) => {
  const actionCode = useDialogActionCode();
  const { ddxdata } = props;
  const theme = useTheme();
  const fullScreen = useMediaQuery(theme.breakpoints.down("md"));
  const mode = actionCode === "edit" ? "edit" : "add";

  const rulesFormSource = useMemo<FormDataServiceSource>(
    () => ({
      idField: "id",
      mode: mode,
      get: {
        url: "/compliance-bff/v1/modelExpressionRules",
      },
      save: {
        url: "/compliance-bff/v1/modelExpressionRules",
        method: mode === "add" ? "post" : "patch",
      },
    }),
    [mode]
  );

  const onBeforeSave = async (
    data: Partial<
      ModelExpressionRule & { applicability_expression: ModelExpression }
    >
  ) => {
    return {
      ...data,
      ddx: data.applicability_expression
        ? data.applicability_expression.ddx
        : null,
      applicability_expression: undefined,
    };
  };
  const onBeforeExpressionPopulate = (data: Partial<ModelExpressionRule>) => {
    const modelExpression: ModelExpression | undefined = {
      id: "",
      code: "",
      ddx_errors: [],
      ddx_expanded: null,
      friendly_description_expanded: null,
      raw_description: null,
      raw_description_expanded: null,
      modified_by: "",
      created_by: "",
      logic: data.logic ?? [],
      friendly_description: data?.friendly_description ?? null,
      ddx: data.ddx ?? "",
    };
    return Promise.resolve(
      data.friendly_description
        ? { ...data, applicability_expression: modelExpression }
        : data
    );
  };
  return (
    <AsyncFormDialog
      {...props}
      title={`${mode === "add" ? "Add" : "Edit"} Rule`}
      dataSource={rulesFormSource}
      fullScreen={fullScreen}
      fullWidth
      PaperProps={{
        sx: getDialogResizePaperPropsSx("720px"),
      }}
      onBeforeSave={onBeforeSave}
      onBeforePopulate={onBeforeExpressionPopulate}
      draggable={true}
      defaultData={{
        rule_name: "",
        applicability_expression: undefined,
        comments: "",
      }}
    >
      <FormTextField<ModelExpressionRule>
        fieldName="rule_name"
        label="Name"
        required={true}
      ></FormTextField>
      <FormExpressionBuilder
        id="applicability_expression"
        label="Expression"
        ddxProps={ddxdata}
      >
        <AddExpressionMenu />
        <DeleteExpression />
        <CopyExpression />
        <PasteMenu />
      </FormExpressionBuilder>
      <FormTextField<ModelExpressionRule>
        fieldName="comments"
        label="Comments"
        multiline
        minRows={3}
      ></FormTextField>
    </AsyncFormDialog>
  );
});

const gridSx: SxProps = {
  flex: "1 1 0px",
  minHeight: "24vmax",
  mb: 2,
};

const rulesDataSource: DataGridDataServiceSource = {
  url: "/compliance-bff/v1/modelExpressionRules:view",
};
const rulesDeleteOperation: FabricAsyncOperation = {
  url: "/compliance-bff/v1/modelExpressionRules:batchDelete",
  operationConfirmedParamLocation: "body",
  method: "post",
  idsField: "names",
};

export const RulesGrid: FunctionComponent = () => {
  const ddxData = useDdxValues();
  const colDefOverrides: ColDefOverride[] = [
    {
      field: "friendly_description",
      colDef: {
        field: "friendly_description",
        autoHeight: true,
        cellStyle: { "text-align": "left" },
        cellRenderer: (params: ICellRendererParams) => {
          return params.value ? (
            <RuleDisplayComponent
              value={ddxFormatter.format(params.value)}
            ></RuleDisplayComponent>
          ) : (
            <Typography variant="inherit">
              Rule has not been defined yet
            </Typography>
          );
        },
      },
    },
  ];

  return (
    <AsyncDataGridPanel
      dataSource={rulesDataSource}
      sx={gridSx}
      rowSelectionMode="multi"
      colDefOverrides={colDefOverrides}
      gridPersistOptions={{
        key: `RULES`,
        enabled: true,
      }}
    >
      <DataGridQuickSearch></DataGridQuickSearch>
      <DataGridActionAdd
        dialog={<RulesFormDialog ddxdata={ddxData}></RulesFormDialog>}
      ></DataGridActionAdd>
      <DataGridActionEdit
        dialog={<RulesFormDialog ddxdata={ddxData}></RulesFormDialog>}
      ></DataGridActionEdit>
      <DataGridActionDelete
        operation={rulesDeleteOperation}
        rowSelectionMode="multi"
      ></DataGridActionDelete>
      <DownloadActionMenu />
      <ActionMenu>
        <DataGridActionRefresh
          type="menuitem"
          icon={null}
        ></DataGridActionRefresh>
        <DataGridActionViewSource
          datasource={rulesDataSource}
          type="menuitem"
        />
      </ActionMenu>
    </AsyncDataGridPanel>
  );
};

