import {
  DataGridActionViewSource,
  DownloadActionMenu,
  useSelectedPortfolioId,
} from "@solvasam/bizcomponents";
import { GridApi, GridReadyEvent, ICellRendererParams } from "@textile/ag-grid";
import {
  ActionMenu,
  ActionTargetIds,
  AsyncDataGridPanel,
  ColDefOverride,
  DataGridActionAdd,
  DataGridActionDelete,
  DataGridActionEdit,
  DataGridActionRefresh,
  DataGridQuickSearch,
  FabricAsyncOperation,
  useRefreshToken,
} from "@textile/biz-components";
import {
  Screen,
  ScreenHeader,
  Splitter,
  useAxiosFactory,
  useMessageAnnouncer,
  useStaticAppContext,
  OpenInNewIcon,
  NextIcon,
} from "@textile/common";
import {
  Divider,
  IconButton,
  Stack,
  SxProps,
  Tab,
  Tabs,
  Typography,
  useMediaQuery,
  useTheme,
} from "@textile/mui";
import {
  FunctionComponent,
  SetStateAction,
  SyntheticEvent,
  useCallback,
  useMemo,
  useRef,
  useState,
} from "react";

import { ModelAddEditDialog } from "./model-add-edit-dialog.component";
import ModelCompareActionDialog from "./model-compare-dialog.component";
import ModelCopyActionDialog from "./model-copy-dialog.component";
import ModelExportDialogAction from "./model-export-dialog.component";
import { useSnapshotModel } from "./useSnapshotModel";
import { ComplianceModel } from "../snapshot-models.types";
import { formatDate } from "../../common";
import { ScreenProps } from "../../screen.types";
import { StatusHistory } from "./models-tab.component";
import { CalculationStepGrid } from "../../calculation-sequence/calculation-step-grid.component";
import { useFetch } from "../../common/useFetch";
import { PriorityOfPaymentsGrid } from "../../priority-of-payments/waterfalls/priority-of-payments-grid.component";
import { PaymentGroupGrid } from "../../priority-of-payments/payment-groups/payment-group-grid.component";
import { EligibilityCriteriaGrid } from "../../tests/eligibility-criteria/eligibility-criteria-screen.component";
import { ComplianceTestGrid } from "../../tests/compliance-tests/compliance-tests-grid.component";
import { Link } from "react-router-dom";
import { useModelRefreshNeedReviewOnChildGrid } from "../../common/refresh-need-review.hook";
import { detailsContainerSx } from "../../common/common.component";
import { ModelLockUnlockCellRenderer } from "./model-lock-unlock-dialog.component";

const gridSx: SxProps = { flex: "1 1 0px" };
const screenSx: SxProps = { display: "flex", flexDirection: "column" };

interface ModelsGetResponse {
  compliance_models: ComplianceModel[];
}

export const ModelsGrid: FunctionComponent<ScreenProps> = () => {
  const [selectedPortfolioId] = useSelectedPortfolioId();
  const { displayModelDataSource } = useSnapshotModel(selectedPortfolioId);
  const [token, refresh] = useRefreshToken();
  const [selectedModel, setModelsSelected] = useState<ComplianceModel>();
  const [selectedModelIdsForDelete, setSelectedModelIdsForDelete] =
    useState<string[]>();
  const axiosFactory = useAxiosFactory();
  const messageAnnouncer = useMessageAnnouncer();
  const { sharedAppContextManager } = useStaticAppContext();
  const [viewSource, setViewSource] = useState();
  const { state: selectedActiveModel, setState: setSelectedActiveModel } =
    sharedAppContextManager.useContext<string>("app.selectedModel");
  const abortController = new AbortController();

  const modelColdefoverrides: ColDefOverride[] = [
    {
      field: "state",
      colDef: {
        field: "state",
        cellRenderer: (params: ICellRendererParams) =>
          ModelLockUnlockCellRenderer({ ...params, refresh }),
        cellStyle: { textAlign: "center" },
      },
    },
    {
      field: "begin_date_description",
      colDef: {
        cellRenderer: (props: ICellRendererParams) => {
          return formatDate(props.value?.toString()?.replace(/^"|"$/g, ""));
        },
      },
    },
    {
      field: "end_date_description",
      colDef: {
        cellRenderer: (props: ICellRendererParams) => {
          return formatDate(props.value?.toString()?.replace(/^"|"$/g, ""));
        },
      },
    },
  ];

  const modelDeleteOperation = useMemo<FabricAsyncOperation>(
    () => ({
      url: `/compliance-bff/v1/portfolios/${selectedPortfolioId}/models:batchDelete`,
      operationConfirmedParamLocation: "body",
      method: "post",
      idsField: "names",
    }),
    [selectedPortfolioId]
  );

  const onModelSelect = (selectedData: ComplianceModel[]) => {
    setModelsSelected(selectedData.length == 1 ? selectedData[0] : undefined);
    setSelectedModelIdsForDelete(selectedData.map((model) => model.id));
  };

  const stackSx: SxProps = { flexDirection: "row", flexGrow: 1 };

  const theme = useTheme();
  const fullScreen = useMediaQuery(theme.breakpoints.down("md"));
  const [selectedTab, setSelectedTab] = useState("status_history");
  const handleTabChange = (
    _event: SyntheticEvent,
    newValue: SetStateAction<string>
  ) => {
    setSelectedTab(newValue);
  };
  const handleNextTab = () => {
    const tabs = [
      "status_history",
      "calculation_sequence",
      "priority_of_payments",
      "priority_of_payment_groups",
      "eligilibility_criteria_tests",
      "compliance_tests",
    ];
    const currentIndex = tabs.indexOf(selectedTab);
    const nextIndex = (currentIndex + 1) % tabs.length;
    setSelectedTab(tabs[nextIndex]);
  };
  const deps = useCallback(
    () =>
      selectedModel?.id && selectedPortfolioId
        ? [selectedModel?.id, selectedPortfolioId]
        : [],
    [selectedModel?.id, selectedPortfolioId]
  );

  const { data } = useFetch<ComplianceModel>({
    url: `/compliance-bff/v1/portfolios/${selectedPortfolioId}/models/${selectedModel?.id}`,
    method: "GET",
    deps: deps(),
  });
  const editButtonRef = useRef<HTMLButtonElement>(null);
  const agGridApiRef = useRef<GridApi | null>(null);

  useModelRefreshNeedReviewOnChildGrid(
    selectedPortfolioId,
    selectedModel?.id,
    agGridApiRef
  );

  const setActiveModel = useCallback(async () => {
    try {
      const axios = await axiosFactory.createAxiosInstance();
      const { data } = await axios.get<ModelsGetResponse>(
        `/compliance-bff/v1/portfolios/${selectedPortfolioId}/models`,
        { signal: abortController.signal }
      );

      const models = data.compliance_models ?? [];
      const foundActiveModel = models.find(
        (model) => model.id === selectedActiveModel
      );

      if (!foundActiveModel && models.length > 0) {
        setSelectedActiveModel(models[0].id);
      }
    } catch (error) {
      messageAnnouncer.error(`Failed to load Models: ${error}`);
    }
  }, [
    axiosFactory,
    selectedPortfolioId,
    abortController.signal,
    selectedActiveModel,
    setSelectedActiveModel,
    messageAnnouncer,
  ]);

  const getErrorMessage = (
    actionName: string,
    targetIds: ActionTargetIds,
    error: unknown
  ) => {
    selectedModelIdsForDelete?.includes(selectedActiveModel)
      ? setActiveModel()
      : null;
    refresh();
    setModelsSelected(undefined);
    return `Failed to process operation ${actionName}: ${
      typeof error === "object" && error !== null && "message" in error
        ? (error as { message: string }).message
        : undefined
    }`;
  };

  return (
    <Screen sx={screenSx} navigationId="compliance-modeling-ui-models">
      <ScreenHeader></ScreenHeader>
      <Stack sx={stackSx} direction={"row"}>
        <Splitter expandable={true}>
          <Stack sx={{ flex: "1 1 0px" }} direction={"column"}>
            <AsyncDataGridPanel
              refreshToken={token}
              sx={gridSx}
              dataSource={displayModelDataSource}
              rowSelectionMode="multi"
              onSelectionChanged={onModelSelect}
              colDefOverrides={modelColdefoverrides}
              agGridProps={{
                suppressRowClickSelection: true,
                onGridReady: (event: GridReadyEvent) => {
                  agGridApiRef.current = event.api;
                },
                onCellClicked: (e) => {
                  if (e.colDef.field !== "state") {
                    e.node.setSelected(true);
                  }
                },
              }}
            >
              <DataGridQuickSearch></DataGridQuickSearch>
              <Divider orientation="vertical" flexItem></Divider>
              <ModelCompareActionDialog
                portfolioId={selectedPortfolioId}
                model={selectedModel}
              />

              <ModelExportDialogAction
                portfolioId={selectedPortfolioId}
                model={selectedModel}
              />
              <Divider orientation="vertical" flexItem></Divider>
              <DataGridActionAdd
                dialog={
                  <ModelAddEditDialog
                    portfolioId={selectedPortfolioId}
                    refreshGrid={refresh}
                  />
                }
              ></DataGridActionAdd>
              <DataGridActionEdit
                dialog={
                  <ModelAddEditDialog
                    portfolioId={selectedPortfolioId}
                    refreshGrid={refresh}
                  />
                }
              ></DataGridActionEdit>
              <DataGridActionDelete
                operation={modelDeleteOperation}
                rowSelectionMode="multi"
                getErrorMessage={getErrorMessage}
                onUpdateUi={() => {
                  refresh();
                  setModelsSelected(undefined);
                  setActiveModel();
                }}
              ></DataGridActionDelete>
              <ModelCopyActionDialog
                portfolioId={selectedPortfolioId}
                refreshGrid={refresh}
              />

              <ActionMenu>
                <DownloadActionMenu isPopover={true} />
                <DataGridActionRefresh
                  type="menuitem"
                  icon={null}
                ></DataGridActionRefresh>
                <DataGridActionViewSource
                  datasource={displayModelDataSource}
                  type="menuitem"
                />
              </ActionMenu>
            </AsyncDataGridPanel>
          </Stack>
          {selectedModel?.id ? (
            <Stack gap={0.5} direction="column" sx={detailsContainerSx}>
              <Stack direction="row" sx={{ pr: 1.5, pt: 1 }}>
                <Tabs
                  variant={fullScreen ? "fullWidth" : "standard"}
                  value={selectedTab}
                  onChange={handleTabChange}
                >
                  <Tab value="status_history" label="Status History" />
                  <Tab
                    value="calculation_sequence"
                    label="Calculation Sequence"
                  />
                  <Tab
                    value="priority_of_payments"
                    label="Priority Of Payments"
                  />
                  <Tab
                    value="priority_of_payment_groups"
                    label="Priority Of Payments Groups"
                  />
                  <Tab
                    value="eligilibility_criteria_tests"
                    label="Eligibility Criteria Tests"
                  />
                  <Tab value="compliance_tests" label="Compliance Tests" />
                </Tabs>
                <IconButton
                  onClick={handleNextTab}
                  edge="end"
                  aria-label={"Expand"}
                >
                  <NextIcon size={20} />
                </IconButton>
              </Stack>
              {selectedTab === "status_history" ? (
                <StatusHistory modelId={selectedModel?.id}></StatusHistory>
              ) : selectedTab === "calculation_sequence" ? (
                <CalculationStepGrid
                  sequenceId={data?.sequence_id ?? ""}
                  portfolioId={selectedPortfolioId ?? ""}
                  modelId={selectedModel?.id}
                  coldefOverrides={[
                    {
                      field: "is_in_sequence",
                      colDef: {
                        field: "is_in_sequence",
                        headerName: "Is In Sequence",
                        hide: true,
                      },
                    },
                  ]}
                  rowSelectionMode="singleRow"
                  titleComponent={
                    <TitleWithIcon
                      title={"Calculation Steps"}
                      tolink={`/compliance-modeling-ui/${selectedPortfolioId}/${selectedModel?.id}/calculation-sequence`}
                    ></TitleWithIcon>
                  }
                >
                  <DownloadActionMenu />
                  <DataGridActionViewSource
                    datasource={viewSource ?? ""}
                    type="menuitem"
                  />
                </CalculationStepGrid>
              ) : selectedTab === "priority_of_payments" ? (
                <PriorityOfPaymentsGrid
                  editButtonRef={editButtonRef}
                  selectedModelId={selectedModel?.id}
                  rowSelectionMode="singleRow"
                  titleComponent={
                    <TitleWithIcon
                      title={"Priority of Payments"}
                      tolink={`/compliance-modeling-ui/${selectedPortfolioId}/${selectedModel?.id}/priority-of-payments`}
                    ></TitleWithIcon>
                  }
                >
                  <DownloadActionMenu />
                </PriorityOfPaymentsGrid>
              ) : selectedTab === "priority_of_payment_groups" ? (
                <PaymentGroupGrid
                  editButtonRef={editButtonRef}
                  selectedModelId={selectedModel?.id}
                  rowSelectionMode="singleRow"
                  titleComponent={
                    <TitleWithIcon
                      title={"Priority of Payments Groups"}
                      tolink={`/compliance-modeling-ui/${selectedPortfolioId}/${selectedModel?.id}/priority-of-payments?tab=pg`}
                    ></TitleWithIcon>
                  }
                >
                  <DownloadActionMenu />
                </PaymentGroupGrid>
              ) : selectedTab === "eligilibility_criteria_tests" ? (
                <EligibilityCriteriaGrid
                  modelId={selectedModel?.id}
                  refreshDetails={refresh}
                  selectedPortfolioId={selectedPortfolioId ?? ""}
                  editButtonRef={editButtonRef}
                  rowSelectionMode="single"
                  titleComponent={
                    <TitleWithIcon
                      title={"Eligibility Criteria"}
                      tolink={`/compliance-modeling-ui/${selectedPortfolioId}/${selectedModel?.id}/tests/eligibility-criteria`}
                    ></TitleWithIcon>
                  }
                >
                  <DownloadActionMenu />
                </EligibilityCriteriaGrid>
              ) : selectedTab === "compliance_tests" ? (
                <ComplianceTestGrid
                  selectedModelId={selectedModel?.id}
                  rowSelectionMode="single"
                  titleComponent={
                    <TitleWithIcon
                      title={"Compliance Tests"}
                      tolink={`/compliance-modeling-ui/${selectedPortfolioId}/${selectedModel?.id}/tests/compliance-tests`}
                    ></TitleWithIcon>
                  }
                >
                  <DownloadActionMenu />
                </ComplianceTestGrid>
              ) : null}
            </Stack>
          ) : null}
        </Splitter>
      </Stack>
    </Screen>
  );
};

interface TitleWithIconProps {
  title: string;
  tolink: string;
}

const TitleWithIcon: React.FC<TitleWithIconProps> = ({ title, tolink }) => {
  const theme = useTheme();
  return (
    <>
      <Typography variant="subtitle2" fontWeight={600}>
        {title}
      </Typography>
      <Link to={tolink}>
        <IconButton
          aria-label="Open in Same Window"
          sx={{ color: theme.palette.info.main, pl: 1 }}
        >
          <OpenInNewIcon size={24} />
        </IconButton>
      </Link>
    </>
  );
};

import {
  AsyncDataGridPanel,
  ColDefOverride,
  DataGridActionEdit,
  DataGridDataServiceSource,
  DataGridQuickSearch,
  DataGridActionAdd,
  DataGridAsyncDialogAction,
  ActionMenu,
  ActionTargetIds,
  ActionButton,
  caseInsensitiveComparator,
} from "@textile/biz-components";
import { IconButtonProps, SxProps, Switch } from "@textile/mui";
import {
  Fragment,
  FunctionComponent,
  useEffect,
  useMemo,
  useRef,
  useCallback,
  useContext,
  MutableRefObject,
  ReactNode,
  createContext,
} from "react";
import {
  AddCalculationSeqStepType,
  CalculationSequenceStep,
} from "./calculation-sequence.types";
import { DuplicateIcon, useStaticAppContext } from "@textile/common";
import {
  GridApi,
  GridReadyEvent,
  ICellRendererParams,
  RowDragEvent,
} from "@textile/ag-grid";
import { AddtoSequenceComponent } from "./add-calculation-sequence/add-sequence-step.component";
import { usePopulateSuccessMessage } from "../common";
import { SequenceStepBatchDeleteAction } from "./sequence-step-batch-delete-action.component";
import { baseUrl } from "../../apis";
import { useFetch } from "../common/useFetch";
import { DuplicateCalculationSequenceComponent } from "./duplicate-calculation-sequence/duplicate-sequence-step.component";
import { AddCalculationSeqChildComponent } from "./add-calculation-sequence-child.component";
import { AddTreeGridChildContext } from "../common/add-tree-grid-child-context.component";
import { DisplayOrderCellRenderer } from "../tests/common/display-order-cell-renderer.component";
import { getTotalSteps } from "../common/helpers";
import {
  DataGridActionViewSource,
  DownloadActionMenu,
  NumericCellEditor,
} from "@solvasam/bizcomponents";
import { useUpdateSequenceOrderOrPriority } from "./hooks/useUpdateSequenceOrderOrPriority.component";
import { useSearchParams } from "react-router-dom";

import { useSequenceNeedReviewRefresh } from "./common/sequence-need-review-refresh.hook";
import { formatUtcToString } from "../common/adjust-date-time-offset";

const gridSx: SxProps = {
  flex: "1 1 0px",
  minHeight: "30vmax",
  height: "100%",
};

interface CalculationStepProps {
  onSelectionChanged?: (
    selectedRecord: CalculationSequenceStep[] | null,
    groupId: string
  ) => void;
  sequenceId: string;
  modelId?: string;
  portfolioId?: string;
  sequenceStepSelection?: Partial<CalculationSequenceStep>[] | null;
  refreshView?: () => void;
  updateRefreshGrid?: (refreshGrid: () => void | null) => void;
  childValueRef?: MutableRefObject<string | null>;
  children?: ReactNode;
  coldefOverrides?: ColDefOverride[];
  titleComponent?: React.ReactElement<
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    any,
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    string | React.JSXElementConstructor<any>
  >;
  rowSelectionMode?: "singleRow" | "multiRow";
  onGridApiReady?: (event: GridReadyEvent) => void;
}

interface InSequenceRendererProps {
  sequenceId: string;
  modelId?: string;
  portfolioId?: string;
  refresh?: () => void;
  agGridApiRef: React.MutableRefObject<GridApi | null>;
  disabled: boolean;
}

type SequenceStepGridActionContextType = {
  portfolioId: string;
  modelId: string;
  sequenceId: string;
  selectedModelstate: string | null;
  sequenceStepSelection: Partial<CalculationSequenceStep>[] | null | undefined;
  refreshView?: (() => void) | undefined;
  refresh?: () => void;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  agGridApiRef?: MutableRefObject<GridApi<any> | null>;
  handleSelectionChange?: (
    selectedRecords: CalculationSequenceStep[] | undefined
  ) => void;
  calculationSequenceSource: DataGridDataServiceSource;
};

const SequenceStepGridActionContext =
  createContext<SequenceStepGridActionContextType>({
    portfolioId: "",
    modelId: "",
    selectedModelstate: null,
    sequenceId: "",
    sequenceStepSelection: undefined,
    refreshView: undefined,
    refresh: undefined,
    agGridApiRef: undefined,
    handleSelectionChange: undefined,
    calculationSequenceSource: {},
  });

export const CalculationStepGrid: FunctionComponent<CalculationStepProps> = ({
  onSelectionChanged,
  sequenceId,
  portfolioId,
  modelId,
  sequenceStepSelection,
  refreshView,
  updateRefreshGrid,
  childValueRef,
  children: children,
  coldefOverrides: extraColdef,
  titleComponent,
  rowSelectionMode = "multiRow",
  onGridApiReady,
}) => {
  const agGridApiRef = useRef<GridApi | null>(null);
  const { sharedAppContextManager } = useStaticAppContext();
  const { state: selectedModelstate } = sharedAppContextManager.useContext<
    string | null
  >("app.selectedModelState");
  const { childIdRef, updateChildValue, refreshToken, refresh } = useContext(
    AddTreeGridChildContext
  );

  const [searchParams] = useSearchParams();
  const rowId = searchParams.get("rowId");
  useEffect(() => {
    if (updateRefreshGrid) updateRefreshGrid(refresh);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    return () => {
      agGridApiRef.current = null;
    };
  }, [agGridApiRef]);

  const calculationSequenceSource = useMemo<DataGridDataServiceSource>(
    () => ({
      url: `${baseUrl}/portfolios/${portfolioId}/models/${modelId}/sequences/${sequenceId}/steps:view`,
    }),
    [portfolioId, sequenceId, modelId]
  );

  const { updateSequenceStep, updatePriorityValue, updateOrderValue } =
    useUpdateSequenceOrderOrPriority({
      modelId,
      portfolioId,
      sequenceId,
      agGridApiRef,
      refresh,
      refreshView,
    });

  const colDefOverrides: ColDefOverride[] = useMemo(
    () => [
      {
        field: "begin_date_description",
        colDef: {
          cellRenderer: (props: ICellRendererParams) => {
            return props.value
              ? formatUtcToString(
                  props.value?.toString()?.replace(/^"|"$/g, ""),
                  "DD MMM YYYY"
                )
              : null;
          },
        },
      },
      {
        field: "type_description",
        colDef: {
          filter: "agMultiColumnFilter",
        },
      },
      {
        field: "end_date_description",
        colDef: {
          cellRenderer: (props: ICellRendererParams) => {
            return props.value
              ? formatUtcToString(
                  props.value?.toString()?.replace(/^"|"$/g, ""),
                  "DD MMM YYYY"
                )
              : null;
          },
        },
      },
      {
        field: "is_in_sequence",

        colDef: {
          field: "is_in_sequence",
          cellStyle: { "text-align": "center" },
          autoHeight: true,
          cellRenderer: (params: ICellRendererParams) => {
            return (
              <InSequenceCellRenderer
                agGridApiRef={agGridApiRef}
                portfolioId={portfolioId}
                modelId={modelId}
                sequenceId={sequenceId}
                refresh={refresh}
                disabled={
                  selectedModelstate === "L" ||
                  (params?.node?.data?.priority &&
                    (params?.node?.data?.order === null ||
                      params?.node?.data?.order === 0))
                }
                {...params}
              ></InSequenceCellRenderer>
            );
          },
        },
      },
      {
        field: "priority",
        colDef: {
          field: "priority",
          editable: (params) => (params?.data?.priority ? true : false),
          cellEditor: NumericCellEditor,
          cellEditorParams: {
            // make "dataType" value available to cell editor
            dataType: "string",
            max:
              sequenceStepSelection?.[0]?.child_count &&
              Number(sequenceStepSelection?.[0]?.child_count) + 1,
            min: 0,
          },
          cellRenderer: DisplayOrderCellRenderer,
          minWidth: 130,
          valueGetter: (params) =>
            params?.data?.priority != null
              ? Number(params.data.priority)
              : null,
          comparator: caseInsensitiveComparator,
          cellRendererParams: {
            suppressCount: true,
          },
          onCellValueChanged: (params) => {
            const newValue = params.newValue;
            const oldValue = params.oldValue;
            const record = params.data;

            if (newValue !== oldValue) {
              updatePriorityValue(record, newValue);
            }
          },
          headerClass: "ag-left-aligned-header",
        },
      },
    ],
    [
      portfolioId,
      modelId,
      sequenceId,
      refresh,
      selectedModelstate,
      updatePriorityValue,
      sequenceStepSelection,
    ]
  );

  const onRowDragMove = async (event: RowDragEvent) => {
    const movingNode = event.node;
    const overNode = event.overNode;
    if (
      movingNode !== overNode &&
      movingNode?.data?.order &&
      overNode?.data?.order
    ) {
      if (!movingNode?.data?.is_in_sequence) return;
      updateSequenceStep(movingNode, overNode, "order");
    } else if (
      movingNode !== overNode &&
      (movingNode?.data?.order === null || movingNode?.data?.order === 0) &&
      movingNode?.data?.priority &&
      overNode?.data?.priority
    ) {
      const movingNodeParentId = movingNode?.data?.tree_data_path.includes("/")
        ? movingNode?.data?.tree_data_path?.split("/")[0]
        : null;
      const overNodeParentId = overNode?.data?.tree_data_path.includes("/")
        ? overNode?.data?.tree_data_path?.split("/")[0]
        : null;
      if (movingNodeParentId !== overNodeParentId) return;
      updateSequenceStep(movingNode, overNode, "priority");
    }
  };

  const onGridReady = (event: GridReadyEvent) => {
    agGridApiRef.current = event.api;
    onGridApiReady?.(event);
    if (rowId) {
      const rowNode = agGridApiRef.current.getRowNode(rowId);

      if (rowNode) {
        const parentNode = rowNode.parent;
        rowNode.setSelected(true);
        agGridApiRef.current?.ensureIndexVisible(
          parentNode?.sourceRowIndex ?? rowNode.sourceRowIndex,
          "top"
        );
      }
    }

    if (rowSelectionMode === "multiRow") {
      event.api.sizeColumnsToFit({
        columnLimits: [{ key: "order", minWidth: 120 }],
      });
    }
  };

  const onRowDataUpdated = useCallback(() => {
    const rowData: CalculationSequenceStep[] = [];
    if (childIdRef.current || (childValueRef && childValueRef.current)) {
      const childNodeId =
        childIdRef.current ?? (childValueRef && childValueRef.current);
      if (childNodeId) {
        let childNode = agGridApiRef.current?.getRowNode(childNodeId);
        if (
          !childNode &&
          sequenceStepSelection &&
          sequenceStepSelection.length > 0
        ) {
          if (childValueRef && childValueRef.current) {
            childNode = agGridApiRef.current?.getRowNode(
              `${sequenceStepSelection[0].tree_data_path}`
            );
          } else {
            childNode = agGridApiRef.current?.getRowNode(
              `${sequenceStepSelection[0].id}/${childNodeId}`
            );
          }
        }
        rowData.push(childNode?.data);
        childNode?.setSelected(true);
        handleSelectionChange(rowData);
        updateChildValue(null);
        if (childValueRef) childValueRef.current = null;
      }
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [sequenceStepSelection]);

  const handleSelectionChange = useCallback(
    (selectedRecords: CalculationSequenceStep[] | undefined) => {
      const selectedRows: CalculationSequenceStep[] | undefined =
        agGridApiRef.current?.getSelectedRows() || selectedRecords;
      if (selectedRows) {
        const treePath = selectedRows[0]?.tree_data_path;
        const parentId = treePath?.split("/")[0];
        const node = agGridApiRef.current?.getRowNode(parentId);
        node?.setExpanded(true);
        if (childIdRef.current || (childValueRef && childValueRef.current)) {
        } else {
          onSelectionChanged !== undefined
            ? selectedRecords?.length && selectedRecords?.length > 0
              ? onSelectionChanged(selectedRecords, node?.data?.item_id ?? "")
              : onSelectionChanged(null, "")
            : null;
        }
      }
    },
    [childIdRef, childValueRef, onSelectionChanged]
  );

  const processOrderCellCallback = (params: any) => {
    if (params.column.getColDef().field === "order") {
      return params.node?.data.order;
    }
    return params.value;
  };

  useSequenceNeedReviewRefresh(agGridApiRef, modelId);

  return (
    <Fragment>
      <AsyncDataGridPanel
        dataSource={
          portfolioId && modelId && sequenceId
            ? calculationSequenceSource
            : null
        }
        onSelectionChanged={handleSelectionChange}
        sx={gridSx}
        refreshToken={refreshToken}
        colDefOverrides={
          extraColdef && extraColdef.length >= 0 ? extraColdef : colDefOverrides
        }
        titleComponent={titleComponent}
        gridPersistOptions={{
          key: "CALC_SEQUENCE",
          enabled: true,
        }}
        agGridProps={{
          defaultColDef: {
            cellDataType: false,
          },
          defaultCsvExportParams: {
            processCellCallback: processOrderCellCallback,
          },
          defaultExcelExportParams: {
            processCellCallback: processOrderCellCallback,
          },
          onRowDragEnd: onRowDragMove,
          onGridReady: onGridReady,
          onRowDataUpdated: onRowDataUpdated,
          rowSelection: {
            mode: rowSelectionMode,
            enableClickSelection: true,
            checkboxes: rowSelectionMode == "multiRow",
            groupSelects: "self",
          },
          groupDefaultExpanded: 0,
          singleClickEdit: false,
          enableGroupEdit: true,
          stopEditingWhenCellsLoseFocus: true,
          onCellClicked: (params) => {
            if (
              params.node.group &&
              params.column.getColDef().field !== "order"
            ) {
              params.node.setExpanded(!params.node.expanded);
            }
          },
          autoGroupColumnDef: {
            rowDrag: rowSelectionMode === "multiRow",
            editable:
              rowSelectionMode === "multiRow"
                ? (params) => params?.data?.order && params?.data?.order !== "0"
                : false,
            cellEditor: NumericCellEditor,
            cellEditorParams: {
              // make "dataType" value available to cell editor
              dataType: "string",
              max: getTotalSteps(agGridApiRef).length,
            },
            headerName: "Order",
            field: "order",
            initialWidth: 140,
            cellStyle:
              rowSelectionMode === "multiRow"
                ? {}
                : {
                    "text-align": "right",
                  },
            cellRendererParams: {
              suppressCount: true,
              innerRenderer:
                rowSelectionMode === "multiRow"
                  ? DisplayOrderCellRenderer
                  : undefined,
            },
            valueGetter: (params) =>
              params?.data?.order != null ? Number(params.data.order) : null,
            comparator: caseInsensitiveComparator,
            onCellValueChanged: (params) => {
              const newValue = params.newValue;
              const oldValue = params.oldValue;
              const record = params.data;

              if (newValue !== oldValue) {
                updateOrderValue(record, newValue);
              }
            },
          },
        }}
      >
        <SequenceStepGridActionContext.Provider
          value={{
            portfolioId: portfolioId as string,
            modelId: modelId as string,
            sequenceId: sequenceId,
            sequenceStepSelection: sequenceStepSelection,
            refreshView: refreshView,
            refresh: refresh,
            handleSelectionChange: handleSelectionChange,
            agGridApiRef: agGridApiRef,
            selectedModelstate: selectedModelstate,
            calculationSequenceSource: calculationSequenceSource,
          }}
        >
          {children}
        </SequenceStepGridActionContext.Provider>
      </AsyncDataGridPanel>
    </Fragment>
  );
};

const InSequenceCellRenderer = (
  props: ICellRendererParams & InSequenceRendererProps
) => {
  const {
    data,
    portfolioId,
    modelId,
    sequenceId,
    refresh,
    agGridApiRef,
    disabled,
  } = props;
  const buttonRef = useRef<HTMLButtonElement>(null);

  const deps = useCallback(
    () =>
      modelId && portfolioId && sequenceId && data && refresh
        ? [modelId, portfolioId, sequenceId, data, refresh]
        : [],
    [modelId, portfolioId, sequenceId, data, refresh]
  );

  const { fetchData: deleteData } = useFetch({
    url: "",
    method: "DELETE",
    deps: deps(),
    autoFetch: false,
  });

  const { fetchData } = useFetch<AddCalculationSeqStepType>({
    url: "",
    method: "POST",
    deps: deps(),
    autoFetch: false,
  });

  const onOperationConfirmed = async () => {
    if (data?.is_in_sequence) {
      agGridApiRef.current?.setGridOption("loading", true);
      deleteData(
        `${baseUrl}/portfolios/${portfolioId}/models/${modelId}/sequences/${sequenceId}/steps/${data?.id}?operation_confirmed=1`
      ).then((resp) => {
        if (resp?.status === 200) refresh ? refresh() : null;
      });
      agGridApiRef.current?.setGridOption("loading", false);
    } else {
      agGridApiRef.current?.setGridOption("loading", true);
      const totalStepOrders = getTotalSteps(agGridApiRef);

      let reqObject = {};
      if (Number(data?.order) === 0) {
        reqObject = {
          sequence_step: {
            ...data,
            order: totalStepOrders.length + 1,
            is_in_sequence: true,
          },
        };
      } else {
        reqObject = {
          sequence_step: {
            ...data,
            is_in_sequence: true,
          },
        };
      }

      fetchData(
        `${baseUrl}/portfolios/${portfolioId}/models/${modelId}/sequences/${sequenceId}/steps?operation_confirmed=1`,
        { ...reqObject }
      ).then((resp) => {
        if (resp?.status === 200) refresh ? refresh() : null;
      });
      agGridApiRef.current?.setGridOption("loading", false);
    }
  };
  const handleSwitchClick = () => {
    agGridApiRef.current?.getRowNode(data.id)?.setSelected(false);
    onOperationConfirmed();
  };
  return (
    <>
      <Switch
        checked={data?.is_in_sequence}
        disabled={disabled}
        ref={buttonRef}
        sx={{
          position: "absolute",
          top: "50%",
          left: "50%",
          transform: "translate(-50%, -50%)",
        }}
        onClick={handleSwitchClick}
      ></Switch>
    </>
  );
};

export const CalculationSequenceStepGridActions = () => {
  const {
    handleSelectionChange,
    modelId,
    portfolioId,
    refresh,
    refreshView,
    sequenceId,
    sequenceStepSelection,
    agGridApiRef,
    selectedModelstate,
    calculationSequenceSource,
  } = useContext(SequenceStepGridActionContext);

  const iconButtonProps = useMemo<IconButtonProps>(() => {
    return selectedModelstate === "L" ||
      (sequenceStepSelection &&
        Number(sequenceStepSelection?.[0]?.order) === 0) ||
      (sequenceStepSelection && sequenceStepSelection?.[0]?.order === null) ||
      (sequenceStepSelection &&
        Number(sequenceStepSelection[0]?.order) === 0 &&
        sequenceStepSelection[0]?.priority === null)
      ? { disabled: true }
      : {};
  }, [selectedModelstate, sequenceStepSelection]);

  const iconButtonPropsForDelete = useMemo<IconButtonProps>(() => {
    return selectedModelstate === "L" ||
      !sequenceStepSelection ||
      (sequenceStepSelection && sequenceStepSelection[0]?.type === "PROJ") ||
      (sequenceStepSelection &&
        sequenceStepSelection[0]?.order === null &&
        sequenceStepSelection[0]?.priority === null)
      ? { disabled: true }
      : {};
  }, [selectedModelstate, sequenceStepSelection]);

  const iconButtonPropsforCopy = useMemo<IconButtonProps>(() => {
    return selectedModelstate === "L" ||
      (sequenceStepSelection && sequenceStepSelection.length > 1) ||
      (sequenceStepSelection && sequenceStepSelection?.[0]?.order === null) ||
      (sequenceStepSelection && Number(sequenceStepSelection?.[0]?.order) === 0)
      ? { disabled: true }
      : {};
  }, [selectedModelstate, sequenceStepSelection]);

  const populateSuccessMessage = usePopulateSuccessMessage();
  const handleOnSubmitComplete = (message: string) => {
    populateSuccessMessage(message);
  };

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const handleUpdateUi = (agGridApi: GridApi<any>, ids: ActionTargetIds) => {
    const id = ids ? ids[0] : null;
    const childNode = agGridApi?.getRowNode(id);

    if (childNode) {
      const updatedRecord = { ...childNode.data };

      agGridApi?.applyTransaction({ remove: [childNode.data] });
      const transactionResult = agGridApi?.applyTransaction({
        add: [updatedRecord],
        addIndex: Number(updatedRecord.order) - 1,
      });
      agGridApi?.ensureIndexVisible(Number(updatedRecord.order) - 1);

      if (transactionResult?.add?.[0]) {
        agGridApi?.getRowNode(updatedRecord.id)?.setSelected(true, true);
      }
    }
  };

  return (
    <>
      <DataGridQuickSearch></DataGridQuickSearch>
      {sequenceStepSelection === null ? (
        <DataGridActionAdd
          iconButtonProps={iconButtonProps}
          actionCode="add"
          onUpdateUi={(data, agGridApi, ids) => {
            handleUpdateUi(agGridApi, ids);
          }}
          dialog={
            <AddtoSequenceComponent
              portfolioId={portfolioId}
              modelId={modelId}
              sequenceId={sequenceId}
              refresh={refreshView}
            ></AddtoSequenceComponent>
          }
        ></DataGridActionAdd>
      ) : (
        sequenceStepSelection && (
          <AddCalculationSeqChildComponent
            portfolioId={portfolioId}
            modelId={modelId}
            refresh={refreshView}
            refreshGrid={refresh}
            selectedSequenceStep={sequenceStepSelection}
            action="add"
            disabled={iconButtonProps.disabled}
          ></AddCalculationSeqChildComponent>
        )
      )}
      <DataGridActionEdit
        iconButtonProps={iconButtonProps}
        actionCode="edit"
        onUpdateUi={(data, agGridApi, ids) => {
          handleUpdateUi(agGridApi, ids);
        }}
        dialog={
          <AddtoSequenceComponent
            portfolioId={portfolioId}
            modelId={modelId}
            sequenceId={sequenceId}
            refresh={refreshView}
          ></AddtoSequenceComponent>
        }
      ></DataGridActionEdit>
      <SequenceStepBatchDeleteAction
        partialUrl={`portfolios/${portfolioId}/models/${modelId}/sequences/${sequenceId}/steps`}
        iconButtonProps={iconButtonPropsForDelete}
        refresh={refresh ? refresh : () => undefined}
        gridApiRef={agGridApiRef}
        disabled={iconButtonPropsForDelete?.disabled}
        selectedRecords={sequenceStepSelection ?? null}
        stepList={agGridApiRef ? getTotalSteps(agGridApiRef) : []}
        onSubmitComplete={handleOnSubmitComplete}
      ></SequenceStepBatchDeleteAction>
      <DataGridAsyncDialogAction
        label="Duplicate"
        actionCode="duplicate"
        level="grid"
        type="icon"
        icon={<DuplicateIcon size={24} />}
        iconButtonProps={iconButtonPropsforCopy}
        loadOnOpen={false}
        onUpdateUi={refresh}
        dialog={
          <DuplicateCalculationSequenceComponent
            portfolioId={portfolioId}
            modelId={modelId}
            sequenceId={sequenceId}
            refresh={refreshView}
          />
        }
      />
      <ActionMenu>
        <DownloadActionMenu isPopover={true} />
        <ActionButton
          actionCode={"Refresh"}
          label={"Refresh"}
          type="menuitem"
          onClick={() => {
            handleSelectionChange?.(undefined);
            agGridApiRef?.current?.forEachNode((node) => {
              node.setExpanded(false);
              node.setSelected(false);
            });
            refresh?.();
          }}
        ></ActionButton>
        <DataGridActionViewSource
          datasource={calculationSequenceSource}
          type="menuitem"
        />
      </ActionMenu>
    </>
  );
};

