export const PriorityOfPaymentsGrid: FunctionComponent<
  PriorityOfPaymentsGridProps
> = ({
  onSelectionChanged,
  editButtonRef,
  selectedWaterfalls,
  selectedModelId,
  updateRefreshGrid,
  refreshGrid,
  refreshAfterUpdate,
  childValueRef,
