    string | null
  >("app.selectedModelState");
  const agGridApiRef = useRef<GridApi | null>(null);

  const { childIdRef, updateChildValue } = useContext(AddTreeGridChildContext);

  const maxPriority = useCallback((data: PriorityOfPayment) => {
    const totalSteps: PriorityOfPayment[] = [];
    agGridApiRef.current?.forEachNode(
      (rowNode: IRowNode<PriorityOfPayment>) => {
        if (rowNode.data) {
          totalSteps.push(rowNode.data);
        }
      }
    );
    const paymentGroupStepId = data?.tree_data_path.includes("/")
      ? data?.id
      : null;
    const paymentGroupId = data?.tree_data_path.includes("/")
      ? data?.tree_data_path?.split("/")[0]
      : null;
    if (paymentGroupStepId && paymentGroupId) {
      const matchId = paymentGroupStepId.split("_")[0];
      const filteredPaymentGroupSteps = totalSteps.filter((grp) =>
        grp.id.startsWith(`${matchId}_`)
      );
      return filteredPaymentGroupSteps.length > 0
        ? filteredPaymentGroupSteps.length
        : 0;
    }
  }, []);

  const priorityOfPaymentsDataSource = useMemo<DataGridDataServiceSource>(
    () => ({
