              ? formatUtcToString(
                  props.value?.toString()?.replace(/^"|"$/g, ""),
                  "DD MMM YYYY"
                )
              : null;
          },
        },
      },
      {
        field: "type_description",
        colDef: {
          filter: "agMultiColumnFilter",
        },
      },
      {
        field: "applicability_end_date_description",
        colDef: {
          cellRenderer: (props: ICellRendererParams) => {
            return props.value
              ? formatUtcToString(
                  props.value?.toString()?.replace(/^"|"$/g, ""),
                  "DD MMM YYYY"
                )
              : null;
          },
        },
      },
      {
        field: "applicability_criteria",
        colDef: {
          field: "applicability_criteria.description",
          headerName: "Applicability Criteria",
        },
      },
      {
        field: "priority",
        colDef: {
          field: "priority",
          editable: (params) =>
            params?.data?.priority && rowSelectionMode == "multiRow"
              ? true
              : false,
          cellEditor: NumericCellEditor,
          cellStyle: { "text-align": "center" },
          cellEditorParams: (params: { data: PriorityOfPayment }) => {
            const maxPriorityVal = maxPriority(params.data);
            return {
              // make "dataType" value available to cell editor
              dataType: "string",
              max: maxPriorityVal,
              min: 0,
            };
          },
          minWidth: 100,
          valueGetter: (params) =>
            params?.data?.priority != null
              ? Number(params.data.priority)
              : null,
          comparator: caseInsensitiveComparator,
          cellRenderer:
            rowSelectionMode == "multiRow"
              ? DisplayOrderCellRenderer
              : undefined,
          cellRendererParams: {
            suppressCount: true,
          },
          onCellValueChanged: (params) => {
            const newValue = params.newValue;
            const oldValue = params.oldValue;

            if (newValue !== oldValue) {
              updateOrderOrPriorityValue(params.data, null, newValue);
            }
          },
          headerClass: "ag-left-aligned-header",
        },
      },
    ],
    [maxPriority, updateOrderOrPriorityValue]
  );

  const onRowDragMove = async (event: RowDragEvent) => {
    const movingNode = event.node;
    const overNode = event.overNode;
    if (
      movingNode !== overNode &&
      movingNode?.data?.order &&
      overNode?.data?.order
    ) {
      updatePopStep(movingNode, overNode, "order");
    } else if (
      movingNode !== overNode &&
      (movingNode?.data?.order === null || movingNode?.data?.order === 0) &&
      movingNode?.data?.priority &&
      overNode?.data?.priority
    ) {
      const movingNodeParentId = movingNode?.data?.tree_data_path.includes("/")
        ? movingNode?.data?.tree_data_path?.split("/")[0]
        : null;
      const overNodeParentId = overNode?.data?.tree_data_path.includes("/")
        ? overNode?.data?.tree_data_path?.split("/")[0]
        : null;
      if (movingNodeParentId !== overNodeParentId) return;
      updatePopStep(movingNode, overNode, "priority");
    }
  };

  const onRowDataUpdated = useCallback(() => {
    const rowData: PriorityOfPayment[] = [];
    if (childIdRef.current || (childValueRef && childValueRef.current)) {
      const childNodeId =
        childIdRef.current ?? (childValueRef && childValueRef.current);
      if (childNodeId) {
        const childNode = agGridApiRef.current?.getRowNode(childNodeId);
        rowData.push(childNode?.data);
        childNode?.setSelected(true);
        handleSelectionChange(rowData);
        updateChildValue(null);
        if (childValueRef) childValueRef.current = null;
      }
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleSelectionChange = useCallback(
    (selectedRecords: PriorityOfPayment[] | undefined) => {
      const selectedRows: PriorityOfPayment[] | undefined =
        agGridApiRef.current?.getSelectedRows() || selectedRecords;
      if (selectedRows?.length) {
        const treePath = selectedRows[0]?.tree_data_path;
        const parentId = treePath.includes("/") ? treePath.split("/")[0] : null;
        const node = parentId
          ? agGridApiRef.current?.getRowNode(parentId)
          : agGridApiRef.current?.getRowNode(treePath);
        node?.setExpanded(true);
        onSelectionChanged !== undefined
          ? selectedRecords?.length && selectedRecords?.length > 0
            ? onSelectionChanged(selectedRecords, parentId ?? "")
            : onSelectionChanged(null, "")
          : null;
      } else {
        if (onSelectionChanged !== undefined) onSelectionChanged(null, "");
      }
    },
    [onSelectionChanged]
  );

  useRefreshNeedReviewOnChildGrid(agGridApiRef, "POPS", "POP");
  useNestedRefreshNeedReviewOnParentGrid("POP", "POPS", agGridApiRef);
  useRefreshNeedReviewOnParentGrid(finalModelId, "PSM", "POP", agGridApiRef);

  return (
    <Fragment>
      {isParameterValid(finalModelId) ? (
        <AsyncDataGridPanel
          sx={waterfallGridSx}
          dataSource={priorityOfPaymentsDataSource}
          refreshToken={refreshToken}
          colDefOverrides={colDefOverrides}
          onSelectionChanged={handleSelectionChange}
          titleComponent={titleComponent}
          gridPersistOptions={{
            key: "POP",
            enabled: true,
          }}
          agGridProps={{
            onGridReady: (event: GridReadyEvent) => {
              agGridApiRef.current = event.api;
            },
            onRowDataUpdated: onRowDataUpdated,
            onRowDragEnd: onRowDragMove,
            getRowId: getRowId,
            rowSelection: {
              mode: rowSelectionMode,
              enableClickSelection: true,
              checkboxes: rowSelectionMode == "multiRow",
              groupSelects: "self",
            },
            onFirstDataRendered: (event) => {
              const popData: PriorityOfPayment[] = [];
              event.api.forEachNode((node) => {
                popData.push(node.data as PriorityOfPayment);
              });
              if (popData.length > 0) {
                setMaxOrder(
                  Math.max(...popData.map((item) => Number(item.order)))
                );
              }
            },
            groupDefaultExpanded: 0,
            singleClickEdit: false,
            enableGroupEdit: true,
            autoGroupColumnDef: {
              rowDrag: rowSelectionMode === "multiRow",
              editable:
                rowSelectionMode === "multiRow"
                  ? (params) =>
                      params?.data?.order && Number(params?.data?.order) !== 0
                  : false,
              cellEditor: NumericCellEditor,
              cellEditorParams: {
                // make "dataType" value available to cell editor
                dataType: "string",
                max: getTotalSteps(agGridApiRef).length,
                min: 0,
              },
              headerName: "Order",
              field: "order",
              initialWidth: 130,
              cellStyle:
                rowSelectionMode === "multiRow"
                  ? {}
                  : { "text-align": "right" },
              cellRendererParams: {
                suppressCount: true,
                innerRenderer:
                  rowSelectionMode === "multiRow"
                    ? DisplayOrderCellRenderer
                    : undefined,
              },
              valueGetter: (params) =>
                params?.data?.order != null ? Number(params.data.order) : null,
              comparator: caseInsensitiveComparator,
              onCellValueChanged: (params) => {
                const newValue = params.newValue;
                const oldValue = params.oldValue;

                if (newValue !== oldValue) {
                  updateOrderOrPriorityValue(params.data, newValue, null);
                }
              },
            },
          }}
        >
          <PriorityOfPaymentGridActionContext.Provider
            value={{
              selectedWaterfalls: selectedWaterfalls,
              refresh: refresh,
              handleSelectionChange: handleSelectionChange,
              agGridApiRef: agGridApiRef,
              selectedModelstate: selectedModelstate,
              refreshGrid: refreshGrid,
              refreshAfterUpdate: refreshAfterUpdate,
              editButtonRef: editButtonRef,
              priorityOfPaymentsDataSource: priorityOfPaymentsDataSource,
              maxOrder: maxOrder,
            }}
          >
            {children}
          </PriorityOfPaymentGridActionContext.Provider>
        </AsyncDataGridPanel>
      ) : null}
    </Fragment>
  );
};

export const PriorityOfPaymentGridActions = () => {
  const {
    handleSelectionChange,
    refresh,
    refreshGrid,
    editButtonRef,
    refreshAfterUpdate,
    selectedWaterfalls,
    agGridApiRef,
    selectedModelstate,
    maxOrder,
    priorityOfPaymentsDataSource,
  } = useContext(PriorityOfPaymentGridActionContext);
  const iconButtonProps = useMemo<IconButtonProps>(() => {
    return selectedModelstate === "L" ? { disabled: true } : {};
  }, [selectedModelstate]);

  const iconButtonPropsForAddOrEdit = useMemo<IconButtonProps>(() => {
    return selectedModelstate === "L" ||
      (selectedWaterfalls && Number(selectedWaterfalls?.[0]?.order) === 0)
      ? { disabled: true }
      : {};
  }, [selectedModelstate, selectedWaterfalls]);

  const iconButtonPropsForDelete = useMemo<IconButtonProps>(() => {
    return selectedModelstate === "L" ||
      !selectedWaterfalls ||
      (selectedWaterfalls &&
        selectedWaterfalls[0]?.order === null &&
        selectedWaterfalls[0]?.priority === null)
      ? { disabled: true }
      : {};
  }, [selectedModelstate, selectedWaterfalls]);

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const handleUpdateUi = (agGridApi: GridApi<any>, ids: ActionTargetIds) => {
    const id = ids ? ids[0] : null;
    const childNode = agGridApi?.getRowNode(id);
    if (childNode) {
      const updatedRecord = { ...childNode.data };
      agGridApi?.applyTransaction({ remove: [childNode.data] });
      const transactionResult = agGridApi?.applyTransaction({
        add: [updatedRecord],
        addIndex: Number(updatedRecord.order) - 1,
      });
      agGridApi?.ensureIndexVisible(Number(updatedRecord.order) - 1);
      if (transactionResult?.add?.[0]) {
        agGridApi?.getRowNode(updatedRecord.id)?.setSelected(true, true);
      }
    }
  };

  const populateSuccessMessage = usePopulateSuccessMessage();
  const handleOnSubmitComplete = (message: string) => {
    populateSuccessMessage(message);
  };

  return (
    <>
      <DataGridQuickSearch></DataGridQuickSearch>
      {selectedWaterfalls === null || selectedWaterfalls === undefined ? (
        <DataGridActionAdd
          iconButtonProps={iconButtonPropsForAddOrEdit}
          dialog={<PriorityOfPaymentsFormDialog maxOrder={maxOrder} />}
          onUpdateUi={(data, agGridApi, ids) => {
            handleUpdateUi(agGridApi, ids);
            refreshGrid?.();
          }}
        ></DataGridActionAdd>
      ) : (
        <AddPaymentStepComponent
          AddEditPaymentDialog={PaymentStepFormDialog}
          onRefresh={refreshGrid}
          onGroupUpdate={refreshAfterUpdate}
          selectedWaterfalls={selectedWaterfalls}
          disabled={
            selectedWaterfalls.length > 1 ||
            selectedWaterfalls[0]?.order === null ||
            selectedWaterfalls[0]?.order === 0 ||
            iconButtonPropsForAddOrEdit.disabled
          }
        ></AddPaymentStepComponent>
      )}
      <DataGridActionEdit
        dialog={<PriorityOfPaymentsFormDialog maxOrder={maxOrder} />}
        onUpdateUi={(data, agGridApi, ids) => {
          handleUpdateUi(agGridApi, ids);
          refreshGrid?.();
        }}
        iconButtonProps={{ ...iconButtonPropsForAddOrEdit, ref: editButtonRef }}
      ></DataGridActionEdit>

      <PriorityOfPaymentBatchDelete
        iconButtonProps={iconButtonPropsForDelete}
        refresh={refresh ? refresh : () => undefined}
        gridApiRef={agGridApiRef}
        disabled={iconButtonPropsForDelete?.disabled}
        selectedRecords={selectedWaterfalls ? selectedWaterfalls : null}
        stepList={agGridApiRef ? getTotalSteps(agGridApiRef) : []}
        onSubmitComplete={handleOnSubmitComplete}
      ></PriorityOfPaymentBatchDelete>
      <DataGridAsyncDialogAction
        actionCode="duplicate"
        label="Duplicate"
        level="grid"
        loadOnOpen={false}
        type="icon"
        icon={<DuplicateIcon size={24} />}
        iconButtonProps={{ ...iconButtonProps, disabled: !!selectedWaterfalls }}
        onUpdateUi={refresh}
        dialog={<PriorityOfPaymentsCopyFormDialog />}
      />

      <ActionMenu>
        <DownloadActionMenu isPopover={true} />
        <DataGridAsyncDialogAction
          actionCode="bulkedit"
          label="Bulk Edit"
          level="grid"
          type="menuitem"
          iconButtonProps={iconButtonProps}
          loadOnOpen={false}
          onUpdateUi={(data, agGridApi) => {
            handleUpdateUi(agGridApi, [selectedWaterfalls?.[0]?.id]);
          }}
          dialog={
            <PopBulkEditFormDialog
              waterfallId={selectedWaterfalls?.[0]?.id ?? null}
              refresh={refresh}
            />
          }
          disabled={
            !(
              selectedWaterfalls &&
              iconButtonPropsForAddOrEdit &&
              !iconButtonPropsForAddOrEdit.disabled
            )
          }
        />
        <ActionButton
          actionCode={"Refresh"}
          label={"Refresh"}
          type="menuitem"
          onClick={() => {
            handleSelectionChange?.(undefined);
            agGridApiRef?.current?.forEachNode((node) => {
              node.setExpanded(false);
              node.setSelected(false);
            });
            refresh?.();
          }}
        ></ActionButton>
        <DataGridActionViewSource
          datasource={priorityOfPaymentsDataSource}
          type="menuitem"
        />
      </ActionMenu>
    </>
  );
};

