const paymentGroupGridSx: SxProps = {
  flex: "1 1 0px",
  minHeight: "25vh",
};

interface PaymentGroupGridProps {
  modelId?: string;
  selectedPortfolioId?: string;
  onSelectionChanged?: (
    selectedRecord: PaymentGroup[] | null,
    parentId: string
  ) => void | null;
  selectedPaymentGroups?: PaymentGroup[] | null | undefined;
  editButtonRef: React.RefObject<HTMLButtonElement>;
  updateRefreshGrid?: (refreshGrid: () => void | null) => void;
  refreshGrid?: (() => void) | undefined;
  refreshAfterUpdate?: () => void | null;
  childValueRef?: MutableRefObject<string | null>;
  selectedModelId?: string;
  children?: ReactNode;
  titleComponent?: React.ReactElement<
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    any,
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    string | React.JSXElementConstructor<any>
  >;
  rowSelectionMode?: "singleRow" | "multiRow";
}

type PaymentGroupGridActionContextType = {
  selectedModelstate: string | null;
  selectedPaymentGroups?: PaymentGroup[] | null | undefined;
  selectedPaymentGroupSteps?: PaymentGroupStep[] | null;
  refresh?: () => void;
  refreshGrid?: (() => void) | undefined;
  refreshAfterUpdate?: () => void | null;
  paymentGroupDelete: FabricAsyncOperation;
  editButtonRef: React.RefObject<HTMLButtonElement>;
  paymentGroupDataSource: DataGridDataServiceSource;
  handleSelectionChange?: (selectedRecords: PaymentGroup[] | undefined) => void;
  agGridApiRef?: MutableRefObject<GridApi<any> | null>;
  maxOrder: number;
};

const PaymentGroupGridActionContext =
  createContext<PaymentGroupGridActionContextType>({
    selectedModelstate: null,
    selectedPaymentGroups: undefined,
    selectedPaymentGroupSteps: null,
    editButtonRef: React.createRef<HTMLButtonElement>(),
    refresh: undefined,
    refreshGrid: undefined,
    refreshAfterUpdate: undefined,
    paymentGroupDataSource: {},
    handleSelectionChange: undefined,
    paymentGroupDelete: {
      url: "",
      operationConfirmedParamLocation: "query",
      method: "delete",
    },
    agGridApiRef: undefined,
    maxOrder: 0,
  });

export const PaymentGroupGrid: FunctionComponent<PaymentGroupGridProps> = ({
  onSelectionChanged,
  editButtonRef,
  selectedModelId,
  refreshGrid,
  updateRefreshGrid,
  childValueRef,
  selectedPaymentGroups,
  children: children,
  titleComponent,
  refreshAfterUpdate,
  rowSelectionMode = "multiRow",
}) => {
  const [refreshToken, refresh] = useRefreshToken();
  const { modelId, portfolioId } = useParams<AppRouteParams>();
  const finalModelId = modelId || selectedModelId;
  const paymentGroupDataSource = useMemo<DataGridDataServiceSource>(
    () => ({
      url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${finalModelId}/paymentGroups:view`,
    }),
    [portfolioId, finalModelId]
  );

  const { sharedAppContextManager } = useStaticAppContext();
  const { state: selectedModelstate } = sharedAppContextManager.useContext<
    string | null
  >("app.selectedModelState");
  const agGridApiRef = useRef<GridApi | null>(null);
  const { childIdRef, updateChildValue } = useContext(AddTreeGridChildContext);
  const [maxOrder, setMaxOrder] = useState<number>(0);

  const maxPriority = useCallback((data: PaymentGroup) => {
    const totalSteps: PaymentGroup[] = [];
    agGridApiRef.current?.forEachNode((rowNode: IRowNode<PaymentGroup>) =>
      rowNode.data ? totalSteps.push(rowNode.data) : null
    );
    const paymentGroupStepId = data?.tree_data_path.includes("/")
      ? data?.id
      : null;
    const paymentGroupId = data?.tree_data_path.includes("/")
      ? data?.tree_data_path?.split("/")[0]
      : null;
    if (paymentGroupStepId && paymentGroupId) {
      const matchId = paymentGroupStepId.split("_")[0];
      const filteredPaymentGroupSteps = totalSteps.filter((grp) =>
        grp.id.startsWith(`${matchId}_`)
      );
      return filteredPaymentGroupSteps.length > 0
        ? filteredPaymentGroupSteps.length
        : 0;
    }
  }, []);

  useEffect(() => {
    if (updateRefreshGrid) updateRefreshGrid(refresh);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useRefreshNeedReviewOnChildGrid(agGridApiRef, "PSEQS", "PSEQ");
  useRefreshNeedReviewOnParentGrid(finalModelId, "PSM", "PSEQ", agGridApiRef);

  const { updatePaymentGroupStep, updateOrderValue, updatePriorityValue } =
    useUpdateOrderOrPriority({
      modelId,
      portfolioId,
      agGridApiRef,
      refresh,
    });

  const paymentGroupDelete: FabricAsyncOperation = {
    url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/paymentGroups`,
    operationConfirmedParamLocation: "query",
    method: "delete",
  };

  const colDefOverrides: ColDefOverride[] = useMemo(
    () => [
      {
        field: "type_description",
        colDef: {
          filter: "agMultiColumnFilter",
        },
      },
      {
        field: "priority",
        colDef: {
          field: "priority",
          editable: (params) =>
            params?.data?.priority && rowSelectionMode == "multiRow"
              ? true
              : false,
          cellEditor: NumericCellEditor,
          cellStyle: { "padding-left": "20px", "text-align": "right" },
          cellEditorParams: (params: { data: PaymentGroup }) => {
            const maxPriorityVal = maxPriority(params.data);
            return {
              // make "dataType" value available to cell editor
              dataType: "string",
              max: maxPriorityVal,
              min: 0,
            };
          },
          cellRenderer:
            rowSelectionMode == "multiRow"
              ? DisplayOrderCellRenderer
              : undefined,
          minWidth: 100,
          valueGetter: (params) =>
            params?.data?.priority != null
              ? Number(params.data.priority)
              : null,
          comparator: caseInsensitiveComparator,
          onCellValueChanged: (params) => {
            const newValue = params.newValue;
            const oldValue = params.oldValue;

            if (newValue !== oldValue) {
              updatePriorityValue(params.data, newValue);
            }
          },
          headerClass: "ag-left-aligned-header",
        },
      },
    ],
    [maxPriority, updatePriorityValue]
  );

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const getRowId = useCallback((params: any) => {
    return params?.data?.id;
  }, []);

  const handleSelectionChange = useCallback(
    (selectedRecords: PaymentGroup[] | undefined) => {
      const selectedRows: PaymentGroup[] | undefined =
        agGridApiRef.current?.getSelectedRows() || selectedRecords;
      if (selectedRows?.length) {
        const treePath = selectedRows[0]?.tree_data_path;
        const parentId = treePath.includes("/") ? treePath.split("/")[0] : null;
        const node = parentId
          ? agGridApiRef.current?.getRowNode(parentId)
          : agGridApiRef.current?.getRowNode(treePath);
        node?.setExpanded(true);
        onSelectionChanged !== undefined
          ? selectedRecords?.length && selectedRecords?.length > 0
            ? onSelectionChanged(selectedRecords, parentId ?? "")
            : onSelectionChanged(null, "")
          : null;
      } else {
        if (onSelectionChanged !== undefined) onSelectionChanged(null, "");
      }
    },
    [onSelectionChanged]
  );

  const onRowDragMove = async (event: RowDragEvent) => {
    const movingNode = event.node;
    const overNode = event.overNode;
    if (
      movingNode !== overNode &&
      movingNode?.data?.order &&
      overNode?.data?.order
    ) {
      updatePaymentGroupStep(movingNode, overNode, "order");
    } else if (
      movingNode !== overNode &&
      (movingNode?.data?.order === null || movingNode?.data?.order === 0) &&
      movingNode?.data?.priority &&
      overNode?.data?.priority
    ) {
      const movingNodeParentId = movingNode?.data?.tree_data_path.includes("/")
        ? movingNode?.data?.tree_data_path?.split("/")[0]
        : null;
      const overNodeParentId = overNode?.data?.tree_data_path.includes("/")
        ? overNode?.data?.tree_data_path?.split("/")[0]
        : null;
      if (movingNodeParentId !== overNodeParentId) return;
      updatePaymentGroupStep(movingNode, overNode, "priority");
    }
  };

  const onRowDataUpdated = useCallback(() => {
    const rowData: PaymentGroup[] = [];
    if (childIdRef.current || (childValueRef && childValueRef.current)) {
      const childNodeId =
        childIdRef.current ?? (childValueRef && childValueRef.current);
      if (childNodeId) {
        const childNode = agGridApiRef.current?.getRowNode(childNodeId);
        rowData.push(childNode?.data);
        childNode?.setSelected(true);
        handleSelectionChange(rowData);
        updateChildValue(null);
        if (childValueRef) childValueRef.current = null;
      }
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return (
    <Fragment>
      {finalModelId ? (
        <AsyncDataGridPanel
          sx={paymentGroupGridSx}
          dataSource={paymentGroupDataSource}
          onSelectionChanged={handleSelectionChange}
          refreshToken={refreshToken}
          colDefOverrides={colDefOverrides}
          titleComponent={titleComponent}
          gridPersistOptions={{
            key: "PGRP",
            enabled: true,
          }}
          agGridProps={{
            onGridReady: (event: GridReadyEvent) => {
              agGridApiRef.current = event.api;
            },
            onRowDataUpdated: onRowDataUpdated,
            onRowDragEnd: onRowDragMove,
            getRowId: getRowId,
            rowSelection: {
              mode: rowSelectionMode,
              enableClickSelection: true,
              checkboxes: rowSelectionMode == "multiRow",
              groupSelects: "self",
            },
            onFirstDataRendered: (event) => {
              const popData: PaymentGroup[] = [];
              event.api.forEachNode((node) => {
                popData.push(node.data as PaymentGroup);
              });
              if (popData.length > 0) {
                setMaxOrder(
                  Math.max(...popData.map((item) => Number(item.order)))
                );
              }
            },
            groupDefaultExpanded: 0,
            singleClickEdit: false,
            enableGroupEdit: true,
            autoGroupColumnDef: {
              rowDrag: rowSelectionMode === "multiRow",
              editable:
                rowSelectionMode === "multiRow"
                  ? (params) =>
                      params?.data?.order && Number(params?.data?.order) !== 0
                  : false,
              cellEditor: NumericCellEditor,
              cellEditorParams: {
                // make "dataType" value available to cell editor
                dataType: "string",
                max: getTotalSteps(agGridApiRef).length,
                min: 0,
              },
              headerName: "Order",
              initialWidth: 130,
              cellStyle:
                rowSelectionMode === "multiRow"
                  ? {}
                  : { "text-align": "right" },
              field: "order",
              cellRendererParams: {
                suppressCount: true,
                innerRenderer:
                  rowSelectionMode === "multiRow"
                    ? DisplayOrderCellRenderer
                    : undefined,
              },
              valueGetter: (params) =>
                params?.data?.order != null ? Number(params.data.order) : null,
              comparator: caseInsensitiveComparator,
              onCellValueChanged: (params) => {
                const newValue = params.newValue;
                const oldValue = params.oldValue;

                if (newValue !== oldValue) {
                  updateOrderValue(params.data, newValue);
                }
              },
            },
          }}
        >
          <PaymentGroupGridActionContext.Provider
            value={{
              refresh: refresh,
              selectedModelstate: selectedModelstate,
              editButtonRef: editButtonRef,
              handleSelectionChange: handleSelectionChange,
              refreshGrid: refreshGrid,
              paymentGroupDataSource: paymentGroupDataSource,
              selectedPaymentGroups: selectedPaymentGroups,
              paymentGroupDelete: paymentGroupDelete,
              agGridApiRef: agGridApiRef,
              refreshAfterUpdate: refreshAfterUpdate,
              maxOrder: maxOrder,
            }}
          >
            {children}
          </PaymentGroupGridActionContext.Provider>
        </AsyncDataGridPanel>
      ) : null}
    </Fragment>
  );
};

export const PaymentGroupGridActions = () => {
  const {
    refresh,
    selectedModelstate,
    refreshGrid,
    editButtonRef,
    selectedPaymentGroups,
    handleSelectionChange,
    agGridApiRef,
    refreshAfterUpdate,
    maxOrder,
    paymentGroupDataSource,
  } = useContext(PaymentGroupGridActionContext);

  const iconButtonProps = useMemo<IconButtonProps>(() => {
    return selectedModelstate === "L" || selectedPaymentGroups
      ? { disabled: true }
      : {};
  }, [selectedModelstate, selectedPaymentGroups]);

  const iconButtonPropsForAddOrEdit = useMemo<IconButtonProps>(() => {
    return selectedModelstate === "L" ||
      (selectedPaymentGroups && Number(selectedPaymentGroups?.[0]?.order) === 0)
      ? { disabled: true }
      : {};
  }, [selectedModelstate, selectedPaymentGroups]);

  const iconButtonPropsForDelete = useMemo<IconButtonProps>(() => {
    const isModelLocked = selectedModelstate === "L";
    const hasNoSelectedPaymentGroups =
      !selectedPaymentGroups || selectedPaymentGroups.length === 0;
    const isFirstPaymentGroupEmpty =
      selectedPaymentGroups?.[0]?.order === null &&
      selectedPaymentGroups[0]?.priority === null;

    const isDisabled =
      isModelLocked || hasNoSelectedPaymentGroups || isFirstPaymentGroupEmpty;

    return { disabled: isDisabled };
  }, [selectedModelstate, selectedPaymentGroups]);

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const handleUpdateUi = (agGridApi: GridApi<any>, ids: ActionTargetIds) => {
    const id = ids ? ids[0] : null;
    const childNode = agGridApi?.getRowNode(id);
    if (childNode) {
      const updatedRecord = { ...childNode.data };
      agGridApi?.applyTransaction({ remove: [childNode.data] });
      const transactionResult = agGridApi?.applyTransaction({
        add: [updatedRecord],
        addIndex: Number(updatedRecord.order) - 1,
      });
      agGridApi?.ensureIndexVisible(Number(updatedRecord.order) - 1);
      if (transactionResult?.add?.[0]) {
        agGridApi?.getRowNode(updatedRecord.id)?.setSelected(true, true);
      }
    }
  };

  const populateSuccessMessage = usePopulateSuccessMessage();
  const handleOnSubmitComplete = (message: string) => {
    populateSuccessMessage(message);
  };

  return (
    <>
      <DataGridQuickSearch></DataGridQuickSearch>
      {selectedPaymentGroups === null || selectedPaymentGroups === undefined ? (
        <DataGridActionAdd
          iconButtonProps={iconButtonPropsForAddOrEdit}
          dialog={<PaymentGroupFormDialog maxOrder={maxOrder} />}
          onUpdateUi={(data, agGridApi, ids) => {
            handleUpdateUi(agGridApi, ids);
          }}
        ></DataGridActionAdd>
      ) : (
        <AddPaymentGroupStepComponent
          AddEditPaymentGroupStepDialog={PaymentGroupStepFormDialog}
          onRefresh={refresh}
          onGroupUpdate={refreshAfterUpdate}
          selectedPaymentGroups={selectedPaymentGroups}
          disabled={
            selectedPaymentGroups.length > 1 ||
            selectedPaymentGroups[0]?.order === null ||
            selectedPaymentGroups[0]?.order === 0 ||
            iconButtonPropsForAddOrEdit.disabled
          }
        ></AddPaymentGroupStepComponent>
      )}
      <DataGridActionEdit
        dialog={<PaymentGroupFormDialog maxOrder={maxOrder} />}
        onUpdateUi={(data, agGridApi, ids) => {
          handleUpdateUi(agGridApi, ids);
          refreshGrid?.();
        }}
        iconButtonProps={{
          ...iconButtonProps,
          disabled:
            !selectedPaymentGroups ||
            Number(selectedPaymentGroups?.[0]?.order) === 0 ||
            selectedPaymentGroups.length > 1,
          ref: editButtonRef,
        }}
      ></DataGridActionEdit>
      <PaymentGroupBatchDelete
        iconButtonProps={iconButtonPropsForDelete}
        refresh={refresh ? refresh : () => undefined}
        gridApiRef={agGridApiRef}
        disabled={iconButtonPropsForDelete?.disabled}
        selectedRecords={selectedPaymentGroups ? selectedPaymentGroups : null}
        stepList={agGridApiRef ? getTotalSteps(agGridApiRef) : []}
        onSubmitComplete={handleOnSubmitComplete}
      ></PaymentGroupBatchDelete>
      <DataGridAsyncDialogAction
        actionCode="duplicate"
        label="Duplicate"
        level="grid"
        loadOnOpen={false}
        type="icon"
        icon={<DuplicateIcon size={24} />}
        iconButtonProps={{
          ...iconButtonProps,
          disabled: !!selectedPaymentGroups,
        }}
        onUpdateUi={refresh}
        dialog={<PaymentGroupCopyFormDialog />}
      />

      <ActionMenu>
        <DownloadActionMenu isPopover={true} />
        <ActionButton
          actionCode={"Refresh"}
          label={"Refresh"}
          type="menuitem"
          onClick={() => {
            handleSelectionChange?.(undefined);
            agGridApiRef?.current?.forEachNode((node) => {
              node.setExpanded(false);
              node.setSelected(false);
            });
            refresh?.();
          }}
        ></ActionButton>
        <DataGridActionViewSource
          datasource={paymentGroupDataSource}
          type="menuitem"
        />
      </ActionMenu>
    </>
  );
};

