export const EligibilityCriteriaGrid: FunctionComponent<
  CommonGridProps<EligibilityCriteriaTest> & {
    editButtonRef: React.RefObject<HTMLButtonElement>;
    refreshDetails?: () => void;
    children?: ReactNode;
    titleComponent?: React.ReactElement<
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      any,
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      string | React.JSXElementConstructor<any>
    >;
    rowSelectionMode?: "single" | "multi";
  }
> = (props) => {
  const {
    modelId,
    selectedPortfolioId,
    refreshDetails,
    onSelectionChanged,
    editButtonRef,
    children: children,
    titleComponent,
    rowSelectionMode = "multi",
  } = props;
  const { sharedAppContextManager } = useStaticAppContext();
  const { state: selectedModelstate } = sharedAppContextManager.useContext<
    string | null
  >("app.selectedModelState");

  const [refreshGridToken, refreshGrid] = useRefreshToken();
  const messageAnnouncer = useMessageAnnouncer();

  const agGridApiRef = useRef<GridApi | null>(null);
  const [searchParams] = useSearchParams();
  const rowId = searchParams.get("rowId");
  const eligibilityCriteriaDataSource = useMemo<DataGridDataServiceSource>(
    () => ({
      url: `/compliance-bff/v1/portfolios/${selectedPortfolioId}/models/${modelId}/eligibilityCriteriaTests:view`,
    }),
    [selectedPortfolioId, modelId]
  );

  const testsEligibilityCriteriaDelete: FabricAsyncOperation = {
    url: `/compliance-bff/v1/portfolios/${selectedPortfolioId}/models/${modelId}/eligibilityCriteriaTests:batchDelete`,
    method: "post",
    operationConfirmedParamLocation: "body",
    idsField: "names",
  };

  const agGridCustomSx: SxProps = {
    ".ag-cell-focus": {
      border: "none !important",
    },
  };

  const updateOrderValue = async (
    test: EligibilityCriteriaTest,
    display_order: number
  ) => {
    if (test) {
      const EligibilityCriteriaTestDisplayOrderUpdate = {
        url: `/compliance-bff/v1/portfolios/${selectedPortfolioId}/models/${modelId}/eligibilityCriteriaTests/${test.id}?operation_confirmed=1`,
        requestObj: {
          order: Number(display_order),
          etag: test.etag,
        },
      };
      try {
        const displayOrderUpdateResp = await updateData(
          EligibilityCriteriaTestDisplayOrderUpdate.url,
          EligibilityCriteriaTestDisplayOrderUpdate.requestObj
        );
        if (displayOrderUpdateResp?.status === 200)
          refreshGrid ? refreshGrid() : null;
      } catch (error) {
        messageAnnouncer.error(`Failed to update Display Order: ${error}`);
      }
    }

    return null;
  };

  const colDefOverrides: ColDefOverride[] = [
    {
      field: "order",
      colDef: {
        rowDrag: true,
        editable: true,
        cellEditor: NumericCellEditor,
        cellEditorParams: {
          // make "dataType" value available to cell editor
          dataType: "number",
        },
        cellRenderer: DisplayOrderCellRenderer,
        onCellValueChanged: (params) => {
          const newValue = params.newValue;
          const oldValue = params.oldValue;
          const record = params.data;

          if (newValue !== oldValue) {
            updateOrderValue(record, newValue);
          }
        },
      },
    },
  ];
  const deps = useCallback(
    () =>
      modelId && selectedPortfolioId && refreshDetails
        ? [modelId, selectedPortfolioId, refreshDetails]
        : [],
    [modelId, selectedPortfolioId, refreshDetails]
  );

  const onRowDragEnd = async (event: RowDragEvent) => {
    if (rowSelectionMode == "multi") {
      const movingNode = event.node;
      const overNode = event.overNode;

      if (
        movingNode !== overNode &&
        movingNode?.data?.order &&
        overNode?.data?.order
      ) {
        updateEligibilityCriteriaOrder(movingNode, overNode);
      }
    }
  };

  const { fetchData: updateData } = useFetch<EligibilityCriteriaTest>({
    url: "",
    method: "PATCH",
    deps: deps(),
    autoFetch: false,
  });

  const updateEligibilityCriteriaOrder = async (
    movingNode: IRowNode,
    overNode: IRowNode
  ) => {
    const EligibilityCriteriaTestDisplayOrderUpdate = {
      url: `/compliance-bff/v1/portfolios/${selectedPortfolioId}/models/${modelId}/eligibilityCriteriaTests/${movingNode.data.id}?operation_confirmed=1`,
      requestObj: {
        order: overNode.data.order,
        etag: movingNode.data.etag,
      },
    };

    try {
      const displayOrderUpdateResp = await updateData(
        EligibilityCriteriaTestDisplayOrderUpdate.url,
        EligibilityCriteriaTestDisplayOrderUpdate.requestObj
      );
      if (displayOrderUpdateResp?.status === 200)
        refreshGrid ? refreshGrid() : null;
    } catch (error) {
      messageAnnouncer.error(`Failed to update Display Order: ${error}`);
    }

    return null;
  };

  const onGridReady = (event: GridReadyEvent) => {
    agGridApiRef.current = event.api;

    if (rowId) {
      const rowNode = agGridApiRef.current.getRowNode(rowId);

      if (rowNode) {
        rowNode.setSelected(true);
        agGridApiRef.current.ensureIndexVisible(rowNode.sourceRowIndex, "top");
      }
    }
  };
  useRefreshNeedReviewOnParentGrid(modelId, "PSM", "EC", agGridApiRef);

  return isParameterValid(modelId) ? (
    <AsyncDataGridPanel
      rowSelectionMode={rowSelectionMode}
      sx={{ ...gridSx, ...agGridCustomSx }}
      dataSource={modelId ? eligibilityCriteriaDataSource : null}
      onSelectionChanged={onSelectionChanged}
      refreshToken={refreshGridToken}
      colDefOverrides={rowSelectionMode == "multi" ? colDefOverrides : []}
      titleComponent={titleComponent}
      agGridProps={{
        onRowDragEnd: onRowDragEnd,
        onGridReady: onGridReady,
        singleClickEdit: true,
        stopEditingWhenCellsLoseFocus: true,
      }}
      gridPersistOptions={{
        key: `EC-SCREEN`,
        enabled: true,
      }}
    >
      <EligibilityGridActionContext.Provider
        value={{
          portfolioId: selectedPortfolioId as string,
          modelId: modelId as string,
          refreshDetails: refreshDetails,
          refreshGrid: refreshGrid,
          selectedModelstate: selectedModelstate,
          editButtonRef: editButtonRef,
          testsEligibilityCriteriaDelete: testsEligibilityCriteriaDelete,
          eligibilityCriteriaDataSource: eligibilityCriteriaDataSource,
        }}
      >
        {children}
      </EligibilityGridActionContext.Provider>
    </AsyncDataGridPanel>
  ) : null;
};

