import { useMemo } from "react";
import { DataGridDataServiceSource } from "@textile/biz-components";

export const useTabDataSource = (
  selectedTab: string,
  portfolioId: string | undefined,
  modelId: string | undefined,
  sequenceId: string | undefined
): DataGridDataServiceSource | null => {
  return useMemo(() => {
    if (!portfolioId || !modelId) return null;

    switch (selectedTab) {
      case "calculation_sequence":
        return sequenceId
          ? {
              url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/sequences/${sequenceId}/steps:view`,
            }
          : null;
      case "priority_of_payments":
        return {
          url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/waterfalls:view`,
        };
      case "priority_of_payment_groups":
        return {
          url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/paymentGroups:view`,
        };
      case "eligilibility_criteria_tests":
        return {
          url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/eligibilityCriteriaTests:view`,
        };
      case "compliance_tests":
        return {
          url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/tests:view`,
        };
      default:
        return null;
    }
  }, [selectedTab, portfolioId, modelId, sequenceId]);
};

