import {
  AsyncDataGridPanel,
  ColDefOverride,
  DataGridActionAdd,
  DataGridActionDelete,
  DataGridActionEdit,
  DataGridActionRefresh,
  DataGridAsyncDialogAction,
  DataGridDataServiceSource,
  DataGridQuickSearch,
  FabricAsyncOperation,
  useRefreshToken,
} from "@textile/biz-components";
import { IconButtonProps, SxProps } from "@textile/mui";
import { FunctionComponent, useMemo, useRef, useState } from "react";
import { useParams } from "react-router-dom";

import { RatingDerivationRuleFormDialog } from "./rating-derivation-rule-form.dialog.component";
import { AppRouteParams } from "../../screen.types";
import {
  AppExpCellRenderer,
  ApplicabilityExpressionCellRendererContext,
} from "../../common/expression-renderer.component";
import { RatingDerivationRuleCopyDialog } from "./rating-derivation-rule-copy-dialog.component";
import {
  DataGridActionViewSource,
  DownloadActionMenu,
  useDdxValues,
} from "@solvasam/bizcomponents";
import { RatingRule } from "../common/dynamic-data-rules.types";
import { DuplicateIcon, useStaticAppContext } from "@textile/common";
import { usePriorityhook } from "../../calculation-sequence/hooks/usePriorityhook.component";
import {
  useRefreshNeedReviewOnParentGrid,
  useRefreshNeedsReviewSync,
} from "../../common/refresh-need-review.hook";
import { GridApi, GridReadyEvent } from "@textile/ag-grid";

const gridSx: SxProps = { flex: "1 1 0px" };

export const RatingDerivationRuleGrid: FunctionComponent<{
  scenarioId: string;
  ratingAgency?: string;
  isRenderedByCalSeq?: boolean;
}> = ({ scenarioId, ratingAgency, isRenderedByCalSeq }) => {
  const { portfolioId, modelId } = useParams<AppRouteParams>();
  const [refreshToken, refresh] = useRefreshToken();
  const { sharedAppContextManager } = useStaticAppContext();
  const { state: selectedModelstate } = sharedAppContextManager.useContext<
    string | null
  >("app.selectedModelState");

  const { maxPriority } = usePriorityhook(
    !!scenarioId,
    portfolioId,
    modelId,
    scenarioId,
    "RDG",
    refresh
  );

  const iconButtonProps = useMemo<IconButtonProps>(() => {
    return selectedModelstate === "L" ? { disabled: true } : {};
  }, [selectedModelstate]);

  const [selectedRuleEtag, setSelectedRuleEtag] = useState<string | null>();
  const ratingRuleDataSource = useMemo<DataGridDataServiceSource>(
    () => ({
      url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/ratingScenarios/${scenarioId}/rules:view`,
    }),
    [portfolioId, modelId, scenarioId]
  );

  const RatingDerivationRuleDeleteOperation: FabricAsyncOperation = {
    url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/ratingScenarios/${scenarioId}/rules`,
    method: "delete",
    operationConfirmedParamLocation: "query",
  };

  const colDefOverrides: ColDefOverride[] = useMemo(
    () => [
      {
        field: "applicability_expression",
        colDef: {
          cellRenderer: AppExpCellRenderer,
          headerName: "Applicability Expression",
          wrapText: true,
          autoHeight: true,
        },
      },
    ],
    []
  );

  const handleSelectionChange = (selectedRules: RatingRule[]) => {
    setSelectedRuleEtag(
      selectedRules.length === 1 ? selectedRules[0].etag : null
    );
  };
  const ddxData = useDdxValues();
  const agGridApiRef = useRef<GridApi | null>(null);

  useRefreshNeedReviewOnParentGrid(scenarioId, "RDG", "RDR", agGridApiRef);
  useRefreshNeedsReviewSync(agGridApiRef, "RDR", "RDR");

  return (
    <ApplicabilityExpressionCellRendererContext.Provider
      value={{
        refresh: refresh,
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/ratingScenarios/${scenarioId}/rules`,
        ruleEtag: selectedRuleEtag,
        ddxData: ddxData,
        readonlyMode: selectedModelstate === "L",
      }}
    >
      <AsyncDataGridPanel
        title={"Rating Derivation Rules"}
        dataSource={ratingRuleDataSource}
        rowSelectionMode={isRenderedByCalSeq ? "single" : "multi"}
        sx={gridSx}
        refreshToken={refreshToken}
        colDefOverrides={colDefOverrides}
        onSelectionChanged={handleSelectionChange}
        gridPersistOptions={{
          key: "RDR",
          enabled: true,
        }}
        agGridProps={{
          defaultColDef: {
            minWidth: 120,
            resizable: true,
            wrapHeaderText: true,
            autoHeaderHeight: true,
            wrapText: true,
            autoHeight: true,
          },
          onGridReady: (e: GridReadyEvent) => {
            agGridApiRef.current = e.api;
          },
        }}
      >
        {!isRenderedByCalSeq && (
          <>
            <DataGridQuickSearch></DataGridQuickSearch>
            <DataGridActionAdd
              iconButtonProps={iconButtonProps}
              dialog={
                <RatingDerivationRuleFormDialog
                  ratingAgency={ratingAgency}
                  portfolioId={portfolioId}
                  modelId={modelId}
                  scenarioId={scenarioId}
                  priority={maxPriority}
                />
              }
            />
            <DataGridActionEdit
              iconButtonProps={iconButtonProps}
              dialog={
                <RatingDerivationRuleFormDialog
                  ratingAgency={ratingAgency}
                  portfolioId={portfolioId}
                  modelId={modelId}
                  scenarioId={scenarioId}
                />
              }
            />
            <DataGridActionDelete
              iconButtonProps={iconButtonProps}
              operation={RatingDerivationRuleDeleteOperation}
            />
            <DataGridAsyncDialogAction
              actionCode="duplicate"
              label="Duplicate"
              level="grid"
              type="icon"
              icon={<DuplicateIcon size={24} />}
              iconButtonProps={iconButtonProps}
              loadOnOpen={false}
              dialog={
                <RatingDerivationRuleCopyDialog
                  ratingAgency={ratingAgency}
                  portfolioId={portfolioId}
                  modelId={modelId}
                  scenarioId={scenarioId}
                  refreshGrid={refresh}
                />
              }
            />
            <DataGridActionRefresh></DataGridActionRefresh>
          </>
        )}
        <DownloadActionMenu />
        <DataGridActionViewSource datasource={ratingRuleDataSource} />
      </AsyncDataGridPanel>
    </ApplicabilityExpressionCellRendererContext.Provider>
  );
};

