import {
  DataGridActionViewSource,
  DownloadActionMenu,
  FormCodeField,
  FormPortfolioAutocomplete,
  getDialogResizePaperPropsSx,
  useUniqueCodeGenerate,
} from "@solvasam/bizcomponents";
import { GridApi, GridReadyEvent, ICellRendererParams } from "@textile/ag-grid";
import {
  AsyncDataGridPanel,
  AsyncFormAutocomplete,
  AsyncFormDialog,
  AsyncFormDialogProps,
  AutocompleteDataServiceProviderDataSource,
  ColDefOverride,
  DataGridActionAdd,
  DataGridActionDelete,
  DataGridActionEdit,
  DataGridActionRefresh,
  DataGridAsyncDialogAction,
  DataGridDataServiceSource,
  DataGridQuickSearch,
  FabricAsyncOperation,
  FormDataServiceSource,
  FormFieldGroup,
  FormTextField,
  useDialogActionCode,
  useField,
  useRefreshToken,
  useFormikContext,
  AsyncFormSelect,
  DropdownTransferList,
} from "@textile/biz-components";
import {
  Box,
  Divider,
  IconButtonProps,
  Stack,
  SxProps,
  TextFieldProps,
  useMediaQuery,
  useTheme,
} from "@textile/mui";
import {
  Fragment,
  FunctionComponent,
  SyntheticEvent,
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState,
} from "react";
import { useParams } from "react-router-dom";

import { CalculationBlock } from "../calculations.types";
import { AppRouteParams } from "../../screen.types";
import { CommonGridProps } from "../../common/common-types";
import { useModelDataSource } from "../../snapshot-models/models/useSnapshotModel";
import { Template } from "../../templates/templates.types";
import { baseUrl } from "../../../apis";
import { DuplicateIcon, useStaticAppContext } from "@textile/common";
import { usePopulateSuccessMessage } from "../../common/helpers";
import {
  useRefreshNeedReviewOnChildGrid,
  useRefreshNeedReviewOnParentGrid,
  useRefreshNeedsReviewSync,
} from "../../common/refresh-need-review.hook";
export interface CalculationBlockFormDialogProps
  extends Partial<AsyncFormDialogProps> {
  groupId: string;
  gridApi?: GridApi | null;
  order?: number;
}
interface CalculationBlockFormProps {
  mode: "add" | "edit";
  setCalculationGroupId: React.Dispatch<React.SetStateAction<string>>;
}

const CalculationBlockForm: FunctionComponent<CalculationBlockFormProps> = ({
  mode,
  setCalculationGroupId,
}) => {
  const { portfolioId, modelId } = useParams<AppRouteParams>();
  const [{ value: sourceGroupId }] = useField("group_id");
  const [{ value: outputFieldId }] = useField("output_field_id");
  const { setFieldValue } = useFormikContext();

  useEffect(() => {
    if (sourceGroupId) {
      setCalculationGroupId(sourceGroupId);
    }
  }, [setCalculationGroupId, sourceGroupId]);

  const templatesDataSource =
    useMemo<AutocompleteDataServiceProviderDataSource>(
      () => ({
        url: "/compliance-bff/v1/templates",
        dataPath: "templates",
        queryParams: {
          "paging.filter": `test_type="CB"`,
          "paging.order_by": "name",
        },
      }),
      []
    );

  const calculationGroupsDataSource =
    useMemo<AutocompleteDataServiceProviderDataSource>(
      () => ({
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/calculationGroups`,
        dataPath: "calculation_groups",
      }),
      [modelId, portfolioId]
    );

  const handleTemplateSelectionChange = useCallback(
    (event: SyntheticEvent, value: unknown) => {
      setFieldValue("comments", (value as Template).comments);
    },
    [setFieldValue]
  );

  const uniqueCodeGenerateSourceFieldProps = useUniqueCodeGenerate(
    "description",
    "code",
    "DC_CALC_BLOCK",
    baseUrl,
    mode,
    modelId
  );

  return (
    <>
      {mode == "edit" && (
        <FormFieldGroup>
          <FormTextField<CalculationBlock>
            fieldName="id"
            label="Block Id"
            variant="outlined"
            disabled
          ></FormTextField>
        </FormFieldGroup>
      )}
      <FormFieldGroup>
        <FormTextField<CalculationBlock>
          fieldName="description"
          label="Description"
          variant="outlined"
          required={true}
          {...uniqueCodeGenerateSourceFieldProps}
        ></FormTextField>
      </FormFieldGroup>
      <FormFieldGroup>
        <FormCodeField<CalculationBlock>
          fieldName="code"
          label="Code"
          disabled={mode === "edit"}
        ></FormCodeField>
      </FormFieldGroup>
      <FormFieldGroup>
        <AsyncFormAutocomplete
          fieldName="group_id"
          valueField="id"
          labelField="description"
          dataSource={calculationGroupsDataSource}
          textFieldProps={{
            label: "Calculation Group",
            variant: "outlined",
            required: true,
          }}
          fullWidth
        ></AsyncFormAutocomplete>
      </FormFieldGroup>
      <FormFieldGroup>
        <AsyncFormAutocomplete<CalculationBlock>
          fieldName="template_id"
          valueField="id"
          labelField="template_name"
          dataSource={templatesDataSource}
          textFieldProps={{
            label: "Template",
            variant: "outlined",
            required: true,
          }}
          onChange={handleTemplateSelectionChange}
          disabled={mode === "edit"}
        ></AsyncFormAutocomplete>
      </FormFieldGroup>
      <FormFieldGroup>
        <FormTextField<CalculationBlock>
          fieldName="order"
          label="Priority"
          variant="outlined"
          required={true}
          helperText="Order range between 1-99"
          InputProps={{
            inputProps: {
              type: "number",
              min: 1,
              max: 99,
            },
          }}
        ></FormTextField>
      </FormFieldGroup>
      {mode === "edit" ? (
        <Fragment>
          {/* <FormFieldGroup>
            <FormCheckbox
              id="include_in_comparision"
              label="Include in Comparision"
            ></FormCheckbox>
          </FormFieldGroup>
          needs to be confirmed as this is not part of figma design Calculation Sequence 27
          */}
          {outputFieldId > 0 ? (
            <>
              <FormFieldGroup>
                <FormTextField<CalculationBlock>
                  fieldName="indenture_reference"
                  label="Document Reference"
                  variant="outlined"
                ></FormTextField>
              </FormFieldGroup>
              <FormFieldGroup>
                <FormTextField<CalculationBlock>
                  fieldName="report_reference"
                  label="Report Reference"
                  variant="outlined"
                ></FormTextField>
              </FormFieldGroup>
            </>
          ) : null}
        </Fragment>
      ) : null}
      {mode === "edit" && (
        <FormFieldGroup>
          <FormTextField<CalculationBlock>
            fieldName="copy_source_description"
            label="Copy Source"
          ></FormTextField>
        </FormFieldGroup>
      )}
      <FormFieldGroup>
        <FormTextField<CalculationBlock>
          fieldName="comments"
          label="Comments"
          variant="outlined"
          multiline
        ></FormTextField>
      </FormFieldGroup>
    </>
  );
};

export const CalculationBlockFormDialog: FunctionComponent<
  CalculationBlockFormDialogProps
> = ({ groupId, gridApi, order = 0 }) => {
  const theme = useTheme();
  const fullScreen = useMediaQuery(theme.breakpoints.down("md"));
  const actionCode = useDialogActionCode();
  const { portfolioId, modelId } = useParams<AppRouteParams>();
  const [calculationGroupId, setCalculationGroupId] = useState<string>(groupId);

  const mode = actionCode === "edit" ? "edit" : "add";

  const populateSuccessMessage = usePopulateSuccessMessage();
  const handleOnSubmitComplete = () => {
    populateSuccessMessage(
      `Calculation block ${mode === "edit" ? "updated." : "added."}`
    );
  };

  const defaultData = {
    order: (gridApi?.getDisplayedRowCount() as number) + 1 || order,
    group_id: groupId,
  };
  const calcualtionBlocksFormSource = useMemo<FormDataServiceSource>(
    () => ({
      idField: "id",
      mode: mode,
      get: {
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/calculationGroups/${calculationGroupId}/blocks`,
      },
      save: {
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/calculationGroups/${calculationGroupId}/blocks`,
        method: mode === "add" ? "post" : "patch",
      },
    }),
    [mode, portfolioId, modelId, calculationGroupId]
  );

  return (
    <AsyncFormDialog
      title={`${mode === "add" ? "Add" : "Edit"} Calculation Block ${
        mode === "edit" ? "Properties" : ""
      }`}
      dataSource={calcualtionBlocksFormSource}
      fullScreen={fullScreen}
      fullWidth
      PaperProps={{
        sx: getDialogResizePaperPropsSx("720px"),
      }}
      defaultData={defaultData ?? null}
      draggable={true}
      onSubmitComplete={handleOnSubmitComplete}
    >
      <CalculationBlockForm
        setCalculationGroupId={setCalculationGroupId}
        mode={mode}
      ></CalculationBlockForm>
    </AsyncFormDialog>
  );
};

const portfolioCopyTextFieldProps: TextFieldProps = {
  label: "Source Portfolio",
  variant: "outlined",
  required: true,
};

const modelCopyTextFieldProps: TextFieldProps = {
  label: "Source Model",
  variant: "outlined",
  required: true,
};

const calculationGroupsCopyTextFieldProps: TextFieldProps = {
  label: "Calculation Groups",
  variant: "outlined",
  required: true,
};

const CalculationBlockCopyForm = () => {
  const [{ value: sourcePortfolioId }] = useField("portfolio_id");
  const [{ value: sourceModelId }] = useField("model_id");
  const [{ value: sourceGroupId }] = useField("group_id");

  const { modelsListDataSource } = useModelDataSource(sourcePortfolioId ?? "");

  const sourceCalculationGroupDataSource =
    useMemo<AutocompleteDataServiceProviderDataSource>(
      () => ({
        url: `/compliance-bff/v1/portfolios/${sourcePortfolioId}/models/${sourceModelId}/calculationGroups`,
        dataPath: "calculation_groups",
      }),
      [sourcePortfolioId, sourceModelId]
    );
  const calculationBlockDataSource =
    useMemo<AutocompleteDataServiceProviderDataSource>(
      () => ({
        url: `/compliance-bff/v1/portfolios/${sourcePortfolioId}/models/${sourceModelId}/calculationGroups/${sourceGroupId}/blocks`,
        dataPath: "calculation_blocks",
      }),
      [sourcePortfolioId, sourceGroupId, sourceModelId]
    );

  return (
    <Fragment>
      <FormFieldGroup>
        <FormPortfolioAutocomplete
          fieldName="portfolio_id"
          textFieldProps={portfolioCopyTextFieldProps}
        ></FormPortfolioAutocomplete>
      </FormFieldGroup>
      <FormFieldGroup>
        <AsyncFormAutocomplete
          fieldName="model_id"
          valueField="id"
          labelField="description"
          dataSource={sourcePortfolioId ? modelsListDataSource : null}
          textFieldProps={modelCopyTextFieldProps}
        ></AsyncFormAutocomplete>
      </FormFieldGroup>
      <FormFieldGroup>
        <AsyncFormAutocomplete
          fieldName="group_id"
          valueField="id"
          labelField="description"
          dataSource={
            sourcePortfolioId && sourceModelId
              ? sourceCalculationGroupDataSource
              : null
          }
          textFieldProps={calculationGroupsCopyTextFieldProps}
        ></AsyncFormAutocomplete>
      </FormFieldGroup>
      <FormFieldGroup>
        <Stack sx={{ flex: "1 1 0px" }}>
          <AsyncFormSelect
            fieldName="selected_blocks"
            dataSource={
              sourcePortfolioId && sourceModelId && sourceGroupId
                ? calculationBlockDataSource
                : []
            }
            labelField={"description"}
            valueField={"name"}
            label="Source Calculation Block"
            required
            multiple
          >
            <DropdownTransferList
              label="Source Calculation Block"
              autoFocusSearch
            />
          </AsyncFormSelect>
        </Stack>
      </FormFieldGroup>
      <Divider></Divider>
    </Fragment>
  );
};

interface CalculationBlockCopyFormDialogProps
  extends Partial<AsyncFormDialogProps> {
  modelId?: string;
  portfolioId?: string;
  groupId: string;
  refreshGrid?: () => void;
}

const CalculationBlockCopyFormDialog: FunctionComponent<
  CalculationBlockCopyFormDialogProps
> = ({ modelId, portfolioId, groupId, refreshGrid, ...props }) => {
  const theme = useTheme();
  const fullScreen = useMediaQuery(theme.breakpoints.down("md"));

  const calculationBlockCopyDataSource = useMemo(
    () => ({
      idField: "id",
      mode: "add",
      save: {
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/calculationGroups/${groupId}/blocks:copy`,
        method: "post",
      },
    }),
    [portfolioId, groupId, modelId]
  );

  const OnBeforeCopy = async (data: Partial<CalculationBlockImportProps>) => {
    const names: string[] = [];
    data.selected_blocks?.forEach((record) => {
      if (record) names.push(record);
    });
    return {
      names: names,
    };
  };

  const defaultData = {
    portfolio_id: portfolioId,
    model_id: modelId,
    group_id: groupId,
  };

  return (
    <AsyncFormDialog
      {...props}
      title="Duplicate Calculation Blocks"
      dataSource={calculationBlockCopyDataSource}
      fullScreen={fullScreen}
      enableFullScreenToggle={true}
      fullWidth
      onBeforeSave={OnBeforeCopy}
      defaultData={defaultData}
      onSubmitComplete={refreshGrid}
      submitButtonLabel="Duplicate"
      PaperProps={{
        sx: getDialogResizePaperPropsSx("lg"),
      }}
      draggable={true}
    >
      <CalculationBlockCopyForm />
    </AsyncFormDialog>
  );
};

