  const agGridApiRef = useRef<GridApi | null>(null);

  useRefreshNeedReviewOnParentGrid(groupId, "CRG", "CB", agGridApiRef);
  useRefreshNeedReviewOnChildGrid(agGridApiRef, "CBP", "CB");
  useRefreshNeedsReviewSync(agGridApiRef, "CB", "CB");

  return (
    <AsyncDataGridPanel
      dataSource={calculationBlockDataSource}
      rowSelectionMode={isRenderedByCalSeq ? "single" : "multi"}
      sx={blockGridSx}
      onSelectionChanged={onSelectionChanged}
      refreshToken={refreshToken}
      colDefOverrides={colDefOverrides}
      gridPersistOptions={{
        key: "CB",
        enabled: true,
      }}
      agGridProps={{
        onGridReady: (e: GridReadyEvent) => {
          setGridApi(e.api);
          agGridApiRef.current = e.api;
        },
      }}
    >
      <DataGridQuickSearch></DataGridQuickSearch>
      {!isRenderedByCalSeq && (
        <>
          <DataGridActionAdd
            iconButtonProps={iconButtonProps}
            dialog={
              <CalculationBlockFormDialog
                groupId={groupId}
                gridApi={gridApi}
              ></CalculationBlockFormDialog>
            }
          ></DataGridActionAdd>
          <DataGridActionEdit
            iconButtonProps={{
              ...iconButtonProps,
              ref: editButtonRefBlock,
            }}
            dialog={
              <CalculationBlockFormDialog
                groupId={groupId}
                gridApi={gridApi}
              ></CalculationBlockFormDialog>
            }
            onUpdateUi={refresh}
          ></DataGridActionEdit>
          <DataGridActionDelete
            iconButtonProps={iconButtonProps}
            operation={blocksDeleteOperation}
          ></DataGridActionDelete>
          <DataGridAsyncDialogAction
            actionCode="duplicate"
            label="Duplicate"
            level="grid"
            type="icon"
            icon={<DuplicateIcon size={24} />}
            iconButtonProps={iconButtonProps}
            loadOnOpen={false}
            dialog={
              <CalculationBlockCopyFormDialog
                modelId={modelId}
                portfolioId={portfolioId}
                groupId={groupId}
                refreshGrid={refresh}
              ></CalculationBlockCopyFormDialog>
            }
          />
          <DataGridActionRefresh></DataGridActionRefresh>{" "}
