interface CalculationBlockCopyFormDialogProps
  extends Partial<AsyncFormDialogProps> {
  modelId?: string;
  portfolioId?: string;
  groupId: string;
  refreshGrid?: () => void;
}

const CalculationBlockCopyFormDialog: FunctionComponent<
  CalculationBlockCopyFormDialogProps
> = ({ modelId, portfolioId, groupId, refreshGrid, ...props }) => {
  const theme = useTheme();
  const fullScreen = useMediaQuery(theme.breakpoints.down("md"));

  const calculationBlockCopyDataSource = useMemo(
    () => ({
      idField: "id",
      mode: "add",
      save: {
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/calculationGroups/${groupId}/blocks:copy`,
        method: "post",
      },
    }),
    [portfolioId, groupId, modelId]
  );

  const OnBeforeCopy = async (data: Partial<CalculationBlockImportProps>) => {
    const names: string[] = [];
    data.selected_blocks?.forEach((record) => {
      if (record) names.push(record);
    });
    return {
      names: names,
    };
  };

  const defaultData = {
    portfolio_id: portfolioId,
    model_id: modelId,
    group_id: groupId,
  };

  return (
    <AsyncFormDialog
      {...props}
      title="Duplicate Calculation Blocks"
      dataSource={calculationBlockCopyDataSource}
      fullScreen={fullScreen}
      enableFullScreenToggle={true}
      fullWidth
      onBeforeSave={OnBeforeCopy}
      defaultData={defaultData}
      onSubmitComplete={refreshGrid}
      submitButtonLabel="Duplicate"
      PaperProps={{
        sx: getDialogResizePaperPropsSx("lg"),
      }}
      draggable={true}
    >
      <CalculationBlockCopyForm />
    </AsyncFormDialog>
  );
};

const blockGridSx: SxProps = { flex: "1 1 0px" };
interface CalculationBlockImportProps {
  portfolio_id?: string;
  model_id?: string;
  group_id?: string;
  selected_blocks?: string[];
}

interface CalculationBlocksProps extends CommonGridProps<CalculationBlock> {
  groupId: string;
  editButtonRefBlock?: React.RefObject<HTMLButtonElement>;
  isRenderedByCalSeq?: boolean;
}

export const CalculationBlockGrid: FunctionComponent<
  CalculationBlocksProps
> = ({
  onSelectionChanged,
  groupId,
  editButtonRefBlock,
  isRenderedByCalSeq,
}) => {
  const { portfolioId, modelId } = useParams<AppRouteParams>();
  const [refreshToken, refresh] = useRefreshToken();
  const { sharedAppContextManager } = useStaticAppContext();
  const { state: selectedModelstate } = sharedAppContextManager.useContext<
    string | null
  >("app.selectedModelState");

  const [gridApi, setGridApi] = useState<GridApi | null>(null);

  const iconButtonProps = useMemo<IconButtonProps>(() => {
    return selectedModelstate === "L" ? { disabled: true } : {};
  }, [selectedModelstate]);

  const blocksDeleteOperation = useMemo<FabricAsyncOperation>(
    () => ({
      url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/calculationGroups/${groupId}/blocks`,
      operationConfirmedParamLocation: "query",
      method: "delete",
    }),
    [groupId, modelId, portfolioId]
  );

  const calculationBlockDataSource = useMemo<DataGridDataServiceSource>(
    () => ({
      url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/calculationGroups/${groupId}/blocks:view`,
    }),
    [groupId, modelId, portfolioId]
  );
  const theme = useTheme();
  const colDefOverrides: ColDefOverride[] = useMemo(
    () => [
      {
        field: "warning",
        colDef: {
          cellRenderer: (props: ICellRendererParams) => {
            return (
              <Box
                sx={{
                  color: props.value ? theme.palette.error.main : "none",
                }}
              >
                {props.value}
              </Box>
            );
          },
        },
      },
      {
        field: "calculation_description",
        colDef: {
          wrapText: true,
          autoHeight: true,
        },
      },
    ],
    // eslint-disable-next-line react-hooks/exhaustive-deps
    []
  );
  const agGridApiRef = useRef<GridApi | null>(null);

  useRefreshNeedReviewOnParentGrid(groupId, "CRG", "CB", agGridApiRef);
  useRefreshNeedReviewOnChildGrid(agGridApiRef, "CBP", "CB");
  useRefreshNeedsReviewSync(agGridApiRef, "CB", "CB");

  return (
    <AsyncDataGridPanel
      dataSource={calculationBlockDataSource}
      rowSelectionMode={isRenderedByCalSeq ? "single" : "multi"}
      sx={blockGridSx}
      onSelectionChanged={onSelectionChanged}
      refreshToken={refreshToken}
      colDefOverrides={colDefOverrides}
      gridPersistOptions={{
        key: "CB",
        enabled: true,
      }}
      agGridProps={{
        onGridReady: (e: GridReadyEvent) => {
          setGridApi(e.api);
          agGridApiRef.current = e.api;
        },
      }}
    >
      <DataGridQuickSearch></DataGridQuickSearch>
      {!isRenderedByCalSeq && (
        <>
          <DataGridActionAdd
            iconButtonProps={iconButtonProps}
            dialog={
              <CalculationBlockFormDialog
                groupId={groupId}
                gridApi={gridApi}
              ></CalculationBlockFormDialog>
            }
          ></DataGridActionAdd>
          <DataGridActionEdit
            iconButtonProps={{
              ...iconButtonProps,
              ref: editButtonRefBlock,
            }}
            dialog={
              <CalculationBlockFormDialog
                groupId={groupId}
                gridApi={gridApi}
              ></CalculationBlockFormDialog>
            }
            onUpdateUi={refresh}
          ></DataGridActionEdit>
          <DataGridActionDelete
            iconButtonProps={iconButtonProps}
            operation={blocksDeleteOperation}
          ></DataGridActionDelete>
          <DataGridAsyncDialogAction
            actionCode="duplicate"
            label="Duplicate"
            level="grid"
            type="icon"
            icon={<DuplicateIcon size={24} />}
            iconButtonProps={iconButtonProps}
            loadOnOpen={false}
            dialog={
              <CalculationBlockCopyFormDialog
                modelId={modelId}
                portfolioId={portfolioId}
                groupId={groupId}
                refreshGrid={refresh}
              ></CalculationBlockCopyFormDialog>
            }
          />
          <DataGridActionRefresh></DataGridActionRefresh>{" "}
        </>
      )}
      <DownloadActionMenu />
      <DataGridActionViewSource datasource={calculationBlockDataSource} />
    </AsyncDataGridPanel>
  );
};

