import {
  Screen,
  ScreenHeader,
  Splitter,
  ToolGroup,
  useAxiosFactory,
} from "@textile/common";
import {
  ResponsiveStyleValue,
  Stack,
  SxProps,
  Typography,
  Theme,
} from "@textile/mui";
import { useRefreshToken } from "@textile/biz-components";
import {
  FunctionComponent,
  useMemo,
  useState,
  useCallback,
  useRef,
  useEffect,
  Fragment,
} from "react";
import { useParams } from "react-router-dom";
import { CalculationSequenceStep } from "./calculation-sequence.types";
import {
  CalculationSequenceStepGridActions,
  CalculationStepGrid,
} from "./calculation-step-grid.component";
import { AppRouteParams, ScreenProps } from "../screen.types";
import { isParameterValid, SnapshotModelDropdown } from "../common";
import { RecoveryRatesGroupSummary } from "../dynamic-data-rules/recovery-rates/recovery-rates-group-summary.component";
import { RecoveryRatesRuleSummary } from "../dynamic-data-rules/recovery-rates/recovery-rates-rule-summary.component";
import { RecoveryRateDerivationRuleGrid } from "../dynamic-data-rules/recovery-rates/recovery-rate-derivation-rule-grid.component";
import { RatingDerivationGroupSummary } from "../dynamic-data-rules/rating-derivation-rules/rating-derivation-group-summary.component";
import { RatingDerivationRuleSummary } from "../dynamic-data-rules/rating-derivation-rules/rating-derivation-rule-summary.component";
import { RatingDerivationRuleGrid } from "../dynamic-data-rules/rating-derivation-rules/rating-derivation-rule-grid.component";
import { PrincipalBalanceRuleGroupDetails } from "../dynamic-data-rules/principal-balance/principal-balance-details-screen.component";
import { PrincipalBalanceRuleDetails } from "../dynamic-data-rules/principal-balance/principal-balance-rule-details.component";
import { PrincipalBalanceRuleGrid } from "../dynamic-data-rules/principal-balance/principal-balance-rule-grid.component";
import { CalculationBlockGrid } from "../calculations/calculation-groups/calculation-block-grid.component";
import { CalculationBlockParameterGrid } from "../calculations/calculation-groups/calculation-block-parameter-grid.component";
import { CalculationGroupDetails } from "../calculations/calculation-groups/calculation-group-details.component";
import { ComplianceModel } from "../snapshot-models/snapshot-models.types";
import { useFetch } from "../common/useFetch";
import { AddTreeGridChildProvider } from "../common/add-tree-grid-child-context.component";
import { GridApi, GridReadyEvent, IRowNode } from "@textile/ag-grid";
import { detailsContainerSx } from "../common/common.component";

const screenSx: SxProps = { display: "flex", flexDirection: "column" };

const calculationSequenceStackSx: SxProps = { flexGrow: 1 };
const calculationSequenceStackDirection: ResponsiveStyleValue<
  "row" | "row-reverse" | "column" | "column-reverse"
> = { xs: "column", sm: "column", md: "column", lg: "row", xl: "row" };

export const CalculationSequenceScreen: FunctionComponent<ScreenProps> = () => {
  const { portfolioId, modelId } = useParams<AppRouteParams>();
  const [sequenceStepSelection, setSequenceStepSelection] = useState<
    Partial<CalculationSequenceStep>[] | null
  >(null);
  const [sequenceId, setSequenceId] = useState<string | null | undefined>();
  const [refreshToken, refresh] = useRefreshToken();
  const groupId = useRef<string | undefined>();
  const refreshGrid = useRef<() => void | null>();
  const childValueRef = useRef<string | null>(null);
  const gridApiRef = useRef<any>(null);
  const selectedRowId = useRef<string | null>(null);
  const axiosFactory = useAxiosFactory();

  const handleGridApiReady = useCallback((event: GridReadyEvent) => {
    if (gridApiRef) gridApiRef.current = event.api;
  }, []);

  const getGroupUrl = (lid: string) => {
    if (sequenceId) {
      return `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/sequences/${sequenceId}/steps/${lid}`;
    }
    return "";
  };
  const refreshCell = async (agGridApi: GridApi<any>, ids: string[]) => {
    const id = ids && ids[0] ? ids[0] : "";
    const childNode = id ? agGridApi?.getRowNode(id) : null;

    if (!childNode) return;

    const data = await fetchNewDescription(childNode);
    const updatedDescription = data?.description || null;
    const updatedComments = data?.comments || null;

    if (
      (updatedDescription &&
        updatedDescription != childNode.data.description) ||
      updatedComments != childNode.data.comments
    ) {
      childNode.data.description = updatedDescription;
      childNode.data.comments = updatedComments;
      const updatedRecord = { ...childNode.data };

      agGridApi?.applyTransaction({ remove: [childNode.data] });

      const transactionResult = agGridApi?.applyTransaction({
        add: [updatedRecord],
        addIndex: Number(updatedRecord.order) - 1,
      });

      agGridApi?.ensureIndexVisible(Number(updatedRecord.order) - 1);

      if (transactionResult?.add?.[0]) {
        agGridApi?.getRowNode(updatedRecord.id)?.setSelected(true, true);
      }
    }
  };

  const fetchNewDescription = async (
    childNode: IRowNode<any> | null | undefined
  ): Promise<CalculationSequenceStep | null> => {
    if (!childNode || !childNode.data) {
      return null;
    }
    const axios = await axiosFactory.createAxiosInstance();
    const url = getGroupUrl(childNode.data.lid);
    const { data } = await axios.get(url);
    return data || null;
  };
  const handleEditEvent = () => {
    if (gridApiRef.current && selectedRowId.current) {
      refreshCell(gridApiRef.current, [selectedRowId.current]);
    }
  };

  const deps = useCallback(
    () => (modelId && portfolioId ? [modelId, portfolioId] : []),
    [modelId, portfolioId]
  );

  //Added extra condition on calling this api as if in the param modelId is inValid it will not call this api then
  const { data } = useFetch<ComplianceModel>({
    url: isParameterValid(modelId)
      ? `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}`
      : "",
    method: "GET",
    deps: deps(),
  });

  useEffect(() => {
    if (data) setSequenceId(data?.sequence_id);
  }, [data]);

  const handleSequenceStepSelectionChange = useCallback(
    (selectedRecords: CalculationSequenceStep[] | null, groupIdVal: string) => {
      setSequenceStepSelection(null);
      setSequenceStepSelection(selectedRecords ? selectedRecords : null);
      if (selectedRecords && selectedRecords.length > 0) {
        selectedRowId.current = selectedRecords[0].id;
      }
      if (
        (selectedRecords?.length === 1 &&
          selectedRecords?.[0]?.order === null) ||
        selectedRecords?.[0]?.order === 0
      ) {
        groupId.current = groupIdVal;
      }
    },
    []
  );

  useEffect(() => {
    setSequenceStepSelection(null);
  }, [portfolioId, modelId]);
  const updateRefreshGrid = useCallback((refreshFunc: () => void | null) => {
    if (refreshFunc) {
      refreshGrid.current = refreshFunc;
    }
  }, []);

  const CalculationParameterGrid = useMemo(
    () => () => {
      return (
        <CalculationBlockParameterGrid
          groupId={groupId.current}
          blockId={sequenceStepSelection?.[0]?.item_id ?? ""}
          isRenderedByCalSeq={true}
        ></CalculationBlockParameterGrid>
      );
    },
    [sequenceStepSelection]
  );

  const PanelComponents = useMemo(
    () =>
      ({ refreshGrid }: { refreshGrid: (() => void | null) | undefined }) => {
        switch (sequenceStepSelection?.[0]?.type?.trim()) {
          case "RRDG":
            return (
              <Stack sx={{ display: "flex", flexGrow: 1 }} gap={1.5}>
                {sequenceStepSelection?.[0]?.order !== null &&
                sequenceStepSelection?.[0]?.order !== 0 ? (
                  <>
                    <RecoveryRatesGroupSummary
                      scenarioId={sequenceStepSelection?.[0]?.item_id ?? ""}
                      portfolioId={portfolioId}
                      modelId={modelId}
                      refreshGrid={refresh}
                      order={sequenceStepSelection?.[0]?.order ?? null}
                      priority={sequenceStepSelection?.[0]?.priority ?? null}
                      refreshRowCells={handleEditEvent}
                    />
                    <RecoveryRateDerivationRuleGrid
                      scenarioId={sequenceStepSelection?.[0]?.item_id ?? ""}
                      isRenderedByCalSeq={true}
                    />
                  </>
                ) : null}
                {sequenceStepSelection?.[0]?.priority ? (
                  <RecoveryRatesRuleSummary
                    scenarioId={groupId.current ?? ""}
                    portfolioId={portfolioId}
                    modelId={modelId}
                    ruleId={sequenceStepSelection?.[0]?.item_id ?? ""}
                    refreshGrid={refresh}
                    priority={sequenceStepSelection?.[0]?.priority ?? null}
                    refreshAfterUpdate={refreshGrid}
                    childValueRef={childValueRef}
                  />
                ) : null}
              </Stack>
            );
          case "RDG":
            return (
              <Stack sx={{ display: "flex", flexGrow: 1 }} gap={1.5}>
                {sequenceStepSelection?.[0]?.order !== null &&
                sequenceStepSelection?.[0]?.order !== 0 ? (
                  <>
                    <RatingDerivationGroupSummary
                      scenarioId={sequenceStepSelection?.[0]?.item_id ?? ""}
                      portfolioId={portfolioId}
                      modelId={modelId}
                      refreshGrid={refresh}
                      order={sequenceStepSelection?.[0]?.order || null}
                      priority={sequenceStepSelection?.[0]?.priority ?? null}
                      refreshRowCells={handleEditEvent}
                    />
                    <RatingDerivationRuleGrid
                      scenarioId={sequenceStepSelection?.[0]?.item_id ?? ""}
                      isRenderedByCalSeq={true}
                    />
                  </>
                ) : null}
                {sequenceStepSelection?.[0]?.priority ? (
                  <RatingDerivationRuleSummary
                    scenarioId={groupId.current ?? ""}
                    portfolioId={portfolioId}
                    modelId={modelId}
                    ruleId={sequenceStepSelection?.[0]?.item_id ?? ""}
                    refreshGrid={refresh}
                    priority={sequenceStepSelection?.[0]?.priority ?? null}
                    refreshAfterUpdate={refreshGrid}
                    childValueRef={childValueRef}
                  />
                ) : null}
              </Stack>
            );
          case "PBG":
            return (
              <Stack sx={{ display: "flex", flexGrow: 1 }} gap={1.5}>
                {sequenceStepSelection?.[0]?.order !== null &&
                sequenceStepSelection?.[0]?.order !== 0 ? (
                  <>
                    <PrincipalBalanceRuleGroupDetails
                      pbGroupId={sequenceStepSelection?.[0]?.item_id ?? ""}
                      refreshGrid={refresh}
                      order={sequenceStepSelection?.[0]?.order ?? null}
                      priority={sequenceStepSelection?.[0]?.priority ?? null}
                      refreshRowCells={handleEditEvent}
                    />
                    <PrincipalBalanceRuleGrid
                      pbGroupId={sequenceStepSelection?.[0]?.item_id ?? ""}
                      isRenderedByCalSeq={true}
                    />
                  </>
                ) : null}
                {sequenceStepSelection?.[0]?.priority ? (
                  <PrincipalBalanceRuleDetails
                    pbGroupId={groupId.current ?? ""}
                    ruleId={sequenceStepSelection?.[0]?.item_id ?? ""}
                    priority={sequenceStepSelection?.[0]?.priority ?? null}
                    refreshGrid={refresh}
                    refreshAfterUpdate={refreshGrid}
                    childValueRef={childValueRef}
                  />
                ) : null}
              </Stack>
            );
          case "CRG":
            return (
              <Stack sx={{ display: "flex", flexGrow: 1 }} gap={1.5}>
                {sequenceStepSelection?.[0]?.order !== null &&
                sequenceStepSelection?.[0]?.order !== 0 ? (
                  <CalculationGroupDetails
                    groupId={
                      sequenceStepSelection?.[0]?.priority
                        ? groupId.current ?? ""
                        : sequenceStepSelection?.[0]?.order !== null
                        ? sequenceStepSelection?.[0]?.item_id ?? ""
                        : ""
                    }
                    blockId={
                      sequenceStepSelection?.[0]?.priority
                        ? sequenceStepSelection?.[0]?.item_id ?? ""
                        : ""
                    }
                    order={sequenceStepSelection?.[0]?.order ?? null}
                    priority={sequenceStepSelection?.[0]?.priority ?? null}
                    refreshToken={refreshToken}
                    refreshGrid={refresh}
                    childValueRef={childValueRef}
                    refreshRowCells={handleEditEvent}
                  ></CalculationGroupDetails>
                ) : null}
                {sequenceStepSelection?.[0]?.order !== null &&
                sequenceStepSelection?.[0]?.order !== 0 ? (
                  <CalculationBlockGrid
                    groupId={sequenceStepSelection?.[0]?.item_id ?? ""}
                    isRenderedByCalSeq={true}
                  ></CalculationBlockGrid>
                ) : null}
                {sequenceStepSelection?.[0]?.priority ? (
                  <>
                    <CalculationGroupDetails
                      groupId={groupId.current ?? ""}
                      blockId={sequenceStepSelection?.[0]?.item_id ?? ""}
                      order={sequenceStepSelection?.[0]?.order || null}
                      priority={sequenceStepSelection?.[0]?.priority ?? null}
                      refreshToken={refreshToken}
                      refreshGrid={refresh}
                      refreshAfterUpdate={refreshGrid}
                      childValueRef={childValueRef}
                    ></CalculationGroupDetails>
                    <CalculationParameterGrid />
                  </>
                ) : null}
              </Stack>
            );
          default:
            const unhandledScreenType: never = sequenceStepSelection?.[0]
              ?.type as never;
            throw new Error(
              `Unexpected screen type: ${unhandledScreenType}. Please double check
              the Calculation Sequence Component.`
            );
        }
      },
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [
      CalculationParameterGrid,
      modelId,
      portfolioId,
      refresh,
      refreshToken,
      sequenceStepSelection,
    ]
  );

  const ConditionalRightPanel = useMemo(
    () => () => {
      return sequenceStepSelection?.length === 1 &&
        sequenceStepSelection?.[0]?.type &&
        ["RRDG", "RDG", "PBG", "CRG"].includes(
          sequenceStepSelection?.[0]?.type?.trim()
        ) ? (
        <Stack gap={0} direction="column" sx={detailsContainerSx}>
          <PanelComponents refreshGrid={refreshGrid.current} />
        </Stack>
      ) : null;
    },
    [sequenceStepSelection, PanelComponents]
  );

  return (
    <Screen
      sx={screenSx}
      navigationId="compliance-modeling-ui-calculation-sequences"
    >
      <ScreenHeader>
        <ToolGroup aria-label="Calculation Sequence Toolbar">
          <SnapshotModelDropdown />
        </ToolGroup>
      </ScreenHeader>
      <Stack
        sx={calculationSequenceStackSx}
        direction={calculationSequenceStackDirection}
      >
        <Splitter expandable={true}>
          {/* left panel */}
          <Fragment>
            {portfolioId && isParameterValid(modelId) && data?.sequence_id ? (
              <AddTreeGridChildProvider>
                <CalculationStepGrid
                  key={`${portfolioId}-${modelId}-${data?.sequence_id ?? ""}`}
                  onSelectionChanged={handleSequenceStepSelectionChange}
                  sequenceId={data?.sequence_id ?? null}
                  portfolioId={portfolioId}
                  modelId={modelId}
                  sequenceStepSelection={sequenceStepSelection}
                  refreshView={refresh}
                  updateRefreshGrid={updateRefreshGrid}
                  childValueRef={childValueRef}
                  onGridApiReady={handleGridApiReady}
                >
                  <CalculationSequenceStepGridActions />
                </CalculationStepGrid>
              </AddTreeGridChildProvider>
            ) : null}
          </Fragment>
          {/* right panel */}
          {sequenceStepSelection?.length &&
          sequenceStepSelection?.[0]?.type != "PROJ" && // "Interest and Principal Projections" does not have a right panel
          sequenceStepSelection?.length === 1 ? (
            <ConditionalRightPanel />
          ) : sequenceStepSelection && sequenceStepSelection?.length > 1 ? (
            <Stack
              sx={(theme) => ({
                ...(detailsContainerSx as (theme: Theme) => any)(theme),
                alignItems: "center",
                justifyContent: "center",
              })}
            >
              <Typography variant="body1" fontWeight={400}>
                Select a single item for data to be displayed.
              </Typography>
            </Stack>
          ) : null}
        </Splitter>
      </Stack>
    </Screen>
  );
};

