import {
  AsyncDataGridPanel,
  ColGroupDefOverride,
  DataGridActionAdd,
  DataGridActionDelete,
  DataGridActionEdit,
  DataGridActionRefresh,
  DataGridAsyncDialogAction,
  DataGridDataServiceSource,
  DataGridQuickSearch,
  useRefreshToken,
} from "@textile/biz-components";
import { IconButtonProps, SxProps } from "@textile/mui";
import { FunctionComponent, useMemo, useRef, useState } from "react";
import { useParams } from "react-router-dom";

import { RecoveryRateDerivationRuleFormDialog } from "./recovery-rate-derivation-rule-form-dialog.component";
import { AppRouteParams } from "../../screen.types";
import {
  AppExpCellRenderer,
  ApplicabilityExpressionCellRendererContext,
} from "../../common/expression-renderer.component";
import { RecoveryDerivationRuleCopyDialog } from "./recovery-rate-derivation-rule-copy-dialog.component";
import {
  CustomDataGridDataServiceProvider,
  DataGridActionViewSource,
  DownloadActionMenu,
  useDdxValues,
} from "@solvasam/bizcomponents";
import { RecoveryRateDerivationRuleScenario } from "../common/dynamic-data-rules.types";
import { DuplicateIcon, useStaticAppContext } from "@textile/common";
import { usePriorityhook } from "../../calculation-sequence/hooks/usePriorityhook.component";
import { GridApi, GridReadyEvent } from "@textile/ag-grid";
import {
  useRefreshNeedReviewOnParentGrid,
  useRefreshNeedsReviewSync,
} from "../../common/refresh-need-review.hook";

const gridSx: SxProps = { flex: "1 1 0px" };

type RecoveryRateDerivationRuleProps = {
  scenarioId: string;
  ratingAgency?: string;
  isRenderedByCalSeq?: boolean;
};

export const RecoveryRateDerivationRuleGrid: FunctionComponent<
  RecoveryRateDerivationRuleProps
> = (props) => {
  const { scenarioId, ratingAgency, isRenderedByCalSeq } = props;
  const { portfolioId, modelId } = useParams<AppRouteParams>();
  const [refreshToken, refresh] = useRefreshToken();
  const { sharedAppContextManager } = useStaticAppContext();
  const [selectedRuleEtag, setSelectedRuleEtag] = useState<string | null>();
  const { state: selectedModelstate } = sharedAppContextManager.useContext<
    string | null
  >("app.selectedModelState");
  const iconButtonProps = useMemo<IconButtonProps>(() => {
    return selectedModelstate === "L" ? { disabled: true } : {};
  }, [selectedModelstate]);

  const recoveryRateDerivationRuleDelete = useMemo<DataGridDataServiceSource>(
    () => ({
      url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/recoveryScenarios/${scenarioId}/rules`,
      operationConfirmedParamLocation: "query",
      method: "delete",
    }),
    [modelId, scenarioId, portfolioId]
  );

  const { maxPriority } = usePriorityhook(
    !!scenarioId,
    portfolioId,
    modelId,
    scenarioId,
    "RRDG",
    refresh
  );

  const recoveryRateDerivationRuleDataSource =
    useMemo<DataGridDataServiceSource>(
      () => ({
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/recoveryScenarios/${scenarioId}/rules:view`,
      }),
      [modelId, scenarioId, portfolioId]
    );

  const colGroupDefOverrides = useMemo(
    () =>
      [
        {
          field: "applicability_expression",
          headerName: "Applicability Expression",
          colDef: {
            field: "applicability_expression",
            cellRenderer: AppExpCellRenderer,
            headerName: "Applicability Expression",
            wrapText: true,
            autoHeight: true,
          },
        },
      ] as unknown as ColGroupDefOverride[],
    []
  );

  const handleSelectionChange = (
    selectedRules: RecoveryRateDerivationRuleScenario[]
  ) => {
    setSelectedRuleEtag(
      selectedRules.length === 1 ? selectedRules[0].etag : null
    );
  };

  const ddxData = useDdxValues();
  const agGridApiRef = useRef<GridApi | null>(null);

  useRefreshNeedReviewOnParentGrid(scenarioId, "RRDG", "RRDR", agGridApiRef);
  useRefreshNeedsReviewSync(agGridApiRef, "RRDR", "RRDR");

  return (
    <ApplicabilityExpressionCellRendererContext.Provider
      value={{
        refresh: refresh,
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/recoveryScenarios/${scenarioId}/rules`,
        ruleEtag: selectedRuleEtag,
        ddxData,
        readonlyMode: selectedModelstate === "L",
      }}
    >
      <CustomDataGridDataServiceProvider>
        <AsyncDataGridPanel
          sx={gridSx}
          dataSource={
            modelId && scenarioId && portfolioId
              ? recoveryRateDerivationRuleDataSource
              : null
          }
          rowSelectionMode={isRenderedByCalSeq ? "single" : "multi"}
          refreshToken={refreshToken}
          colGroupDefOverrides={colGroupDefOverrides}
          onSelectionChanged={handleSelectionChange}
          gridPersistOptions={{
            key: "RRDR",
            enabled: true,
          }}
          agGridProps={{
            defaultColDef: {
              minWidth: 120,
              resizable: true,
              wrapHeaderText: true,
              autoHeaderHeight: true,
            },
            onGridReady: (e: GridReadyEvent) => {
              agGridApiRef.current = e.api;
            },
          }}
        >
          {!isRenderedByCalSeq && (
            <>
              <DataGridQuickSearch></DataGridQuickSearch>
              <DataGridActionAdd
                iconButtonProps={iconButtonProps}
                dialog={
                  <RecoveryRateDerivationRuleFormDialog
                    rrdgId={scenarioId}
                    priority={maxPriority}
                  ></RecoveryRateDerivationRuleFormDialog>
                }
              ></DataGridActionAdd>
              <DataGridActionEdit
                iconButtonProps={iconButtonProps}
                dialog={
                  <RecoveryRateDerivationRuleFormDialog rrdgId={scenarioId} />
                }
              ></DataGridActionEdit>
              <DataGridActionDelete
                iconButtonProps={iconButtonProps}
                operation={recoveryRateDerivationRuleDelete}
              ></DataGridActionDelete>
              <DataGridAsyncDialogAction
                actionCode="duplicate"
                label="Duplicate"
                level="grid"
                loadOnOpen={false}
                type="icon"
                icon={<DuplicateIcon size={24} />}
                iconButtonProps={iconButtonProps}
                onUpdateUi={refresh}
                dialog={
                  <RecoveryDerivationRuleCopyDialog
                    ratingAgency={ratingAgency}
                    scenarioId={scenarioId}
                  />
                }
              />
              <DataGridActionRefresh></DataGridActionRefresh>
            </>
          )}
          <DownloadActionMenu />
          <DataGridActionViewSource
            datasource={recoveryRateDerivationRuleDataSource}
          />
        </AsyncDataGridPanel>
      </CustomDataGridDataServiceProvider>
    </ApplicabilityExpressionCellRendererContext.Provider>
  );
};

