interface PrincipalBalanceRuleCopyFormProps
  extends Partial<AsyncFormDialogProps> {
  pbGroupId?: string;
}

const ruleGridSx: SxProps = {
  flex: "1 1 0px",
  minHeight: "20%",
};

const PrincipalBalanceRuleCopyForm = () => {
  const [{ value: sourcePortfolio }] = useField("portfolio_id");
  const [{ value: sourceModel }] = useField("model_id");
  const [{ value: sourceRuleGroup }] = useField("group_id");
  const { modelsListDataSource } = useModelDataSource(sourcePortfolio);

  const selectSourceRuleGroupDataSource =
    useMemo<AutocompleteDataServiceProviderDataSource>(
      () => ({
        url: `/compliance-bff/v1/portfolios/${sourcePortfolio}/models/${sourceModel}/pbRuleGroups`,
        dataPath: "pb_rule_groups",
      }),
      [sourceModel, sourcePortfolio]
    );

  const pbRuleDataSource = useMemo<AutocompleteDataServiceProviderDataSource>(
    () => ({
      url: `/compliance-bff/v1/portfolios/${sourcePortfolio}/models/${sourceModel}/pbRuleGroups/${sourceRuleGroup}/rules`,
      dataPath: "pb_rules",
    }),
    [sourcePortfolio, sourceModel, sourceRuleGroup]
  );

  const onBeforePopulate = async (data: Partial<PrincipalBalanceRule>[]) => {
    return data.map((record) => {
      return {
        ...record,
        description_ui: `${record.priority} - ${record.rule_applicability} - ${record.valuation_option}`,
      };
    });
  };

  return (
    <Fragment>
      <FormPortfolioAutocomplete
        fieldName="portfolio_id"
        textFieldProps={{
          label: "Source Portfolio",
          variant: "outlined",
          required: true,
        }}
      ></FormPortfolioAutocomplete>
      <AsyncFormAutocomplete
        fieldName="model_id"
        dataSource={sourcePortfolio ? modelsListDataSource : null}
        valueField="id"
        labelField="description"
        textFieldProps={{
          label: "Source Model",
          variant: "outlined",
          required: true,
        }}
      />
      <AsyncFormAutocomplete
        fieldName="group_id"
        dataSource={
          sourcePortfolio && sourceModel
            ? selectSourceRuleGroupDataSource
            : null
        }
        valueField="id"
        labelField="description"
        textFieldProps={{
          label: "Source Rule Group",
          variant: "outlined",
          required: true,
        }}
      />
      <AsyncFormSelect
        fieldName={"selected_pb_rules"}
        dataSource={
          sourcePortfolio && sourceModel && sourceRuleGroup
            ? pbRuleDataSource
            : []
        }
        labelField={"description_ui"}
        valueField={"name"}
        label="Source Principal Balance Calculation Rule"
        onBeforePopulate={onBeforePopulate}
        required
        multiple
      >
        <DropdownTransferList autoFocusSearch />
      </AsyncFormSelect>
    </Fragment>
  );
};

const PrincipalBalanceRuleCopyDialog: FunctionComponent<
  PrincipalBalanceRuleCopyFormProps
> = ({ pbGroupId, ...props }) => {
  const theme = useTheme();
  const fullScreen = useMediaQuery(theme.breakpoints.down("md"));
  const { portfolioId, modelId } = useParams<AppRouteParams>();

  const principalBalanceRuleCopyDataSource = useMemo(
    () => ({
      idField: "id",
      mode: "add",
      save: {
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/pbRuleGroups/${pbGroupId}/rules:copy`,
        method: "post",
      },
    }),
    [portfolioId, modelId, pbGroupId]
  );

  const onBeforeCopy = async (data: Partial<PBRulesImportProps>) => {
    const names: string[] = [];
    data.selected_pb_rules?.forEach((record) => {
      if (record) names.push(record);
    });

    return {
      names: names,
    };
  };

  return (
    <AsyncFormDialog
      {...props}
      dataSource={principalBalanceRuleCopyDataSource}
      title="Duplicate Principal Balance Calculation Rules"
      fullScreen={fullScreen}
      enableFullScreenToggle={true}
      fullWidth
      submitButtonLabel="Duplicate"
      defaultData={{
        portfolio_id: portfolioId,
        model_id: modelId,
        group_id: pbGroupId,
      }}
      onBeforeSave={onBeforeCopy}
      PaperProps={{
        sx: getDialogResizePaperPropsSx("lg"),
      }}
      draggable={true}
    >
      <PrincipalBalanceRuleCopyForm />
    </AsyncFormDialog>
  );
};

interface PBRulesImportProps {
  portfolio_id?: string;
  model_id?: string;
  group_id?: string;
  selected_pb_rules?: string[];
}

export const PrincipalBalanceRuleGrid: FunctionComponent<{
  pbGroupId: string;
  isRenderedByCalSeq?: boolean;
}> = ({ pbGroupId, isRenderedByCalSeq }) => {
  const { modelId, portfolioId } = useParams<AppRouteParams>();
