      url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/pbRuleGroups/${pbGroupId}/rules:view`,
    }),
    [modelId, pbGroupId, portfolioId]
  );

  const pbRulesDeleteOperation = useMemo<FabricAsyncOperation>(
    () => ({
      url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/pbRuleGroups/${pbGroupId}/rules`,
      operationConfirmedParamLocation: "query",
      method: "delete",
    }),
    [modelId, portfolioId, pbGroupId]
  );

  const colDefOverrides: ColDefOverride[] = useMemo(
    () => [
      {
        field: "applicability_expression",
        colDef: {
          cellRenderer: (params: ICellRendererParams) => {
            return params.data?.type === "CUST" ? (
              <AppExpCellRenderer {...params} />
            ) : (
              <NoneRenderer />
            );
          },
          headerName: "Applicability Expression",
          wrapText: true,
          autoHeight: true,
        },
      },
      {
        field: "formula_expression",
        colDef: {
          cellRenderer: (params: ICellRendererParams) => {
            return params.data?.valuation_option === "Formula" ? (
              <FormulaExpCellRenderer {...params} />
            ) : (
              <NoneRenderer />
            );
          },
          headerName: "Formula",
          wrapText: true,
          autoHeight: true,
        },
      },
    ],
    []
  );

  const handleSelectionChange = (selectedRules: PrincipalBalanceRule[]) => {
    setSelectedRuleEtag(
      selectedRules.length === 1 ? selectedRules[0].etag : null
    );
  };
  const ddxData = useDdxValues();
  useRefreshNeedReviewOnParentGrid(pbGroupId, "PBG", "PBR", agGridApiRef);
  useRefreshNeedsReviewSync(agGridApiRef, "PBR", "PBR");
  return (
    <ApplicabilityExpressionCellRendererContext.Provider
      value={{
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/pbRuleGroups/${pbGroupId}/rules`,
        refresh: refresh,
        ruleEtag: selectedRuleEtag,
        ddxData,
        readonlyMode: selectedModelstate === "L",
      }}
    >
      <AsyncDataGridPanel
        dataSource={pbRulesDataSource}
        sx={ruleGridSx}
        rowSelectionMode={isRenderedByCalSeq ? "single" : "multi"}
        refreshToken={refreshToken}
        colDefOverrides={colDefOverrides}
        onSelectionChanged={handleSelectionChange}
        agGridProps={{
          onGridReady: (e: GridReadyEvent) => {
            agGridApiRef.current = e.api;
            setGridApi(e.api);
          },
        }}
        gridPersistOptions={{
          key: "PBR",
          enabled: true,
        }}
      >
        {!isRenderedByCalSeq && (
          <>
            <DataGridQuickSearch></DataGridQuickSearch>
            <DataGridActionAdd
              iconButtonProps={iconButtonProps}
              dialog={
                <PrincipalBalanceRulesFormDialog
                  pbGroupId={pbGroupId}
                  gridApi={gridApi}
                />
              }
              onUpdateUi={refresh}
            />
            <DataGridActionEdit
              iconButtonProps={iconButtonProps}
              dialog={
                <PrincipalBalanceRulesFormDialog
                  pbGroupId={pbGroupId}
                  gridApi={gridApi}
                />
              }
              onUpdateUi={refresh}
            />
