              actionCode="duplicate"
              label="Duplicate"
              level="grid"
              type="icon"
              icon={<DuplicateIcon size={24} />}
              iconButtonProps={iconButtonProps}
              loadOnOpen={false}
              onUpdateUi={refresh}
              dialog={<PrincipalBalanceRuleCopyDialog pbGroupId={pbGroupId} />}
            />
            <DataGridActionDelete
              iconButtonProps={iconButtonProps}
              operation={pbRulesDeleteOperation}
            />
            <DataGridActionRefresh></DataGridActionRefresh>
          </>
