  });

  const onOperationConfirmed = async () => {
    if (data?.is_in_sequence) {
      agGridApiRef.current?.setGridOption("loading", true);
      deleteData(
        `${baseUrl}/portfolios/${portfolioId}/models/${modelId}/sequences/${sequenceId}/steps/${data?.id}?operation_confirmed=1`
      ).then((resp) => {
        if (resp?.status === 200) refresh ? refresh() : null;
      });
      agGridApiRef.current?.setGridOption("loading", false);
    } else {
      agGridApiRef.current?.setGridOption("loading", true);
      const totalStepOrders = getTotalSteps(agGridApiRef);

      let reqObject = {};
      if (Number(data?.order) === 0) {
        reqObject = {
          sequence_step: {
            ...data,
            order: totalStepOrders.length + 1,
            is_in_sequence: true,
          },
        };
      } else {
        reqObject = {
          sequence_step: {
            ...data,
            is_in_sequence: true,
          },
        };
      }

      fetchData(
        `${baseUrl}/portfolios/${portfolioId}/models/${modelId}/sequences/${sequenceId}/steps?operation_confirmed=1`,
        { ...reqObject }
      ).then((resp) => {
        if (resp?.status === 200) refresh ? refresh() : null;
      });
      agGridApiRef.current?.setGridOption("loading", false);
    }
  };
  const handleSwitchClick = () => {
    agGridApiRef.current?.getRowNode(data.id)?.setSelected(false);
    onOperationConfirmed();
  };
  return (
    <>
      <Switch
        checked={data?.is_in_sequence}
        disabled={disabled}
        ref={buttonRef}
        sx={{
          position: "absolute",
          top: "50%",
          left: "50%",
          transform: "translate(-50%, -50%)",
        }}
        onClick={handleSwitchClick}
      ></Switch>
    </>
  );
};

