};

import { DependencyList, useState, useEffect, useCallback } from "react";
import { useAxiosFactory, useMessageAnnouncer } from "@textile/common";
import {
  isOperationError,
  mapFabricBadRequestToError,
} from "@textile/biz-components";
import { AxiosRequestConfig, Method } from "axios";

interface FetchOptions {
  method: Method;
  url: string;
  query_params?: Record<string, string | number | boolean | object | undefined>;
  body?: unknown;
  deps: DependencyList;
  autoFetch?: boolean;
}

interface FetchState<T> {
  data: T | null;
  fetchData: (
    newUrl?: string,
    newBody?: Record<string, unknown>
  ) => Promise<{ status: number; data: T } | undefined>; //Accepts optional new URL
}

export const useFetch = <T,>({
  url,
  deps = [],
  body = null,
  query_params = undefined,
  autoFetch = true,
  method,
}: FetchOptions): FetchState<T> => {
  const [data, setData] = useState<T | null>(null);
  const axiosFactory = useAxiosFactory();
  const messageAnnouncer = useMessageAnnouncer();

  const fetchData = useCallback(
    async (newUrl?: string, newBody?: Record<string, unknown>) => {
      const requestUrl = newUrl || url;

      if (deps.length === 0 || requestUrl === "") return;
      const abortController = new AbortController();
      const config: AxiosRequestConfig = {
        url: requestUrl,
        params: query_params ? query_params : null,
        method: method,
        headers: {
          "Content-Type": "application/json",
        },
        data: method !== "GET" ? (newBody ? newBody : body) : null,
        signal: abortController.signal,
      };

      try {
        const axios = await axiosFactory.createAxiosInstance(config);
        const { data, status } = await axios(config);
        if (method === "GET") {
          setData(data);
        }
        return { status, data };
      } catch (error) {
        const operationError = mapFabricBadRequestToError(
          error,
          abortController
        );
        if (isOperationError(operationError)) {
          if (operationError.operationResult.length > 0) {
            messageAnnouncer.error(
              `Failed to load Data: ${operationError.operationResult[0].message}`
            );
          }
        } else {
          messageAnnouncer.error(
            `Failed to load Data: ${
              operationError instanceof Error
                ? operationError.message
                : operationError
            }`
          );
        }
      }
    },
    [
      axiosFactory,
      messageAnnouncer,
      method,
      url,
      body,
      deps.length,
      query_params,
    ]
  );

  useEffect(() => {
    if (autoFetch) {
      fetchData();
    }
  }, [fetchData, autoFetch]);

  return { data, fetchData };
};

