import {
  ArrowDownIcon,
  ArrowUpIcon,
  EditIcon,
  ToolGroup,
  useAxiosFactory,
  useStaticAppContext,
} from "@textile/common";
import { Box, Collapse, IconButton, Stack, Typography } from "@textile/mui";
import { FunctionComponent, useState, useMemo, useEffect } from "react";

import { RatingScenario } from "../common/dynamic-data-rules.types";
import { CommonProps } from "../../common";
import { baseUrl } from "../../../apis";
import { EditGroupDetailsComponent } from "../../calculation-sequence/common/edit-group-details.component";
import { RatingDerivationGroupFormDialog } from "./rating-derivation-group-form-dialog.component";
import {
  CodePair,
  SummaryComponent,
  SummaryDownloadActionMenu,
  SummaryRow,
  ViewCustomSourceActionDialog,
} from "@solvasam/bizcomponents";

interface RatingDerivationGroupDetailProps {
  portfolioId?: string;
  modelId?: string;
  scenarioId: string;
  editButtonRef?: React.RefObject<HTMLButtonElement> | null;
  refreshToken?: symbol;
  order?: number | null;
  priority?: number | null;
}

export const RatingDerivationGroupSummary: FunctionComponent<
  RatingDerivationGroupDetailProps & CommonProps
> = ({
  scenarioId,
  portfolioId,
  modelId,
  editButtonRef,
  refreshToken,
  refreshGrid,
  order,
  priority,
  refreshRowCells,
}) => {
  const [isCollapsed, setIsCollapsed] = useState(true);

  const { sharedAppContextManager } = useStaticAppContext();
  const { state: modelstate } = sharedAppContextManager.useContext<
    string | null
  >("app.selectedModelState");

  const [groupDetail, setGroupDetail] = useState<RatingScenario | null>(null);

  const axiosFactory = useAxiosFactory();

  useEffect(() => {
    const abortController = new AbortController();

    const loadGroups = async () => {
      const axios = await axiosFactory.createAxiosInstance();
      const { data } = await axios.get<RatingScenario>(
        `${baseUrl}/portfolios/${portfolioId}/models/${modelId}/ratingScenarios/${scenarioId}`,
        { signal: abortController.signal }
      );
      setGroupDetail(data);
    };
    if (scenarioId) loadGroups();

    return () => abortController.abort();
  }, [portfolioId, modelId, scenarioId, refreshToken, axiosFactory]);

  const summaryRows: CodePair[] = useMemo(
    () => [
      {
        code: "Rating Agency",
        description: groupDetail?.rating_agency_description ?? "",
      },
      {
        code: "Derivation Group",
        description: groupDetail?.number?.toString() ?? "",
      },
      {
        code: "Description",
        description: groupDetail?.description ?? "",
      },
      {
        code: "Resolution of Rules with Equal Priority",
        description: groupDetail?.same_priority_preference_description ?? "",
      },
      {
        code: "Resolution of Rules with Multiple Sources",
        description: groupDetail?.same_priority_designation_description ?? "",
      },
      {
        code: "Notching Preference",
        description: groupDetail?.notching_preference_description ?? "",
      },
      {
        code: "Copy Source",
        description: groupDetail?.copy_source_description ?? "",
      },
      {
        code: "Comments",
        description: groupDetail?.comments ?? "",
      },
    ],
    [groupDetail]
  );

  const GroupDetailComp = EditGroupDetailsComponent(
    RatingDerivationGroupFormDialog,
    groupDetail,
    refreshGrid
  );

  return (
    <Stack gap={0.5}>
      <ToolGroup
        display={"flex"}
        sx={{ height: "32px", gap: 1, alignItems: "center" }}
        aria-label="Rating Derivation Group Properties"
      >
        <Typography variant="subtitle2" fontWeight={600}>
          Rating Derivation Group Properties
        </Typography>
        <Box sx={{ flexGrow: 1 }} />
        {editButtonRef && !order && !priority ? (
          <IconButton
            aria-label="Edit Rating Derivation Group"
            onClick={(event) => {
              event.stopPropagation();
              editButtonRef?.current?.click();
            }}
            disabled={modelstate === "L"}
          >
            <EditIcon size={24} />
          </IconButton>
        ) : order && !priority && groupDetail ? (
          <GroupDetailComp
            portfolioId={portfolioId}
            modelId={modelId}
            ratingAgency={groupDetail.rating_agency}
            refreshDescriptionCell={refreshRowCells}
          />
        ) : null}
        <SummaryDownloadActionMenu
          filename={"Rating Derivation Group"}
          rows={summaryRows}
        />
        <ViewCustomSourceActionDialog url={baseUrl + "/" + groupDetail?.name} />
        <IconButton
          aria-label="collapse"
          onClick={() => {
            setIsCollapsed(!isCollapsed);
          }}
        >
          {isCollapsed ? (
            <ArrowUpIcon size={24} />
          ) : (
            <ArrowDownIcon size={24} />
          )}
        </IconButton>
      </ToolGroup>
      <Collapse in={isCollapsed}>
        <SummaryComponent cardSx={{ maxHeight: "30vh", overflow: "auto" }}>
          {summaryRows.map((row, index) => (
            <SummaryRow key={index} Key={row.code} Value={row.description} />
          ))}
        </SummaryComponent>
      </Collapse>
    </Stack>
  );
};

import {
  ArrowDownIcon,
  ArrowUpIcon,
  EditIcon,
  ToolGroup,
  useAxiosFactory,
  useStaticAppContext,
} from "@textile/common";
import { Box, Collapse, IconButton, Stack, Typography } from "@textile/mui";
import {
  FunctionComponent,
  useState,
  useMemo,
  useEffect,
  MutableRefObject,
} from "react";

import { RatingRule } from "../common/dynamic-data-rules.types";
import { CommonProps } from "../../common";
import { baseUrl } from "../../../apis";
import { EditGroupDetailsComponent } from "../../calculation-sequence/common/edit-group-details.component";
import { RatingDerivationRuleFormDialog } from "./rating-derivation-rule-form.dialog.component";
import {
  CodePair,
  ddxFormatter,
  RuleDisplayComponent,
  SummaryComponent,
  SummaryDownloadActionMenu,
  SummaryRow,
  useDdxValues,
  ViewCustomSourceActionDialog,
} from "@solvasam/bizcomponents";

interface RatingDerivationRuleDetailProps {
  portfolioId?: string;
  modelId?: string;
  scenarioId: string;
  ruleId: string;
  editButtonRef?: React.RefObject<HTMLButtonElement> | null;
  refreshToken?: symbol;
  priority?: number | null;
  refreshAfterUpdate?: () => void | null;
  childValueRef: MutableRefObject<string | null>;
}

export const RatingDerivationRuleSummary: FunctionComponent<
  RatingDerivationRuleDetailProps & CommonProps
> = ({
  scenarioId,
  portfolioId,
  modelId,
  ruleId,
  editButtonRef,
  refreshToken,
  priority,
  refreshGrid,
  refreshAfterUpdate,
  childValueRef,
}) => {
  const [isCollapsed, setIsCollapsed] = useState(true);
  const { sharedAppContextManager } = useStaticAppContext();
  const { state: modelstate } = sharedAppContextManager.useContext<
    string | null
  >("app.selectedModelState");

  const [ruleDetail, setRuleDetail] = useState<RatingRule | null>(null);

  const axiosFactory = useAxiosFactory();

  const ddxData = useDdxValues();
  useEffect(() => {
    const abortController = new AbortController();

    const loadGroups = async () => {
      const axios = await axiosFactory.createAxiosInstance();
      const { data } = await axios.get<RatingRule>(
        `${baseUrl}/portfolios/${portfolioId}/models/${modelId}/ratingScenarios/${scenarioId}/rules/${ruleId}`,
        { signal: abortController.signal }
      );
      setRuleDetail(data);
    };
    if (scenarioId && ruleId) loadGroups();

    return () => abortController.abort();
  }, [portfolioId, modelId, scenarioId, ruleId, refreshToken, axiosFactory]);

  const summaryRows: CodePair[] = useMemo(
    () => [
      { code: "Description", description: ruleDetail?.description ?? "" },
      {
        code: "Derived From",
        description: ruleDetail?.rule_type_description ?? "",
      },
      {
        code: "Outlook Preference",
        description: ruleDetail?.outlook_preference ?? "",
      },
      {
        code: "Rating Source",
        description: ruleDetail?.designation_description ?? "",
      },
      {
        code: "Priority",
        description: (ruleDetail?.rule_priority ?? 0).toString(),
      },
      {
        code: "Rating Agency Used",
        description: ruleDetail?.reference_rating_agency ?? "",
      },
      {
        code: "Highest Rating Used",
        description: ruleDetail?.reference_rating_maximum ?? "",
      },
      {
        code: "Lowest Rating Used",
        description: ruleDetail?.reference_rating_minimum ?? "",
      },
      {
        code: "Adjustment to Reference Rating",
        description: ruleDetail?.reference_rating_adjustment.toString() ?? "",
      },
      {
        code: "Adjustment to Positive Watch",
        description:
          ruleDetail?.reference_rating_upgrade_adjustment.toString() ?? "",
      },
      {
        code: "Adjustment to Negative Watch",
        description:
          ruleDetail?.reference_rating_downgrade_adjustment.toString() ?? "",
      },
      {
        code: "Adjustment to Positive Outlook",
        description:
          ruleDetail?.reference_rating_positive_outlook_adjustment.toString() ??
          "",
      },
      {
        code: "Adjustment to Negative Outlook",
        description:
          ruleDetail?.reference_rating_negative_outlook_adjustment.toString() ??
          "",
      },
      {
        code: "Highest Rating After Adjustment",
        description: ruleDetail?.reference_rating_adjustment_maximum ?? "",
      },
      {
        code: "Lowest Rating After Adjustment",
        description: ruleDetail?.reference_rating_adjustment_minimum ?? "",
      },
      {
        code: "Applicability Expression",
        description: ddxFormatter.format(
          ruleDetail?.applicability_expression?.friendly_description ?? ""
        ),
      },
      {
        code: "Copy Source",
        description: ruleDetail?.copy_source_description ?? "",
      },
      { code: "Comments", description: ruleDetail?.comments ?? "" },
    ],
    [ruleDetail]
  );

  const RatingDerivationRuleComp = EditGroupDetailsComponent(
    RatingDerivationRuleFormDialog,
    ruleDetail,
    refreshGrid,
    refreshAfterUpdate,
    childValueRef
  );

  return (
    <Stack gap={0.5}>
      <ToolGroup
        display={"flex"}
        sx={{ height: "32px", gap: 1, alignItems: "center" }}
        aria-label="Rating Derivation Rule Properties"
      >
        <Typography variant="subtitle2" fontWeight={600}>
          Rating Derivation Rule Properties
        </Typography>
        <Box sx={{ flexGrow: 1 }} />
        {editButtonRef && !priority ? (
          <IconButton
            aria-label="Edit Rating Derivation Rule"
            onClick={(event) => {
              event.stopPropagation();
              editButtonRef?.current?.click();
            }}
            disabled={modelstate === "L"}
          >
            <EditIcon size={24} />
          </IconButton>
        ) : priority && ruleDetail && ruleDetail?.reference_rating_agency ? (
          <RatingDerivationRuleComp
            scenarioId={scenarioId}
            ratingAgency={ruleDetail.reference_rating_agency ?? null}
          />
        ) : null}
        <SummaryDownloadActionMenu
          filename={"Rating Derivation Rule"}
          rows={summaryRows}
        />
        <ViewCustomSourceActionDialog url={baseUrl + "/" + ruleDetail?.name} />
        <IconButton
          aria-label="collapse"
          onClick={() => {
            setIsCollapsed(!isCollapsed);
          }}
        >
          {isCollapsed ? (
            <ArrowUpIcon size={24} />
          ) : (
            <ArrowDownIcon size={24} />
          )}
        </IconButton>
      </ToolGroup>
      <Collapse in={isCollapsed}>
        <SummaryComponent>
          {summaryRows.map((row, index) => (
            <SummaryRow
              key={index}
              Key={row.code}
              Value={
                row.code === "Applicability Expression" ? (
                  <RuleDisplayComponent
                    ddxData={ddxData}
                    value={row.description}
                  />
                ) : (
                  row.description
                )
              }
            />
          ))}
        </SummaryComponent>
      </Collapse>
    </Stack>
  );
};

