import { PrincipalBalanceRule } from "../common/dynamic-data-rules.types";
import { CommonProps } from "../../common";
import { AppRouteParams } from "../../screen.types";

import { baseUrl } from "../../../apis";
import { EditGroupDetailsComponent } from "../../calculation-sequence/common/edit-group-details.component";
import { PrincipalBalanceRulesFormDialog } from "./principal-balance-rule-form-dialog.component";
import {
  CodePair,
  ddxFormatter,
  RuleDisplayComponent,
  SummaryComponent,
  SummaryDownloadActionMenu,
  SummaryRow,
  useDdxValues,
  ViewCustomSourceActionDialog,
} from "@solvasam/bizcomponents";

const shimBox: SxProps = {
  flexGrow: 1,
};
export const PrincipalBalanceRuleDetails: FunctionComponent<
  {
    pbGroupId: string;
    ruleId: string;
    editButtonRef?: React.RefObject<HTMLButtonElement> | null;
    priority?: number | null;
    refreshAfterUpdate?: () => void | null;
    childValueRef: MutableRefObject<string | null>;
  } & CommonProps
> = ({
  pbGroupId,
  ruleId,
  editButtonRef,
  refreshToken,
  refreshGrid,
  priority,
  refreshAfterUpdate,
  childValueRef,
}) => {
  const [isDetailsCollapsed, setIsDetailsCollapsed] = useState(true);
  const { portfolioId, modelId } = useParams<AppRouteParams>();
  const { sharedAppContextManager } = useStaticAppContext();
  const { state: modelstate } = sharedAppContextManager.useContext<
    string | null
  >("app.selectedModelState");

  const [principalBalanceRule, setPrincipalBalanceRule] =
    useState<PrincipalBalanceRule | null>(null);

  const axiosFactory = useAxiosFactory();
  const ddxValues = useDdxValues();
  useEffect(() => {
    const abortController = new AbortController();

    const loadRules = async () => {
      const axios = await axiosFactory.createAxiosInstance();
      const { data } = await axios.get<PrincipalBalanceRule>(
        `${baseUrl}/portfolios/${portfolioId}/models/${modelId}/pbRuleGroups/${pbGroupId}/rules/${ruleId}`,
        { signal: abortController.signal }
      );
      setPrincipalBalanceRule(data);
    };
    if (pbGroupId && ruleId) loadRules();

    return () => abortController.abort();
  }, [portfolioId, modelId, pbGroupId, ruleId, refreshToken, axiosFactory]);

  const summaryRows: CodePair[] = useMemo(
    () => [
      {
        code: "Priority",
        description: principalBalanceRule?.priority?.toString() ?? "0",
      },
      {
        code: "Description",
        description: principalBalanceRule?.description ?? "",
      },
      {
        code: "Rule Applicability",
        description: principalBalanceRule?.rule_applicability ?? "",
      },
      {
        code: "Valuation Method",
        description: principalBalanceRule?.value_data_type_description ?? "",
      },
      {
        code: "Valuation Option",
        description: principalBalanceRule?.valuation_option ?? "",
      },
      {
        code: "Formula",
        description:
          principalBalanceRule?.formula_expression?.friendly_description ?? "",
      },
      {
        code: "Price Option",
        description:
          principalBalanceRule?.purchase_price_option_description ?? "",
      },
      {
        code: "Percentage Of Par",
        description: principalBalanceRule?.par_percentage?.toString() ?? "",
      },
      {
        code: "Par Capitalized Interest Option",
        description:
          principalBalanceRule?.par_calculation_method_description ?? "",
      },
      {
        code: "Include Accrued PIK Interest",
        description: principalBalanceRule?.include_accrued_pik ? "Yes" : "No",
      },
      {
        code: "Applicability Expression",
        description: ddxFormatter.format(
          principalBalanceRule?.applicability_expression
            ?.friendly_description ?? ""
        ),
      },
      {
        code: "Copy Source",
        description: principalBalanceRule?.copy_source_description ?? "",
      },
      {
        code: "Comments",
        description: principalBalanceRule?.comments ?? "",
      },
    ],
    [principalBalanceRule]
  );

  const PrincipleBalanceRuleComp = EditGroupDetailsComponent(
    PrincipalBalanceRulesFormDialog,
    principalBalanceRule,
    refreshGrid,
    refreshAfterUpdate,
    childValueRef
  );
  const ddxData = useDdxValues();
  return (
    <Stack gap={0.5}>
      <ToolGroup
        display={"flex"}
        sx={{ height: "32px", gap: 1, alignItems: "center" }}
        aria-label="Principal Balance Rule Properties"
      >
        <Typography variant="subtitle2" fontWeight={600}>
          Principal Balance Rule Properties
        </Typography>
        <Box sx={shimBox} />
        {editButtonRef && !priority ? (
          <IconButton
            aria-label="Edit Principal Balance Rule"
            onClick={(event) => {
              event.stopPropagation();
              editButtonRef?.current?.click();
            }}
            disabled={modelstate === "L"}
          >
            <EditIcon size={24} />
          </IconButton>
        ) : priority && principalBalanceRule ? (
          <PrincipleBalanceRuleComp pbGroupId={pbGroupId} />
        ) : null}
        <SummaryDownloadActionMenu
          filename={"Principal Balance Rule"}
          rows={summaryRows}
        />
        <ViewCustomSourceActionDialog
          url={baseUrl + "/" + principalBalanceRule?.name}
        />
        <IconButton
          aria-label="collapse"
          onClick={() => {
            setIsDetailsCollapsed(!isDetailsCollapsed);
          }}
        >
          {isDetailsCollapsed ? (
            <ArrowUpIcon size={24} />
          ) : (
            <ArrowDownIcon size={24} />
          )}
        </IconButton>
      </ToolGroup>
      <Collapse in={isDetailsCollapsed}>
        <SummaryComponent>
          {summaryRows.map((row, index) => (
            <SummaryRow
              key={index}
              Key={row.code}
              Value={
                row.code === "Applicability Expression" ? (
                  <RuleDisplayComponent
                    value={row.description}
                    ddxData={ddxValues}
                  />
                ) : (
                  row.description
                )
              }
            />
          ))}
        </SummaryComponent>
      </Collapse>
    </Stack>
  );
};

