import {
  ActionButton,
  ActionMenu,
  ActionTargetIds,
  AsyncDataGridPanel,
  caseInsensitiveComparator,
  ColDefOverride,
  DataGridActionAdd,
  DataGridActionEdit,
  DataGridAsyncDialogAction,
  DataGridDataServiceSource,
  DataGridQuickSearch,
  useRefreshToken,
} from "@textile/biz-components";
import { DuplicateIcon, useStaticAppContext } from "@textile/common";
import { IconButtonProps, SxProps } from "@textile/mui";
import React, {
  createContext,
  Fragment,
  FunctionComponent,
  MutableRefObject,
  ReactNode,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useRef,
  useState,
} from "react";
import { useParams } from "react-router-dom";

import { PriorityOfPaymentsFormDialog } from "./priority-of-payments-form-dialog.component";
import { PriorityOfPayment } from "../priority-of-payments.types";
import { AppRouteParams } from "../../screen.types";
import {
  getTotalSteps,
  isParameterValid,
  usePopulateSuccessMessage,
} from "../../common";
import {
  GridApi,
  GridReadyEvent,
  ICellRendererParams,
  IRowNode,
  RowDragEvent,
} from "@textile/ag-grid";
import {
  DataGridActionViewSource,
  DownloadActionMenu,
  NumericCellEditor,
} from "@solvasam/bizcomponents";
import { PriorityOfPaymentsCopyFormDialog } from "./priority-of-payment-copy-form-dialog.component";
import { AddTreeGridChildContext } from "../../common/add-tree-grid-child-context.component";
import { PaymentStepFormDialog } from "./payment-step-form-dialog.component";
import { AddPaymentStepComponent } from "./add-payment-step.component";
import { PriorityOfPaymentBatchDelete } from "./priority-of-payments-batch-delete.component";
import { DisplayOrderCellRenderer } from "../../tests/common/display-order-cell-renderer.component";
import { useUpdateOrderOrPriority } from "./hooks/update-order-or-priority.hook";
import {
  useNestedRefreshNeedReviewOnParentGrid,
  useRefreshNeedReviewOnChildGrid,
  useRefreshNeedReviewOnParentGrid,
} from "../../common/refresh-need-review.hook";

import { PopBulkEditFormDialog } from "./priority-of-payment-bulk-edit-form-dialog.component";
import { formatUtcToString } from "../../common/adjust-date-time-offset";
const waterfallGridSx: SxProps = {
  flex: "1 1 0px",
  minHeight: "20vh",
  height: "100%",
};

interface PriorityOfPaymentsGridProps {
  modelId?: string;
  selectedPortfolioId?: string;
  editButtonRef: React.RefObject<HTMLButtonElement>;
  refreshDetails?: () => void;
  onSelectionChanged?: (
    selectedRecord: PriorityOfPayment[] | null,
    groupId: string
  ) => void;
  selectedWaterfalls?: PriorityOfPayment[] | null;
  selectedModelId?: string;
  updateRefreshGrid?: (refreshGrid: () => void | null) => void;
  refreshGrid?: (() => void) | undefined;
  refreshAfterUpdate?: () => void | null;
  childValueRef?: MutableRefObject<string | null>;
  children?: ReactNode;
  titleComponent?: React.ReactElement<
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    any,
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    string | React.JSXElementConstructor<any>
  >;
  rowSelectionMode?: "singleRow" | "multiRow";
}

type PriorityOfPaymentGridActionContextType = {
  selectedModelstate: string | null;
  selectedWaterfalls?: PriorityOfPayment[] | null | undefined;
  refresh?: () => void;
  refreshGrid?: (() => void) | undefined;
  refreshAfterUpdate?: () => void | null;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  agGridApiRef?: MutableRefObject<GridApi<any> | null>;
  handleSelectionChange?: (
    selectedRecords: PriorityOfPayment[] | undefined
  ) => void;
  editButtonRef: React.RefObject<HTMLButtonElement>;
  priorityOfPaymentsDataSource: DataGridDataServiceSource;
  maxOrder: number;
};

const PriorityOfPaymentGridActionContext =
  createContext<PriorityOfPaymentGridActionContextType>({
    selectedModelstate: null,
    selectedWaterfalls: undefined,
    refreshGrid: undefined,
    refreshAfterUpdate: undefined,
    editButtonRef: React.createRef<HTMLButtonElement>(),
    refresh: undefined,
    agGridApiRef: undefined,
    handleSelectionChange: undefined,
    priorityOfPaymentsDataSource: {},
    maxOrder: 0,
  });

export const PriorityOfPaymentsGrid: FunctionComponent<
  PriorityOfPaymentsGridProps
> = ({
  onSelectionChanged,
  editButtonRef,
  selectedWaterfalls,
  selectedModelId,
  updateRefreshGrid,
  refreshGrid,
  refreshAfterUpdate,
  childValueRef,
  children: children,
  titleComponent,
  rowSelectionMode = "multiRow",
}) => {
  const { modelId, portfolioId } = useParams<AppRouteParams>();

  const finalModelId = modelId || selectedModelId;

  const [maxOrder, setMaxOrder] = useState<number>(0);

  const { sharedAppContextManager } = useStaticAppContext();
  const { state: selectedModelstate } = sharedAppContextManager.useContext<
    string | null
  >("app.selectedModelState");
  const agGridApiRef = useRef<GridApi | null>(null);

  const { childIdRef, updateChildValue } = useContext(AddTreeGridChildContext);

  const maxPriority = useCallback((data: PriorityOfPayment) => {
    const totalSteps: PriorityOfPayment[] = [];
    agGridApiRef.current?.forEachNode(
      (rowNode: IRowNode<PriorityOfPayment>) => {
        if (rowNode.data) {
          totalSteps.push(rowNode.data);
        }
      }
    );
    const paymentGroupStepId = data?.tree_data_path.includes("/")
      ? data?.id
      : null;
    const paymentGroupId = data?.tree_data_path.includes("/")
      ? data?.tree_data_path?.split("/")[0]
      : null;
    if (paymentGroupStepId && paymentGroupId) {
      const matchId = paymentGroupStepId.split("_")[0];
      const filteredPaymentGroupSteps = totalSteps.filter((grp) =>
        grp.id.startsWith(`${matchId}_`)
      );
      return filteredPaymentGroupSteps.length > 0
        ? filteredPaymentGroupSteps.length
        : 0;
    }
  }, []);

  const priorityOfPaymentsDataSource = useMemo<DataGridDataServiceSource>(
    () => ({
      url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${finalModelId}/waterfalls:view`,
    }),
    [portfolioId, finalModelId]
  );
  const [refreshToken, refresh] = useRefreshToken();

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const getRowId = useCallback((params: any) => {
    return params?.data?.id;
  }, []);

  useEffect(() => {
    if (updateRefreshGrid) updateRefreshGrid(refresh);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const { updatePopStep, updateOrderOrPriorityValue } =
    useUpdateOrderOrPriority({ modelId, portfolioId, agGridApiRef, refresh });

  const colDefOverrides: ColDefOverride[] = useMemo(
    () => [
      {
        field: "applicability_begin_date_description",
        colDef: {
          cellRenderer: (props: ICellRendererParams) => {
            return props.value
              ? formatUtcToString(
                  props.value?.toString()?.replace(/^"|"$/g, ""),
                  "DD MMM YYYY"
                )
              : null;
          },
        },
      },
      {
        field: "type_description",
        colDef: {
          filter: "agMultiColumnFilter",
        },
      },
      {
        field: "applicability_end_date_description",
        colDef: {
          cellRenderer: (props: ICellRendererParams) => {
            return props.value
              ? formatUtcToString(
                  props.value?.toString()?.replace(/^"|"$/g, ""),
                  "DD MMM YYYY"
                )
              : null;
          },
        },
      },
      {
        field: "applicability_criteria",
        colDef: {
          field: "applicability_criteria.description",
          headerName: "Applicability Criteria",
        },
      },
      {
        field: "priority",
        colDef: {
          field: "priority",
          editable: (params) =>
            params?.data?.priority && rowSelectionMode == "multiRow"
              ? true
              : false,
          cellEditor: NumericCellEditor,
          cellStyle: { "text-align": "center" },
          cellEditorParams: (params: { data: PriorityOfPayment }) => {
            const maxPriorityVal = maxPriority(params.data);
            return {
              // make "dataType" value available to cell editor
              dataType: "string",
              max: maxPriorityVal,
              min: 0,
            };
          },
          minWidth: 100,
          valueGetter: (params) =>
            params?.data?.priority != null
              ? Number(params.data.priority)
              : null,
          comparator: caseInsensitiveComparator,
          cellRenderer:
            rowSelectionMode == "multiRow"
              ? DisplayOrderCellRenderer
              : undefined,
          cellRendererParams: {
            suppressCount: true,
          },
          onCellValueChanged: (params) => {
            const newValue = params.newValue;
            const oldValue = params.oldValue;

            if (newValue !== oldValue) {
              updateOrderOrPriorityValue(params.data, null, newValue);
            }
          },
          headerClass: "ag-left-aligned-header",
        },
      },
    ],
    [maxPriority, updateOrderOrPriorityValue]
  );

  const onRowDragMove = async (event: RowDragEvent) => {
    const movingNode = event.node;
    const overNode = event.overNode;
    if (
      movingNode !== overNode &&
      movingNode?.data?.order &&
      overNode?.data?.order
    ) {
      updatePopStep(movingNode, overNode, "order");
    } else if (
      movingNode !== overNode &&
      (movingNode?.data?.order === null || movingNode?.data?.order === 0) &&
      movingNode?.data?.priority &&
      overNode?.data?.priority
    ) {
      const movingNodeParentId = movingNode?.data?.tree_data_path.includes("/")
        ? movingNode?.data?.tree_data_path?.split("/")[0]
        : null;
      const overNodeParentId = overNode?.data?.tree_data_path.includes("/")
        ? overNode?.data?.tree_data_path?.split("/")[0]
        : null;
      if (movingNodeParentId !== overNodeParentId) return;
      updatePopStep(movingNode, overNode, "priority");
    }
  };

  const onRowDataUpdated = useCallback(() => {
    const rowData: PriorityOfPayment[] = [];
    if (childIdRef.current || (childValueRef && childValueRef.current)) {
      const childNodeId =
        childIdRef.current ?? (childValueRef && childValueRef.current);
      if (childNodeId) {
        const childNode = agGridApiRef.current?.getRowNode(childNodeId);
        rowData.push(childNode?.data);
        childNode?.setSelected(true);
        handleSelectionChange(rowData);
        updateChildValue(null);
        if (childValueRef) childValueRef.current = null;
      }
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleSelectionChange = useCallback(
    (selectedRecords: PriorityOfPayment[] | undefined) => {
      const selectedRows: PriorityOfPayment[] | undefined =
        agGridApiRef.current?.getSelectedRows() || selectedRecords;
      if (selectedRows?.length) {
        const treePath = selectedRows[0]?.tree_data_path;
        const parentId = treePath.includes("/") ? treePath.split("/")[0] : null;
        const node = parentId
          ? agGridApiRef.current?.getRowNode(parentId)
          : agGridApiRef.current?.getRowNode(treePath);
        node?.setExpanded(true);
        onSelectionChanged !== undefined
          ? selectedRecords?.length && selectedRecords?.length > 0
            ? onSelectionChanged(selectedRecords, parentId ?? "")
            : onSelectionChanged(null, "")
          : null;
      } else {
        if (onSelectionChanged !== undefined) onSelectionChanged(null, "");
      }
    },
    [onSelectionChanged]
  );

  useRefreshNeedReviewOnChildGrid(agGridApiRef, "POPS", "POP");
  useNestedRefreshNeedReviewOnParentGrid("POP", "POPS", agGridApiRef);
  useRefreshNeedReviewOnParentGrid(finalModelId, "PSM", "POP", agGridApiRef);

  return (
    <Fragment>
      {isParameterValid(finalModelId) ? (
        <AsyncDataGridPanel
          sx={waterfallGridSx}
          dataSource={priorityOfPaymentsDataSource}
          refreshToken={refreshToken}
          colDefOverrides={colDefOverrides}
          onSelectionChanged={handleSelectionChange}
          titleComponent={titleComponent}
          gridPersistOptions={{
            key: "POP",
            enabled: true,
          }}
          agGridProps={{
            onGridReady: (event: GridReadyEvent) => {
              agGridApiRef.current = event.api;
            },
            onRowDataUpdated: onRowDataUpdated,
            onRowDragEnd: onRowDragMove,
            getRowId: getRowId,
            rowSelection: {
              mode: rowSelectionMode,
              enableClickSelection: true,
              checkboxes: rowSelectionMode == "multiRow",
              groupSelects: "self",
            },
            onFirstDataRendered: (event) => {
              const popData: PriorityOfPayment[] = [];
              event.api.forEachNode((node) => {
                popData.push(node.data as PriorityOfPayment);
              });
              if (popData.length > 0) {
                setMaxOrder(
                  Math.max(...popData.map((item) => Number(item.order)))
                );
              }
            },
            groupDefaultExpanded: 0,
            singleClickEdit: false,
            enableGroupEdit: true,
            autoGroupColumnDef: {
              rowDrag: rowSelectionMode === "multiRow",
              editable:
                rowSelectionMode === "multiRow"
                  ? (params) =>
                      params?.data?.order && Number(params?.data?.order) !== 0
                  : false,
              cellEditor: NumericCellEditor,
              cellEditorParams: {
                // make "dataType" value available to cell editor
                dataType: "string",
                max: getTotalSteps(agGridApiRef).length,
                min: 0,
              },
              headerName: "Order",
              field: "order",
              initialWidth: 130,
              cellStyle:
                rowSelectionMode === "multiRow"
                  ? {}
                  : { "text-align": "right" },
              cellRendererParams: {
                suppressCount: true,
                innerRenderer:
                  rowSelectionMode === "multiRow"
                    ? DisplayOrderCellRenderer
                    : undefined,
              },
              valueGetter: (params) =>
                params?.data?.order != null ? Number(params.data.order) : null,
              comparator: caseInsensitiveComparator,
              onCellValueChanged: (params) => {
                const newValue = params.newValue;
                const oldValue = params.oldValue;

                if (newValue !== oldValue) {
                  updateOrderOrPriorityValue(params.data, newValue, null);
                }
              },
            },
          }}
        >
          <PriorityOfPaymentGridActionContext.Provider
            value={{
              selectedWaterfalls: selectedWaterfalls,
              refresh: refresh,
              handleSelectionChange: handleSelectionChange,
              agGridApiRef: agGridApiRef,
              selectedModelstate: selectedModelstate,
              refreshGrid: refreshGrid,
              refreshAfterUpdate: refreshAfterUpdate,
              editButtonRef: editButtonRef,
              priorityOfPaymentsDataSource: priorityOfPaymentsDataSource,
              maxOrder: maxOrder,
            }}
          >
            {children}
          </PriorityOfPaymentGridActionContext.Provider>
        </AsyncDataGridPanel>
      ) : null}
    </Fragment>
  );
};

export const PriorityOfPaymentGridActions = () => {
  const {
    handleSelectionChange,
    refresh,
    refreshGrid,
    editButtonRef,
    refreshAfterUpdate,
    selectedWaterfalls,
    agGridApiRef,
    selectedModelstate,
    maxOrder,
    priorityOfPaymentsDataSource,
  } = useContext(PriorityOfPaymentGridActionContext);
  const iconButtonProps = useMemo<IconButtonProps>(() => {
    return selectedModelstate === "L" ? { disabled: true } : {};
  }, [selectedModelstate]);

  const iconButtonPropsForAddOrEdit = useMemo<IconButtonProps>(() => {
    return selectedModelstate === "L" ||
      (selectedWaterfalls && Number(selectedWaterfalls?.[0]?.order) === 0)
      ? { disabled: true }
      : {};
  }, [selectedModelstate, selectedWaterfalls]);

  const iconButtonPropsForDelete = useMemo<IconButtonProps>(() => {
    return selectedModelstate === "L" ||
      !selectedWaterfalls ||
      (selectedWaterfalls &&
        selectedWaterfalls[0]?.order === null &&
        selectedWaterfalls[0]?.priority === null)
      ? { disabled: true }
      : {};
  }, [selectedModelstate, selectedWaterfalls]);

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const handleUpdateUi = (agGridApi: GridApi<any>, ids: ActionTargetIds) => {
    const id = ids ? ids[0] : null;
    const childNode = agGridApi?.getRowNode(id);
    if (childNode) {
      const updatedRecord = { ...childNode.data };
      agGridApi?.applyTransaction({ remove: [childNode.data] });
      const transactionResult = agGridApi?.applyTransaction({
        add: [updatedRecord],
        addIndex: Number(updatedRecord.order) - 1,
      });
      agGridApi?.ensureIndexVisible(Number(updatedRecord.order) - 1);
      if (transactionResult?.add?.[0]) {
        agGridApi?.getRowNode(updatedRecord.id)?.setSelected(true, true);
      }
    }
  };

  const populateSuccessMessage = usePopulateSuccessMessage();
  const handleOnSubmitComplete = (message: string) => {
    populateSuccessMessage(message);
  };

  return (
    <>
      <DataGridQuickSearch></DataGridQuickSearch>
      {selectedWaterfalls === null || selectedWaterfalls === undefined ? (
        <DataGridActionAdd
          iconButtonProps={iconButtonPropsForAddOrEdit}
          dialog={<PriorityOfPaymentsFormDialog maxOrder={maxOrder} />}
          onUpdateUi={(data, agGridApi, ids) => {
            handleUpdateUi(agGridApi, ids);
            refreshGrid?.();
          }}
        ></DataGridActionAdd>
      ) : (
        <AddPaymentStepComponent
          AddEditPaymentDialog={PaymentStepFormDialog}
          onRefresh={refreshGrid}
          onGroupUpdate={refreshAfterUpdate}
          selectedWaterfalls={selectedWaterfalls}
          disabled={
            selectedWaterfalls.length > 1 ||
            selectedWaterfalls[0]?.order === null ||
            selectedWaterfalls[0]?.order === 0 ||
            iconButtonPropsForAddOrEdit.disabled
          }
        ></AddPaymentStepComponent>
      )}
      <DataGridActionEdit
        dialog={<PriorityOfPaymentsFormDialog maxOrder={maxOrder} />}
        onUpdateUi={(data, agGridApi, ids) => {
          handleUpdateUi(agGridApi, ids);
          refreshGrid?.();
        }}
        iconButtonProps={{ ...iconButtonPropsForAddOrEdit, ref: editButtonRef }}
      ></DataGridActionEdit>

      <PriorityOfPaymentBatchDelete
        iconButtonProps={iconButtonPropsForDelete}
