import { AsyncFormDialog } from "@textile/biz-components";

import {
  useTheme,
  useMediaQuery,
  Alert,
  Button,
  Typography,
  DialogActions,
  DialogContent,
  Divider,
  Box,
} from "@textile/mui";
import { Dialog, DialogTitle, WarningIcon } from "@textile/common";
import { getDialogResizePaperPropsSx } from "@solvasam/bizcomponents";

interface BulkEditFormDialogProps<T> {
  datasource: unknown;
  onBeforePopulate: (data: Partial<T>) => Promise<Partial<T>>;
  handleOnBeforeSave: () => Promise<unknown>;
  onConfirmContinue: () => void;
  onCancel: () => void;
  showConfirmation: boolean;
  defaultData: Partial<T>;
  children: React.ReactElement;
}

export const BulkEditFormDialog = <T,>({
  datasource,
  onBeforePopulate,
  handleOnBeforeSave,
  onConfirmContinue,
  onCancel,
  showConfirmation,
  defaultData,
  children,
}: BulkEditFormDialogProps<T>) => {
  const theme = useTheme();
  const fullScreen = useMediaQuery(theme.breakpoints.down("md"));
  return (
    <AsyncFormDialog
      dataSource={datasource}
      title="Bulk Edit"
      fullScreen={fullScreen}
      enableFullScreenToggle={true}
      fullWidth
      submitButtonLabel="Save"
      onBeforePopulate={onBeforePopulate}
      onBeforeSave={handleOnBeforeSave}
      draggable={true}
      PaperProps={{ sx: getDialogResizePaperPropsSx("lg") }}
      defaultData={defaultData}
    >
      <Alert variant="outlined" severity="info">
        Please note that the double quotes in text fields will be changed to
        single quotes.
      </Alert>
      {children}
      {/****Warning dialog *******/}
      <Dialog
        onClose={onCancel}
        open={showConfirmation}
        fullWidth={true}
        PaperProps={{ sx: getDialogResizePaperPropsSx("720px") }}
        draggable={true}
      >
        <DialogTitle
          sx={{
            background: "none",
            display: "flex",
            gap: "0.5rem",
          }}
        >
          <Box sx={{ display: "flex", alignItems: "center", gap: 0.5 }}>
            <WarningIcon
              sx={{
                color: theme.palette.warning.dark,
                mt: 1,
              }}
              size={20}
            />
            <Typography
              variant="subtitle1"
              sx={{
                fontWeight: 600,
                color: theme.palette.common.black,
                marginTop: 1,
              }}
            >
              This action cannot be undone!
            </Typography>
          </Box>
        </DialogTitle>
        <DialogContent>
          <Box>
            <Typography variant="body2">
              Are you sure you want to go ahead with the update?
            </Typography>
          </Box>
        </DialogContent>
        <Divider></Divider>
        <DialogActions sx={{ display: "flex", gap: 2 }}>
          <Button variant="outlined" onClick={onCancel}>
            Cancel
          </Button>
          <Button variant="contained" onClick={onConfirmContinue}>
            Update
          </Button>
        </DialogActions>
      </Dialog>
    </AsyncFormDialog>
  );
};

import { CustomDataGrid, FormValueSelector } from "@solvasam/bizcomponents";
import { ICellRendererParams } from "@textile/ag-grid";
import { FormFieldGroup, FormTextField } from "@textile/biz-components";

import { Stack, Paper, Button, Box, Typography, useTheme } from "@textile/mui";
import { SyntheticEvent } from "react";
import { useParams } from "react-router-dom";

import { AppRouteParams } from "../screen.types";
import { useBulkEditContext } from "./bulk-edit-context.component";
import { FormFieldConfig } from "./common-types";
import { CalendarIcon } from "@textile/common";

export const CellRenderer = (params: ICellRendererParams) => {
  const theme = useTheme();
  const showCalendar =
    params.colDef?.field === "begin_date_description" ||
    params.colDef?.field === "end_date_description";
  return (
    <Box
      sx={{
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        borderRadius: "4px",
        border: `1px solid ${theme.palette.grey[400]}`,
        px: 1,
        "&:hover": {
          borderColor: theme.palette.common.black,
        },
        height: "100%",
      }}
    >
      <Typography
        variant="inherit"
        noWrap
        sx={{
          overflow: "hidden",
          textOverflow: "ellipsis",
        }}
      >
        {params.valueFormatted}
      </Typography>
      {showCalendar && <CalendarIcon size={16} />}
    </Box>
  );
};

export const BulkEditFormComponent = <T,>({
  textfields,
  datefields,
  onBeginDateFieldChange,
  onEndDateFieldChange,
  onHandleUpdate,
  applicabilityBeginType,
  applicabilityEndType,
}: {
  textfields: FormFieldConfig[];
  datefields: FormFieldConfig[];
  onBeginDateFieldChange?: (_event: SyntheticEvent, value: unknown) => void;
  onEndDateFieldChange?: (_event: SyntheticEvent, value: unknown) => void;
  onHandleUpdate?: () => void;
  applicabilityBeginType: string;
  applicabilityEndType: string;
}) => {
  const { portfolioId, modelId } = useParams<AppRouteParams>();
  const { selectedData, colDefOverrides, gridMeta, gridApiRef } =
    useBulkEditContext<T>();
  const isLoading = !selectedData || selectedData.length === 0;

  return (
    <Stack gap={2.5}>
      <FormFieldGroup>
        {textfields?.map(({ name, label, type, helperText }) => {
          switch (type) {
            case "number":
              return (
                <FormTextField
                  key={name}
                  label={label}
                  fieldName={name}
                  helperText={helperText ? helperText : undefined}
                  type={type}
                  variant="outlined"
                  InputProps={{
                    inputProps: {
                      min: 1,
                      max: 1000,
                    },
                  }}
                  sx={{
                    flex: "1 0 0px",
                    textOverflow: "ellipsis",
                    whiteSpace: "nowrap",
                  }}
                ></FormTextField>
              );
            case "text":
              return (
                <FormTextField
                  key={name}
                  label={label}
                  fieldName={name}
                  variant="outlined"
                  sx={{ flex: "3 0 0px" }}
                ></FormTextField>
              );
            default:
              return null;
          }
        })}
      </FormFieldGroup>
      <FormFieldGroup>
        <Stack gap={5} sx={{ display: "flex", flexGrow: 1 }} direction={"row"}>
          <Stack
            direction={"row"}
            sx={{ display: "flex", flexGrow: 1 }}
            gap={2.5}
          >
            {datefields?.map(({ name, label, dataType }) => {
              switch (dataType) {
                case "DATE":
                  return (
                    <FormValueSelector
                      key={name}
                      valFieldId={`${name}_date`}
                      refFieldId={`${name}_date_reference`}
                      dataType={dataType}
                      textFieldProps={{ label: label }}
                      valueTypeId={`${name}_type`}
                      valueType={
                        label === "Applicability Begin Date"
                          ? applicabilityBeginType ?? "val"
                          : applicabilityEndType ?? "val"
                      }
                      onReferenceFieldChange={
                        label === "Applicability Begin Date"
                          ? onBeginDateFieldChange
                          : onEndDateFieldChange
                      }
                    ></FormValueSelector>
                  );
                default:
                  return null;
              }
            })}
          </Stack>
          <Button
            variant="outlined"
            onClick={() => {
              onHandleUpdate?.();
            }}
          >
            Update Selected Rows
          </Button>
        </Stack>
      </FormFieldGroup>

      {portfolioId && modelId ? (
        <Stack sx={{ flexGrow: 1, height: "100%", width: "100%" }}>
          <Paper sx={{ flex: "1 1 0px", minHeight: "25vmax", mb: 2 }}>
            <CustomDataGrid
              meta={gridMeta}
              data={{ rowData: selectedData ? selectedData : [] }}
              rowSelectionMode="multi"
              colDefOverrides={colDefOverrides}
              agGridProps={{
                loading: isLoading,
                onGridReady: (e) => {
                  gridApiRef.current = e.api;
                },
                getRowHeight: function () {
                  return 26;
                },
                singleClickEdit: true,
              }}
              gridPersistOptions={{
                key: "BULK-EDIT-FORM",
                enabled: true,
              }}
            ></CustomDataGrid>
          </Paper>
        </Stack>
      ) : null}
    </Stack>
  );
};

