import {
  AddExpressionMenu,
  CopyExpression,
  DeleteExpression,
  FormExpressionBuilder,
  FormFormulaEditor,
  FormValueSelector,
  PasteMenu,
  useDdxValues,
  FormCustomDatePicker,
} from "@solvasam/bizcomponents";
import {
  ColDefOverride,
  DataGridActionRefresh,
  DataGridField,
  DataGridMeta,
  DataGridQuickSearch,
  DropdownTransferList,
  FormAutocomplete,
  FormFieldGroup,
  FormSelect,
  FormTextField,
  useField,
} from "@textile/biz-components";
import { Stack, TextField, TextFieldProps } from "@textile/mui";
import {
  Fragment,
  FunctionComponent,
  useCallback,
  useEffect,
  useState,
} from "react";

import { DataDictionaryFieldsGrid } from ".";
import { CodePair } from "./common-types";
import { CalculationBlockParameter } from "../calculations/calculations.types";

export const dataTypeDictionary: Record<string, string> = {
  M: "CURRENCY",
  D: "DATE",
  N: "NUMERIC",
  P: "NUMERIC",
  V: "VARIANT",
  T: "TABLE",
  B: "BOOLEAN",
};

export const assignValueFieldName = (
  parameterValueType: string,
  dataType: string
) => {
  switch (parameterValueType) {
    case "E":
      return "applicability_value";
    case "R":
      return "numeric_value";
    case "B":
      return "boolean_value";
    case "C":
      return "formula_value";
    case "L":
      return "string_value";
    case "F":
      return "field_name_value";
    case "T":
      return "table_value";
    case "M":
      switch (dataType) {
        case "C":
        case "N":
          return "string_value";
        default:
          return "string_value";
      }
    case "P":
      switch (dataType) {
        case "C":
        case "M":
          return "string_value";
        case "N":
          return "numeric_value";
        default:
          return "string_value";
      }
    case "V":
      switch (dataType) {
        case "C":
          return "string_value";
        case "N":
        case "P":
          return "numeric_value";
        case "D":
          return "date_time_value";
        default:
          return "string_value";
      }
    default:
      return "string_value";
  }
};
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export const stringifyJSONObject = (tableValueObject: Record<string, any>) => {
  return tableValueObject.map(JSON.stringify);
};

export const getSchema = (dataSource: string) => {
  const gridFields: DataGridField[] = [];
  const columns = dataSource.split(";");
  columns.forEach((column: string) => {
    const field = {
      name: column.replaceAll(".", "").replaceAll(" ", ""),
      dataType: column === "Effective Date" ? "date" : "string",
      header: column.replace(/\w/, (firstLetter: string) =>
        firstLetter.toUpperCase()
      ),
      visible: true,
      wrapHeaderText: true,
    };
    gridFields.push(field);
  });

  return {
    idField: "id",
    gridFields: [
      ...gridFields,
      {
        name: "id",
        dataType: "string",
        header: "Id",
        visible: false,
        filterable: true,
        sortable: true,
      },
    ],
  };
};

const convertDataType = (dataType: string) => {
  return dataTypeDictionary[dataType] != null
    ? dataTypeDictionary[dataType]
    : "TEXT";
};

interface ParameterValueFormComponentProps {
  mode?: "add" | "edit";
}
const colDefOverrides: ColDefOverride[] = [
  {
    field: "aggregation_level_description",

    colDef: { filter: "agSetColumnFilter" },
  },
  {
    field: "category_description",

    colDef: { filter: "agSetColumnFilter" },
  },
  {
    field: "data_type_description",

    colDef: { filter: "agSetColumnFilter" },
  },
  {
    field: "lookup_type_description",

    colDef: { filter: "agSetColumnFilter" },
  },
  {
    field: "field_name",

    colDef: { filter: "agTextColumnFilter" },
  },
  {
    field: "currency_type_description",

    colDef: { filter: "agSetColumnFilter" },
  },
];

const FieldComponent = () => {
  const [, , fieldHelpers] = useField("field_name_value");
  const [{ value: description }, , stringValueHelpers] =
    useField("description");
  const [fieldNameValue, setFieldNameValue] = useState("");

  useEffect(() => {
    if (description !== undefined) {
      setFieldNameValue(description.replace(/^\[|\]$/g, ""));
    }
  }, [description]);
  const handleOnDdfSelect = useCallback(
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (selectedRecord: any[]) => {
      if (selectedRecord?.length) {
        fieldHelpers.setValue(selectedRecord[0]?.code);
        stringValueHelpers.setValue(selectedRecord[0]?.display_name);
      }
    },
    [fieldHelpers, stringValueHelpers]
  );
  return (
    <Fragment>
      <FormFieldGroup>
        <TextField
          label="Selected Parameter"
          variant="outlined"
          value={fieldNameValue}
          disabled
        ></TextField>
      </FormFieldGroup>
      <DataDictionaryFieldsGrid
        onSelectionChanged={handleOnDdfSelect}
        rowSelectionMode="single"
        colDefOverrides={colDefOverrides}
      >
        <DataGridQuickSearch></DataGridQuickSearch>
        <DataGridActionRefresh></DataGridActionRefresh>
      </DataDictionaryFieldsGrid>
    </Fragment>
  );
};

export const ParameterValueFormComponent: FunctionComponent<
  ParameterValueFormComponentProps
> = ({ mode }) => {
  const [{ value: dataSourceValues }] =
    useField<CodePair[]>("data_source_values");
  const [{ value: valueType }] = useField<string>("value_type");
  const [{ value: dataType }] = useField<string>("data_type");
  const [{ value: paramType }] = useField("type");
  const [{ value: purpose }] = useField("purpose");
  const [{ value: parameterValueType }] = useField("parameter_value_type");
  const [{ value: lookupCodes }] = useField("lookup_codes");
  const [{ value: predefinedTable }] = useField("predefined_table");
  const [{ value: dataSource }] = useField("data_source");
  const [{ value: valueRequired }] = useField("value_required");

  const fieldValueName = assignValueFieldName(
    parameterValueType,
    dataType
  ) as string;
  let valDataType = convertDataType(dataType);
  let tableValueSchema: DataGridMeta = { idField: "id", gridFields: [] };
  const ddxData = useDdxValues(
    purpose ?? parameterValueType === "C"
      ? "FIELD_FORMULA"
      : "FILTER_EXPRESSION"
  );

  if (parameterValueType === "B") {
    valDataType = "BOOLEAN";
  }

  if (parameterValueType === "T") {
    valDataType = "TABLE";
    tableValueSchema = getSchema(dataSource);
  }

  const dataSourceTextFieldProps: TextFieldProps = {
    label: "Value",
    variant: "outlined",
    required: valueRequired,
  };
  return (
    <Fragment>
      <FormFieldGroup>
        <FormTextField<CalculationBlockParameter>
          fieldName="parameter_name"
          label="Name"
          variant="outlined"
          disabled
        ></FormTextField>
      </FormFieldGroup>
      <FormFieldGroup>
        <FormTextField<CalculationBlockParameter>
          fieldName="parameter_description"
          label="Description"
          variant="outlined"
          disabled
        ></FormTextField>
      </FormFieldGroup>
      {(() => {
        switch (parameterValueType) {
          case "C":
            return (
              <FormFieldGroup sx={{ flexDirection: "column" }}>
                <FormFormulaEditor<CalculationBlockParameter>
                  id={fieldValueName}
                  errors={[]}
                  sx={{ flexDirection: "column" }}
                  ddxData={ddxData}
                  purpose="FIELD_FORMULA"
                ></FormFormulaEditor>
              </FormFieldGroup>
            );
          case "E":
            return (
              <Fragment>
                <FormExpressionBuilder id={fieldValueName} ddxProps={ddxData}>
                  <AddExpressionMenu />
                  <DeleteExpression />
                  <CopyExpression />
                  <PasteMenu />
                </FormExpressionBuilder>
              </Fragment>
            );
          case "L":
            return (
              <FormFieldGroup>
                <FormAutocomplete
                  fieldName={fieldValueName}
                  valueField="code"
                  labelField="description"
                  options={lookupCodes}
                  textFieldProps={dataSourceTextFieldProps}
                ></FormAutocomplete>
              </FormFieldGroup>
            );
          case "P":
          case "R":
            return (
              <FormFieldGroup>
                <FormAutocomplete
                  fieldName={fieldValueName}
                  valueField={"code"}
                  labelField={"description"}
                  options={dataSourceValues ?? []}
                  textFieldProps={dataSourceTextFieldProps}
                ></FormAutocomplete>
              </FormFieldGroup>
            );
          case "F":
            return <FieldComponent />;
          case "M":
            return (
              <FormFieldGroup>
                <Stack sx={{ flex: "1 1 0px" }}>
                  <FormSelect
                    fieldName={fieldValueName}
                    options={dataSourceValues ?? []}
                    valueField={"code"}
                    labelField={"description"}
                    label={dataSourceTextFieldProps.label}
                    required={dataSourceTextFieldProps.required}
                    variant={dataSourceTextFieldProps.variant}
                    multiple
                  >
                    <DropdownTransferList autoFocusSearch />
                  </FormSelect>
                </Stack>
              </FormFieldGroup>
            );
          case "V":
          case "B":
          case "T":
            return (
              <FormFieldGroup>
                <FormValueSelector
                  valFieldId={fieldValueName}
                  refFieldId="reference_value"
                  textFieldProps={{ label: "Value" }}
                  dataType={valDataType}
                  lockValueType={paramType === "OUTP"}
                  valueType={valueType?.toLowerCase()}
                  tableValueSchema={tableValueSchema ?? {}}
                  isCalculated={
                    paramType === "OUTP" || predefinedTable ? true : undefined
                  }
                  predefinedTable={predefinedTable}
                  parameterValueType={parameterValueType}
                ></FormValueSelector>
              </FormFieldGroup>
            );
          default:
            return (
              <FormFieldGroup>
                <FormTextField
                  fieldName="description"
                  label="Selected Parameter"
                  variant="outlined"
                ></FormTextField>
              </FormFieldGroup>
            );
        }
      })()}
      {mode === "add" ? (
        <FormCustomDatePicker
          fieldName="effective_date"
          label="Effective Date"
          textFieldProps={{
            variant: "outlined",
          }}
        />
      ) : null}
      <FormFieldGroup>
        <FormTextField
          fieldName="comments"
          label="Comments"
          variant="outlined"
          multiline
        ></FormTextField>
      </FormFieldGroup>
    </Fragment>
  );
};

import { GridApi, IRowNode, ValueFormatterParams } from "@textile/ag-grid";

import {
  useState,
