  test?: Test;
};

export const ComplianceTestsBulkEditFormDialog = () => {
  const { portfolioId, modelId } = useParams<AppRouteParams>();
  const gridApiRef = useRef<GridApi<Test> | null>();
  const [showConfirmation, setShowConfirmation] = useState(false);
  const { open } = useActionDialog();
  const [selectedComplianceTests, setSelectedComplianceTests] = useState<
    Test[]
  >([]);
  const axiosFactory = useAxiosFactory();
  const messageAnnouncer = useMessageAnnouncer();
  const resolveRef: MutableRefObject<((value: unknown) => void) | null> =
    useRef(null);
  const bulkEditRequestRef = useRef<{
    requests: ComplianceTestsBulkEdit[];
  }>({
    requests: [],
  });
  const ComplianceTestBulkEditDataSource = useMemo(
    () => ({
      idField: "id",
      mode: "add",
      save: {
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/tests:batchUpdate`,
        method: "patch",
      },
    }),
    [portfolioId, modelId]
  );

  const onBeforePopulate = useCallback(async (data: Partial<Test>) => {
    return {
      ...(data ?? {}),
      applicability_begin_type: "val",
      applicability_end_type: "val",
    };
  }, []);

  const handleOnBeforeSave = useCallback(async () => {
    bulkEditRequestRef.current = {
      requests: [] as ComplianceTestsBulkEdit[],
    };

    gridApiRef.current?.stopEditing();
    gridApiRef?.current?.forEachNode((node: IRowNode<Test>) => {
      if (node.data && node?.isSelected()) {
        if (
          typeof node.data.begin_date_description !== "string" &&
          node.data?.begin_date_description !==
            node.data?.applicability_begin_date_reference_description &&
          node.data?.begin_date_description !==
            node.data?.applicability_begin_date
        ) {
          node.data.applicability_begin_date =
            node.data?.begin_date_description;
        }
        if (
          typeof node.data.end_date_description !== "string" &&
          node.data?.end_date_description !==
            node.data?.applicability_end_date_reference_description &&
          node.data?.end_date_description !== node.data?.applicability_end_date
        ) {
          node.data.applicability_end_date = node.data?.end_date_description;
        }

        bulkEditRequestRef.current.requests.push({
          test: node.data,
        });
      }
    });
    return new Promise((resolve) => {
      setShowConfirmation(true);
      resolveRef.current = resolve;
    });
  }, []);

  const onConfirmContinue = () => {
    setShowConfirmation(false);
    resolveRef.current?.(bulkEditRequestRef.current);
  };

  const onCancel = () => {
    setShowConfirmation(false);
    resolveRef.current?.(false);
  };

  useEffect(() => {
    const abortController = new AbortController();
    const loadComplianceTests = async () => {
      try {
        const axios = await axiosFactory.createAxiosInstance();
        const { data } = await axios.get<{ tests: Test[] }>(
          `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/tests`,
          {
            signal: abortController.signal,
          }
        );
        setSelectedComplianceTests(data.tests);
      } catch (error) {
        messageAnnouncer.error(`Failed to load Compliance Tests: ${error}`);
      }
    };
    if (open && modelId && portfolioId) {
      loadComplianceTests();
    }
    return () => abortController.abort();
  }, [axiosFactory, messageAnnouncer, portfolioId, modelId, open]);

  useEffect(() => {
    return () => {
      gridApiRef.current = null;
      setSelectedComplianceTests([]);
    };
  }, [gridApiRef]);

  return (
    <BulkEditProvider<Test>
      selectedData={selectedComplianceTests}
      gridMeta={complianceTestsMeta}
      colDefOverrides={colDefOverrides}
      gridApiRef={gridApiRef}
    >
      <BulkEditFormDialog
        datasource={ComplianceTestBulkEditDataSource}
        onBeforePopulate={onBeforePopulate}
        handleOnBeforeSave={handleOnBeforeSave}
        showConfirmation={showConfirmation}
        onConfirmContinue={onConfirmContinue}
        onCancel={onCancel}
        defaultData={{
          applicability_begin_date: null,
          applicability_end_date: null,
          applicability_end_date_reference: null,
          applicability_begin_date_reference: null,
          indenture_reference: "",
          report_reference: "",
        }}
      >
        <ComplianceTestsBulkEditFormComponent />
      </BulkEditFormDialog>
    </BulkEditProvider>
  );
};

