import { PaymentStepFormComponent } from "./payment-step-form.component";
import { usePopulateSuccessMessage } from "../../common/helpers";
import {
  assignValueFieldName,
  DdxDataContext,
  hydrateParameterBeforePopulate,
  hydrateParameterBeforeSave,
  parseTableParameterValue,
  stringifyJSONObject,
} from "../../common";
import {
  TemplateParameter,
  TemplateParametersResponse,
} from "../../templates/templates.types";
import { ParameterValueForBulkEditFormComponent } from "../../common/parameter-value-for-bulk-edit-form.component";

export interface PaymentStepAddEditFormDialogProps
  extends Partial<AsyncFormDialogProps> {
  modelId?: string;
  portfolioId?: string;

  waterfallId: string;
  waterfallStepId?: string;
  waterfallStepDetails?: PaymentStep;
  totalRecords?: number | undefined;
  gridApi?: GridApi | null;
}

const payment_ref_id = "payment_ref";

export const PaymentStepFormDialog: FunctionComponent<
  PaymentStepAddEditFormDialogProps
> = ({
  modelId,
  portfolioId,
  waterfallId,
  waterfallStepId,
  waterfallStepDetails,
  totalRecords,
  gridApi,
  ...props
}) => {
  const theme = useTheme();
  const fullScreen = useMediaQuery(theme.breakpoints.down("md"));
  const actionCode = useDialogActionCode();
  const mode = actionCode === "edit" ? "edit" : "add";
  const { open } = useActionDialog();
  const ddxDataForFieldFormula = useDdxValues("FIELD_FORMULA");
  const ddxDataForFilterExpression = useDdxValues("FILTER_EXPRESSION");
  const populateSuccessMessage = usePopulateSuccessMessage();

  const defaultData = {
    template_id: "",
    reference_waterfall_id: "",
    description: "",
    document_reference: "",
    report_reference: "",
    effective_period_begin_date: null,
    effective_period_begin_date_reference: "",
    effective_period_end_date: null,
    effective_period_end_date_reference: "",
    comments: "",
    order:
      (gridApi?.getDisplayedRowCount() as number) ??
      (totalRecords ? totalRecords : 1),
  };

  const [selectedReferenceSteps, setSelectedReferenceSteps] = useState<
    PaymentStep[]
  >([]);

  const [selectedTemplateParameters, setSelectedTemplateParameters] =
    useState<TemplateParametersResponse | null>(null);

  const [preSelectedStepsId, setPreSelectedStepsId] = useState<string[]>();
  const PaymentStepsFormSource = useMemo<FormDataServiceSource>(
    () => ({
      idField: "id",
      mode: mode,
      get: {
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/waterfalls/${waterfallId}/steps`,
      },
      save: {
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/waterfalls/${waterfallId}/steps`,
        method: mode === "add" ? "post" : "patch",
      },
    }),
    [portfolioId, mode, modelId, waterfallId]
  );

  const onBeforeSavePaymentStepDetails = async (
    data: Partial<PaymentStep> & {
      effective_period_begin_type?: string;
      effective_period_end_type?: string;
      parameters?: StepParameter[] | null;
    }
  ) => {
    const isRef = data.template_id === payment_ref_id;
    if (isRef) {
      if (selectedReferenceSteps?.length === 0) return false;
    }
    const getReferenceAndValueType = (
      paramId: string,
      paramValueType: string
    ) => {
      if (
        ["V", "B", "T"].includes(paramValueType?.toUpperCase() ?? "") &&
        data[paramId + "_value_type"] &&
        data[paramId + "_value_type"].toUpperCase() === "REF" &&
        data[paramId + "_reference_value"] !== undefined
      ) {
        return {
          refValue: data[paramId + "_reference_value"],
          valType: data[paramId + "_value_type"]?.toUpperCase(),
        };
      }
      return null;
    };

    const getValueType = (paramId: string, paramValueType: string) => {
      if (
        ["V", "B", "T"].includes(paramValueType?.toUpperCase() ?? "") &&
        data[paramId + "_value_type"] &&
        data[paramId + "_value_type"].toUpperCase() === "VAL"
      ) {
        return data[paramId + "_value_type"]?.toUpperCase();
      }
    };

    const hydrateParameter = (param: StepParameter) => {
      hydrateParameterBeforeSave(
        param,
        param.data_source_values ?? [],
        param.lookup_codes ?? []
      );
      param = {
        ...param,
        lookup_codes: [],
        data_source_values: [],
        value_type: param.value_type
          ? param.value_type.toUpperCase()
          : param.value_type,
        table_value: stringifyJSONObject(param?.table_value ?? []),
        boolean_value: param?.boolean_value ?? null,
        numeric_value: param?.numeric_value ?? null,
        string_value: param?.string_value ?? null,
        reference_value: param?.reference_value ?? null,
      };
    };

    const keysToDelete: string[] = [];
    if (mode === "add") {
      const parameters: StepParameter[] | undefined =
        selectedTemplateParameters?.template_parameters?.map((tempParamter) => {
          const fieldName = assignValueFieldName(
            tempParamter.value_type ?? "",
            tempParamter.data_type ?? ""
          );

          const reference_value = getReferenceAndValueType(
            tempParamter.id,
            tempParamter?.value_type
          )?.refValue;

          const value_type =
            getReferenceAndValueType(tempParamter.id, tempParamter?.value_type)
              ?.valType ??
            getValueType(tempParamter.id, tempParamter?.value_type);

          const param: StepParameter = {
            id: tempParamter.id,
            parameter_value_type: tempParamter.value_type,
            data_type: tempParamter.data_type,
            [fieldName]: data[tempParamter.id] ?? null,
            reference_value: reference_value,
            value_type: value_type ?? "VAL",
            template_parameter_id: tempParamter.id,
            formula_value: {
              ddx: null,
              // eslint-disable-next-line @typescript-eslint/no-explicit-any
            } as any,
            applicability_value: {
              ddx: null,
              // eslint-disable-next-line @typescript-eslint/no-explicit-any
            } as any,
            value: tempParamter.value,
            parameter_name: tempParamter.parameter_name,
            parameter_description: tempParamter.description,
            type: tempParamter.type,
            value_required: tempParamter.value_required,
            lookup_codes: tempParamter.lookup_codes,
            data_source_values: tempParamter.data_source_values,
          };
          hydrateParameter(param);
          keysToDelete.push(param.id);
          keysToDelete.push(tempParamter.id);
          keysToDelete.push(tempParamter.id + "_value_type");
          keysToDelete.push(tempParamter.id + "_reference_value");

          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          if (param.id) delete (param as any).id;
          return param;
        });

      data.parameters = parameters && [...parameters];
    } else if (mode === "edit") {
      data?.parameters?.forEach((param) => {
        const fieldName = assignValueFieldName(
          param.parameter_value_type ?? "",
          param.data_type ?? ""
        );
        const value = data[param.id] ?? null;
        param[fieldName] = value;
        const selectedValueType =
          data[param.id + "_value_type"]?.toUpperCase() ?? "VAL";

        if (selectedValueType === "REF") {
          const ref = getReferenceAndValueType(
            param.id,
            param?.parameter_value_type ?? ""
          );
          param.reference_value = ref?.refValue ?? null;
          param.value_type = ref?.valType ?? "REF";
        } else {
          param.reference_value = null;
          param.value_type = selectedValueType;
        }

        if (param.parameter_value_type === "C" && !param.formula_value) {
          param.formula_value = {
            ddx: null,
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
          } as any;
        }

        if (param.parameter_value_type === "E" && !param.applicability_value) {
          param.applicability_value = {
            ddx: null,
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
          } as any;
        }

        hydrateParameter(param);
        keysToDelete.push(param.id);

        keysToDelete.push(param.id + "_value_type");
        keysToDelete.push(param.id + "_reference_value");
      });
    }

    const updatedData: Partial<PaymentStep> & {
      effective_period_begin_type?: string;
      effective_period_end_type?: string;
      parameters?: StepParameter[] | null;
    } = {
      ...data,
      effective_period_begin_date_reference:
        data.effective_period_begin_type === "ref"
          ? data.effective_period_begin_date_reference ?? null
          : null,
      effective_period_end_date_reference:
        data.effective_period_end_type === "ref"
          ? data.effective_period_end_date_reference ?? null
          : null,
      effective_period_begin_date:
        data.effective_period_begin_type !== "ref"
          ? data.effective_period_begin_date ?? null
          : null,
      effective_period_end_date:
        data.effective_period_end_type !== "ref"
          ? data.effective_period_end_date ?? null
          : null,
      effective_period_begin_type: undefined,
      effective_period_end_type: undefined,
      reference_steps: isRef
        ? selectedReferenceSteps?.map((step) => {
            return step.id;
          })
        : [],
      applicability_criteria: data?.applicability_criteria ?? {
        boolean_value: null,
        reference_value: null,
        description: null,
      },
      template_id: isRef ? null : data.template_id,
      etag: data.etag,
    };
    keysToDelete.forEach((key) => {
      if (updatedData.hasOwnProperty(key)) {
        delete updatedData[key];
      }
    });
    return updatedData;
  };

  const handleOnBeforePopulate = useCallback(
    async (data: Partial<PaymentStep>) => {
      if (data?.reference_steps && data?.reference_steps?.length > 0) {
        setPreSelectedStepsId(data.reference_steps);
      }
      if (mode === "edit" && waterfallStepDetails) {
        waterfallStepDetails.parameters &&
          waterfallStepDetails.parameters.forEach((param) =>
            hydrateParameterBeforePopulate(param)
          );

        const parameterObject =
          waterfallStepDetails &&
          waterfallStepDetails.parameters &&
          waterfallStepDetails?.parameters.reduce((acc, parameter) => {
            const tableValue = parameter?.table_value
              ? parseTableParameterValue(parameter?.table_value as string[])
              : [];

            const fieldName = assignValueFieldName(
              parameter.parameter_value_type ?? "",
              parameter.data_type ?? ""
            );
            const value =
              fieldName === "table_value"
                ? tableValue
                : parameter[fieldName] ?? null;

            if (
              ["V", "B", "T"].includes(
                parameter?.parameter_value_type?.toUpperCase() ?? ""
              ) &&
              parameter.value_type?.toUpperCase() === "REF"
            ) {
              acc[parameter.id + "_reference_value"] =
                parameter.reference_value;
              acc[parameter.id + "_value_type"] = parameter.value_type;
            }
            acc[`${parameter.id}`] = value;
            return acc;
          }, {} as { [key: string]: string | number | boolean | string[] | ModelExpression | null | undefined });

        return {
          ...data,
          effective_period_begin_type:
            data.effective_period_begin_date_reference ? "ref" : "val",
          effective_period_end_type: data.effective_period_end_date_reference
            ? "ref"
            : "val",
          template_id:
            data.reference_waterfall_id != null &&
            data.reference_waterfall_id !== ""
              ? payment_ref_id
              : data.template_id,
          ...parameterObject,
        };
      }
      return { ...data };
    },
    [mode, waterfallStepDetails]
  );

  const handleOnSubmitComplete = useCallback(() => {
    populateSuccessMessage(
      `Payment has been ${mode === "edit" ? "updated." : "added."}`
    );
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleOnClose = useCallback(() => {
    setSelectedTemplateParameters(null);
  }, []);

  return (
    open && (
      <DdxDataContext.Provider
        value={{
          ddxDataForFieldFormula: ddxDataForFieldFormula,
          ddxDataForFilterExpression: ddxDataForFilterExpression,
        }}
      >
        <AsyncFormDialog
          {...props}
          title={`${mode === "add" ? "Add" : "Edit"} Payment Step`}
          submitButtonLabel={mode === "add" ? "Add" : "Update"}
          dataSource={PaymentStepsFormSource}
          fullScreen={fullScreen}
          enableFullScreenToggle={true}
          onBeforeSave={onBeforeSavePaymentStepDetails}
          onBeforePopulate={async (originalData: Partial<PaymentStep>) => {
            const data = await handleOnBeforePopulate(originalData);
            return data;
          }}
          onSubmitComplete={handleOnSubmitComplete}
          fullWidth
          PaperProps={{
            sx: getDialogResizePaperPropsSx("lg"),
          }}
          defaultData={defaultData}
          draggable={true}
          onClose={handleOnClose}
        >
          <PaymentStepFormComponent
            mode={mode}
            setSelectedReferenceSteps={setSelectedReferenceSteps}
            selectedSteps={preSelectedStepsId}
            waterfallId={waterfallId}
            waterfallStepId={waterfallStepId}
            waterfallStepDetails={waterfallStepDetails}
            selectedTemplateParameters={
              selectedTemplateParameters?.template_parameters
            }
            maxSteps={totalRecords ? totalRecords : 1}
            setSelectedTemplateParameters={setSelectedTemplateParameters}
          ></PaymentStepFormComponent>
          {selectedTemplateParameters &&
            selectedTemplateParameters?.template_parameters
              ?.sort((itemA: TemplateParameter, itemB: TemplateParameter) =>
                itemA.order > itemB.order
                  ? 1
                  : itemA.order < itemB.order
                  ? -1
                  : 0
              )
              ?.map((parameter: TemplateParameter) => {
                return (
                  <ParameterValueForBulkEditFormComponent
                    key={parameter.id}
                    parameterName={parameter?.parameter_name ?? ""}
                    dataSourceValues={parameter.data_source_values}
                    valueType={"VAL"}
                    dataType={parameter?.data_type ?? ""}
                    parameterType={parameter?.type ?? ""}
                    purpose={parameter.purpose}
                    parameterValueType={parameter?.value_type}
                    lookupCodes={parameter?.lookup_codes}
                    predefinedTable={false}
                    dataSource={parameter?.data_source}
                    parameterId={parameter.id}
                    isInvokedFromPop={true}
                    parameterDescription={parameter?.description}
                    parameterValueRequired={parameter?.value_required}
                  />
                );
              })}
        </AsyncFormDialog>
      </DdxDataContext.Provider>
    )
  );
};

