};

export const UpdateReferencesFormDialog: FunctionComponent<
  PaymentStepFormDialogProps
> = ({ modelId, portfolioId, waterfallId, refreshGrid, ...props }) => {
  const theme = useTheme();
  const fullScreen = useMediaQuery(theme.breakpoints.down("md"));
  const [, setSelectedSteps] = useState<PaymentStep[]>([]);
  const { open } = useActionDialog();

  useEffect(() => {
    setSelectedSteps([]);
  }, [open]);

  const UpdatePaymentReferenceDataSource = useMemo(
    () => ({
      idField: "id",
      mode: "edit",
      save: {
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/waterfalls/${waterfallId}/steps:batchUpdate`,
        method: "patch",
      },
    }),
    [portfolioId, modelId, waterfallId]
  );

  const handleOnBeforeSave = async () => {
    const batchUpdateRequest = {
      requests: [] as WaterFallStepBatchUpdate[],
    };

    gridApiRef?.current?.forEachNode((node) => {
      batchUpdateRequest.requests.push({
        waterfall_step: node.data,
      });
    });

    return Promise.resolve(batchUpdateRequest);
  };
  const axiosFactory = useAxiosFactory();
  const messageAnnouncer = useMessageAnnouncer();

  const [selectedBulkPaymentSteps, setSelectedBulkPaymentSteps] = useState<
    PaymentStep[]
  >([]);
  const [reloadBatchGrid, setReloadBatchGrid] = useState(false);
  const [isFormOpened, setIsFormOpened] = useState(false);

  useEffect(() => {
    const abortController = new AbortController();
    const loadSteps = async () => {
      try {
        const axios = await axiosFactory.createAxiosInstance();
        const { data } = await axios.get<{ waterfall_steps: PaymentStep[] }>(
          `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/waterfalls/${waterfallId}/steps`,
          {
            signal: abortController.signal,
          }
        );
        setSelectedBulkPaymentSteps(data.waterfall_steps);
        setIsFormOpened(true);
        setReloadBatchGrid(false);
      } catch (error) {
        messageAnnouncer.error(`Failed to load Payment steps: ${error}`);
      }
    };
    if (open && (waterfallId || reloadBatchGrid)) {
      loadSteps();
    }
    return () => abortController.abort();
  }, [
    axiosFactory,
    messageAnnouncer,
    portfolioId,
    modelId,
    waterfallId,
    reloadBatchGrid,
    open,
  ]);

  const gridApiRef = useRef<GridApi<PaymentStep> | null>();

  useEffect(() => {
    return () => {
      gridApiRef.current = null;
    };
  }, [gridApiRef]);

  const updateBatchDocRef = (docRef?: HTMLInputElement) => {
    gridApiRef?.current?.forEachNode((node) => {
      if (node?.isSelected()) {
        const data = {
          ...node.data,
          document_reference: docRef?.value ?? node.data?.document_reference,
        } as PaymentStep;
        node.setData(data);
      }
    });
  };

  const updateBatchReportRef = (reportRef?: HTMLInputElement) => {
    gridApiRef?.current?.forEachNode((node) => {
      if (node?.isSelected()) {
        const data = {
          ...node.data,
          report_reference: reportRef?.value ?? node.data?.report_reference,
        } as PaymentStep;
        node.setData(data);
      }
    });
  };
  const docRef = useRef();
  const reportRef = useRef();

  useEffect(() => {
    if (
      isFormOpened &&
      selectedBulkPaymentSteps.length > 0 &&
      gridApiRef.current
    ) {
      gridApiRef?.current?.forEachNode((node) => {
        if (selectedBulkPaymentSteps.find((row) => row.id === node.data?.id)) {
          node.setSelected(true);
        }
      });
    }
  }, [isFormOpened, selectedBulkPaymentSteps]);

  return (
    <AsyncFormDialog
      {...props}
      dataSource={UpdatePaymentReferenceDataSource}
      title="Update References"
      fullScreen={fullScreen}
      fullWidth
      onBeforeSave={handleOnBeforeSave}
      onSubmitComplete={() => {
        refreshGrid?.();
        setReloadBatchGrid(true);
      }}
      PaperProps={{
        sx: getDialogResizePaperPropsSx("md"),
      }}
      draggable={true}
      defaultData={{
        document_reference: "",
        report_reference: "",
      }}
    >
      <FormFieldGroup>
        <FormTextField
          fieldName="document_reference"
          label="Document Reference"
          variant="outlined"
          inputRef={docRef}
        ></FormTextField>
        <Button onClick={() => updateBatchDocRef(docRef.current)}>
          Update checked
        </Button>
      </FormFieldGroup>
      <FormFieldGroup>
        <FormTextField
          fieldName="report_reference"
          label="Report Reference"
          variant="outlined"
          inputRef={reportRef}
        ></FormTextField>
        <Button onClick={() => updateBatchReportRef(reportRef.current)}>
          Update checked
        </Button>
      </FormFieldGroup>
      {waterfallId ? (
        <Stack sx={{ flexGrow: 1, height: "100%" }}>
          <Typography sx={{ color: "text.secondary" }}>
            Apply Changes to the following Payments
          </Typography>
          <Paper sx={{ flex: "1 1 0px", minHeight: "20vmax", mb: 2, pt: 1 }}>
            <CustomDataGrid
              meta={paymentStepBulkMeta}
              data={{ rowData: selectedBulkPaymentSteps }}
              rowSelectionMode="multi"
              agGridProps={{
                onGridReady: (e) => {
                  gridApiRef.current = e.api;
                },
              }}
              colDefOverrides={colDefOverrides}
              gridPersistOptions={{
                key: "POP-STEP-UPDATE-REF",
                enabled: true,
              }}
            ></CustomDataGrid>
          </Paper>
        </Stack>
      ) : null}
    </AsyncFormDialog>
  );
};

