const colDefOverrides: ColDefOverride[] = [
  {
    field: "aggregation_level_description",

    colDef: { filter: "agSetColumnFilter" },
  },
  {
    field: "category_description",

    colDef: { filter: "agSetColumnFilter" },
  },
  {
    field: "data_type_description",

    colDef: { filter: "agSetColumnFilter" },
  },
  {
    field: "lookup_type_description",

    colDef: { filter: "agSetColumnFilter" },
  },
  {
    field: "field_name",

    colDef: { filter: "agTextColumnFilter" },
  },
  {
    field: "currency_type_description",

    colDef: { filter: "agSetColumnFilter" },
  },
];

export const ParameterValueForBulkEditFormComponent: FunctionComponent<
  ParameterValueFormComponentProps
> = ({
  mode,
  parameterName,
  dataSourceValues,
  valueType,
  dataType,
  parameterType,
  parameterValueType,
  lookupCodes,
  predefinedTable,
  dataSource,
  parameterId,
  parameterDescription,
  isInvokedFromPop,
  parameterValueRequired,
  isFilterExpression,
}) => {
  const theme = useTheme();

  const dataSourceTextFieldProps = useMemo<TextFieldProps>(
    () => ({
      label: !isInvokedFromPop ? (
        parameterName
      ) : (
        <>
          <Box
            component="span"
            sx={{ display: "inline-flex", alignItems: "center", gap: 0.5 }}
          >
            {`${parameterName}${parameterType === "OUTP" ? "(Output) " : ""}`}

            <Tooltip
              children={
                <span aria-hidden="true">
                  <InfoIcon
                    sx={{
                      color: theme.palette.info.main,
                    }}
                    size={16}
                  ></InfoIcon>
                </span>
              }
              title={parameterDescription}
            />
          </Box>
        </>
      ),
      variant: "outlined",
      required: parameterValueRequired ?? false,
    }),
    [
      isInvokedFromPop,
      parameterDescription,
      parameterName,
      parameterType,
      parameterValueRequired,
      theme.palette.info.main,
    ]
  );

  const [fields, setFields] = useState<DataDictionaryField[]>([]);
  const axiosFactory = useAxiosFactory();

  useEffect(() => {
    const abortController = new AbortController();

    const loadDataDictionaryFields = async () => {
      const axios = await axiosFactory.createAxiosInstance();
      const { data } = await axios.get<{
        data_dictionary_fields: DataDictionaryField[];
      } | null>("/solvasam-bff/v1/dataDictionaryFields", {
        signal: abortController.signal,
      });
      setFields(data?.data_dictionary_fields ?? []);
    };
    if (parameterValueType === "F") loadDataDictionaryFields();

    return () => abortController.abort();
  }, [axiosFactory, parameterValueType]);

  let valDataType = convertDataType(dataType);
  let tableValueSchema: DataGridMeta = { idField: "id", gridFields: [] };

  const ddxDataForFieldFormula =
    useContext(DdxDataContext)?.ddxDataForFieldFormula ?? defaultDdx;
  const ddxDataForFilterExpression =
    useContext(DdxDataContext)?.ddxDataForFilterExpression ?? defaultDdx;

  if (parameterValueType === "B") {
    valDataType = "BOOLEAN";
  }

  if (parameterValueType === "T") {
    valDataType = "TABLE";
    tableValueSchema = getSchema(dataSource ?? "");
  }

  useEffect(() => {
    console.log(`parameterValueType: ${parameterValueType}`);
    console.log(`parameterValueRequired: ${parameterValueRequired}`);
  }, [parameterValueType, parameterValueRequired]);
  return (
    <Fragment>
      {(() => {
        switch (parameterValueType) {
          case "C":
            return (
              <FormFieldGroup sx={{ flexDirection: "column" }}>
                <FormFormulaEditor
                  id={parameterId}
                  errors={[]}
                  sx={{ flexDirection: "column" }}
                  ddxData={
                    isFilterExpression
                      ? ddxDataForFilterExpression
                      : ddxDataForFieldFormula
                  }
                  purpose={
                    isFilterExpression ? "FIELD_FORMULA" : "VARIABLE_FORMULA"
                  }
                  label={parameterName}
                  required={parameterValueRequired ?? false}
                ></FormFormulaEditor>
              </FormFieldGroup>
            );
          case "E":
            return (
              <Fragment>
                <FormExpressionBuilder
                  id={parameterId}
                  ddxProps={ddxDataForFilterExpression}
                  label={parameterName}
                >
                  <AddExpressionMenu />
                  <DeleteExpression />
                  <CopyExpression />
                  <PasteMenu />
                </FormExpressionBuilder>
              </Fragment>
            );
          case "L":
            return (
              <FormFieldGroup>
                <FormAutocomplete
                  fieldName={parameterId}
                  valueField="code"
                  labelField="description"
                  options={lookupCodes ?? []}
                  textFieldProps={dataSourceTextFieldProps}
                ></FormAutocomplete>
              </FormFieldGroup>
            );
          case "P":
          case "R":
            return (
              <FormFieldGroup>
                <FormAutocomplete
                  fieldName={parameterId}
                  valueField={"code"}
                  labelField={"description"}
                  options={dataSourceValues ?? []}
                  textFieldProps={dataSourceTextFieldProps}
                ></FormAutocomplete>
              </FormFieldGroup>
            );
          case "F":
            return (
              <FormFieldWithGrid
                fieldName={parameterId}
                labelField="display_name"
                valueField="field_name"
                textFieldProps={{
                  required: parameterValueRequired ?? false,
                  label: parameterName,
                }}
                meta={FieldsMeta}
                data={{
                  rowData: fields,
                }}
                colDefOverrides={colDefOverrides}
              ></FormFieldWithGrid>
            );
          case "M":
            return (
              <FormFieldGroup>
                <Stack sx={{ flex: "1 1 0px" }}>
                  <FormSelect
                    fieldName={parameterId}
                    label={parameterName}
                    labelId={undefined} //aria-labelledby takes precedence over aria-label; removing labelId avoids the bad computed name source
                    SelectDisplayProps={{ "aria-label": parameterName }} // applies aria-label directly to the role=combobox element.
                    labelField={"description"}
                    options={dataSourceValues ?? []}
                    valueField={"code"}
                    multiple
                    required={parameterValueRequired ?? false}
                  >
                    <DropdownTransferList
                      label={"Datasource List"}
                      autoFocusSearch
                    />
                  </FormSelect>
                </Stack>
              </FormFieldGroup>
            );
          case "V":
          case "B":
          case "T":
            return (
              <FormValueSelector
                valFieldId={parameterId}
                refFieldId={parameterId + "_reference_value"}
                valueTypeId={parameterId + "_value_type"}
                textFieldProps={dataSourceTextFieldProps}
                dataType={valDataType}
                lockValueType={
                  parameterType === "OUTP" || (predefinedTable ?? undefined)
                }
                valueType={valueType?.toLowerCase()}
                tableValueSchema={tableValueSchema ?? {}}
                isCalculated={
                  parameterType === "OUTP" || predefinedTable ? true : undefined
                }
                predefinedTable={predefinedTable}
                parameterValueType={parameterValueType}
              ></FormValueSelector>
            );
          default:
            return (
              <FormFieldGroup>
                <FormTextField
                  fieldName={parameterId}
                  label={parameterName}
                  variant="outlined"
                  required={parameterValueRequired ?? false}
                ></FormTextField>
              </FormFieldGroup>
            );
        }
      })()}
      {mode === "add" ? (
        <FormCustomDatePicker
          fieldName="effective_date"
          label="Effective Date"
          textFieldProps={{
            variant: "outlined",
          }}
        />
      ) : null}
    </Fragment>
  );
};

