import { FunctionComponent, useCallback, useMemo } from "react";

import { IconButtonProps } from "@textile/mui";

import { GridApi } from "@textile/ag-grid";

import { CalculationSequenceStep } from "./calculation-sequence.types";
import { baseUrl } from "../../apis";
import { useFetch } from "../common/useFetch";
import { BatchDeleteComponent } from "../common/batch-delete-component";

export const SequenceStepBatchDeleteAction: FunctionComponent<{
  partialUrl: string;
  refresh: () => void;
  gridApiRef?: React.MutableRefObject<GridApi<CalculationSequenceStep> | null>;
  disabled?: boolean;
  iconButtonProps?: IconButtonProps;
  selectedRecords: Partial<CalculationSequenceStep>[] | null;
  stepList: CalculationSequenceStep[] | [];
  onSubmitComplete?: (message: string) => void;
}> = ({
  refresh,
  gridApiRef,
  disabled,
  partialUrl,
  iconButtonProps,
  selectedRecords,
  onSubmitComplete,
  stepList,
}) => {
  const selectedRecordsForDelete = useMemo(() => {
    const selectedStepsForDelete: Record<
      string,
      Partial<CalculationSequenceStep>[]
    > = {};

    const totalStepsMap = new Map<string, CalculationSequenceStep[]>();
    stepList?.forEach((step: CalculationSequenceStep) => {
      const existingSteps = totalStepsMap.get(step.id) ?? [];
      totalStepsMap.set(step.id, [...existingSteps, step]);
    });

    const appendParent = (step: Partial<CalculationSequenceStep>) => {
      const order = `${step.order}`;
      if (order) {
        selectedStepsForDelete[order] = [
          ...(selectedStepsForDelete[order] ?? []),
          step,
        ];
      }
    };

    const appendChild = (step: Partial<CalculationSequenceStep>) => {
      const parentId = step.tree_data_path?.includes("/")
        ? step?.tree_data_path?.split("/")[0]
        : null;
      if (parentId && totalStepsMap.has(parentId)) {
        const parentSteps = totalStepsMap.get(parentId);
        parentSteps?.forEach((parentStep) => {
          const orderNo = parentStep?.order;
          const priority = orderNo ? `${orderNo}.${step.priority}` : null;
          if (priority) {
            selectedStepsForDelete[priority] = [
              ...(selectedStepsForDelete[priority] ?? []),
              step,
            ];
          }
        });
      }
    };
    selectedRecords?.forEach((step) => {
      if (Number(step.order) !== 0) {
        appendParent(step);
      }
      if (Number(step.priority) !== 0 && stepList?.length) {
        appendChild(step);
      }
    });
    return selectedStepsForDelete;
  }, [selectedRecords, stepList]);

  const deps = useCallback(
    () =>
      selectedRecords && gridApiRef && partialUrl
        ? [selectedRecords, gridApiRef, partialUrl, refresh]
        : [],
    [selectedRecords, gridApiRef, partialUrl, refresh]
  );

  const { fetchData } = useFetch({
    url: "",
    method: "POST",
    deps: deps(),
    autoFetch: false,
  });

  const buildRequestObj = useCallback(
    (
      type: string,
      name: string,
      url: string,
      reqObj: { [key: string]: { names: string[]; url: string } }
    ) => {
      if (reqObj[type]) {
        reqObj[type] = {
          ...reqObj[type],
          names: [...reqObj[type]["names"], name],
        };
      } else {
        reqObj[type] = {
          names: [name],
          url: url,
        };
      }
    },
    []
  );

  const handleDeleteAll = useCallback(
    async (rowDatas: Partial<CalculationSequenceStep>[]) => {
      gridApiRef?.current?.setGridOption("loading", true);
      const reqObj: { [key: string]: { names: string[]; url: string } } = {};
      const message: Record<string, string> = {
        value: "",
      };
      if(rowDatas.length > 0){
        message.value = `Selected calculation steps deleted successfully.`
      }
      rowDatas?.forEach((item) => {
        if (item?.order) {
          buildRequestObj(
            "step",
            `${partialUrl}/${item?.order == 0 ? item?.item_id : item?.id}`,
            `${baseUrl}/${partialUrl}:batchDelete`,
            reqObj
          );

          message.value = `Selected ${item.type_description?.toLocaleLowerCase()} deleted. \n`;
        } else if (
          item?.priority &&
          (item?.order === null || item?.order === 0)
        ) {
          const newUrl = partialUrl.split("/sequences")?.[0];
          const treePath = item?.tree_data_path;
          const parentId = treePath?.split("/")[0];
          if (parentId) {
            const matchingParent = rowDatas.filter(
              (row) => row.id === parentId
            );
            if (matchingParent?.length) return;
            const node = gridApiRef?.current?.getRowNode(parentId);
            if (item?.type === "CRG") {
              buildRequestObj(
                item?.type,
                `o/t111/${newUrl}/calculationGroups/${node?.data?.item_id}/blocks/${item?.id}`,
                `${baseUrl}/${newUrl}/calculationGroups/${node?.data?.item_id}/blocks:batchDelete`,
                reqObj
              );

              message.value = "Calculation block deleted.";
            }
            if (item?.type === "RRDG") {
              buildRequestObj(
                item?.type,
                `o/t111/${newUrl}/recoveryScenarios/${node?.data?.item_id}/rules/${item?.id}`,
                `${baseUrl}/${newUrl}/recoveryScenarios/${node?.data?.item_id}/rules:batchDelete`,
                reqObj
              );
              message.value = "Recovery rating rule deleted.";
            }
            if (item?.type === "RDG") {
              buildRequestObj(
                item?.type,
                `o/t111/${newUrl}/ratingScenarios/${node?.data?.item_id}/rules/${item?.id}`,
                `${baseUrl}/${newUrl}/ratingScenarios/${node?.data?.item_id}/rules:batchDelete`,
                reqObj
              );
              message.value = "Rating derivation rule deleted.";
            }
            if (item?.type === "PBG") {
              buildRequestObj(
                item?.type,
                `o/t111/${newUrl}/pbRuleGroups/${node?.data?.item_id}/rules/${item?.id}`,
                `${baseUrl}/${newUrl}/pbRuleGroups/${node?.data?.item_id}/rules:batchDelete`,
                reqObj
              );
              message.value = "Principal balance rule deleted.";
            }
          }
        }
      });

      let count = 0;
      const results: string[] = [];
      while (count < Object.keys(reqObj).length) {
        const key = Object.keys(reqObj)[count];
        const resp = await fetchData(reqObj[key]["url"], {
          names: reqObj[key]["names"],
        });
        if (resp?.status === 200) {
          count++;
          results.push("OK");
        } else break;
      }
      if (results.every((val) => val === "OK")) {
        refresh();
        onSubmitComplete?.(message.value);
        message.value = "";
      }

      gridApiRef?.current?.setGridOption("loading", false);
    },

    // eslint-disable-next-line react-hooks/exhaustive-deps
    [partialUrl, gridApiRef, refresh, fetchData, buildRequestObj]
  );

  return (
    <BatchDeleteComponent
      data={selectedRecords}
      selectedData={selectedRecordsForDelete}
      disabled={disabled}
      iconButtonProps={iconButtonProps}
      deleteHandler={handleDeleteAll}
      title={"Delete Calculation Step(s)"}
      titleText={"Do you wish to delete the selected Calculation step(s)?"}
      contentText={
        "Deleting a group will also remove all associated blocks and rules"
      }
    />
  );
};

