import {
  ActionMenu,
  ActionTargetIds,
  AsyncDataGridPanel,
  caseInsensitiveComparator,
  ColDefOverride,
  DataGridActionAdd,
  DataGridActionDelete,
  DataGridActionEdit,
  DataGridActionRefresh,
  DataGridAsyncDialogAction,
  DataGridDataServiceSource,
  DataGridQuickSearch,
  FabricAsyncOperation,
  useRefreshToken,
} from "@textile/biz-components";
import { IconButtonProps, SxProps } from "@textile/mui";
import React, {
  createContext,
  FunctionComponent,
  ReactNode,
  useCallback,
  useContext,
  useMemo,
  useRef,
} from "react";
import { useParams, useSearchParams } from "react-router-dom";

import {
  ComplianceTestImportDialog,
  ComplianceTestFormDialog,
} from "./compliance-tests-form-dialog.component";
import {
  GridApi,
  GridReadyEvent,
  ICellRendererParams,
  IRowNode,
  RowDragEvent,
} from "@textile/ag-grid";
import { useFetch } from "../../common/useFetch";
import { ComplianceTestsBulkEditFormDialog } from "./compliance-tests-bulk-edit-form-dialog";
import { Test } from "../tests.types";
import { AppRouteParams } from "../../screen.types";
import { formatDate, isParameterValid } from "../../common";
import { DisplayOrderCellRenderer } from "../common/display-order-cell-renderer.component";
import { DuplicateIcon } from "@textile/common";
import {
  DataGridActionViewSource,
  DownloadActionMenu,
  NumericCellEditor,
  useCustomMessageAnnouncer,
} from "@solvasam/bizcomponents";
import {
  useRefreshNeedReviewOnChildGrid,
  useRefreshNeedReviewOnParentGrid,
} from "../../common/refresh-need-review.hook";

const gridSx: SxProps = {
  flex: "1 1 0px",
  "& .ag-header-cell-label": {
    // Target the header cell label directly
    display: "-webkit-box",
    WebkitLineClamp: "3", // Limit to 3 lines
    WebkitBoxOrient: "vertical",
    overflow: "hidden",
    textOverflow: "ellipsis", // Display ellipsis when truncated
  },
};

interface ComplianceTestGridProps {
  onSelectionChanged?: (selectedRecord: Test[]) => void;
  disableActions?: boolean;
  editButtonRef?: React.RefObject<HTMLButtonElement>;
  refreshDetails?: () => void;
  selectedModelId?: string;
  children?: ReactNode;
  coldefOverrides?: ColDefOverride[];
  titleComponent?: React.ReactElement<
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    any,
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    string | React.JSXElementConstructor<any>
  >;
  rowSelectionMode?: "single" | "multi";
}

type ComplianceTestsGridActionContextType = {
  portfolioId: string;
  modelId: string;
  disableActions: boolean | undefined;
  refreshDetails: (() => void) | undefined;
  refresh?: () => void;
  editButtonRef?: React.RefObject<HTMLButtonElement>;
  complianceTestDeleteOperation: FabricAsyncOperation;
  complianceTestsDataSource: DataGridDataServiceSource;
};

const ComplianceTestsGridActionContext =
  createContext<ComplianceTestsGridActionContextType>({
    portfolioId: "",
    modelId: "",
    refreshDetails: undefined,
    refresh: undefined,
    editButtonRef: React.createRef<HTMLButtonElement>(),
    disableActions: undefined,
    complianceTestDeleteOperation: {
      url: "",
      operationConfirmedParamLocation: "query",
      method: "delete",
    },
    complianceTestsDataSource: {},
  });

export const ComplianceTestGrid: FunctionComponent<ComplianceTestGridProps> = (
  props
) => {
  const {
    onSelectionChanged,
    disableActions,
    editButtonRef,
    refreshDetails,
    selectedModelId,
    children: children,
    titleComponent,
    rowSelectionMode = "multi",
  } = props;
  const [refreshToken, refresh] = useRefreshToken();
  const { portfolioId, modelId } = useParams<AppRouteParams>();
  const finalModelId = modelId || selectedModelId;
  const agGridApiRef = useRef<GridApi | null>(null);
  const complianceTestsDataSource = useMemo<DataGridDataServiceSource>(
    () => ({
      url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${finalModelId}/tests:view`,
    }),
    [finalModelId, portfolioId]
  );

  const messageAnnouncer = useCustomMessageAnnouncer();

  const [searchParams] = useSearchParams();
  const rowId = searchParams.get("rowId");

  const complianceTestDeleteOperation = useMemo<FabricAsyncOperation>(
    () => ({
      url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/tests:batchDelete`,
      operationConfirmedParamLocation: "body",
      method: "post",
      idsField: "names",
    }),
    [modelId, portfolioId]
  );

  const agGridCustomSx: SxProps = {
    ".ag-cell-focus": {
      border: "none !important",
    },
  };

  const updateOrderValue = async (test: Test, display_order: number) => {
    if (test) {
      const ComplianceTestDisplayOrderUpdateRequest = {
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/tests/${test.id}?operation_confirmed=1`,
        requestObj: {
          display_order: display_order,
          etag: test.etag,
        },
      };
      try {
        const displayOrderUpdateResp = await updateData(
          ComplianceTestDisplayOrderUpdateRequest.url,
          ComplianceTestDisplayOrderUpdateRequest.requestObj
        );
        if (displayOrderUpdateResp?.status === 200) refresh ? refresh() : null;
      } catch (error) {
        messageAnnouncer.error(
          `Failed to update Display Order: ${error}`,
          error
        );
      }
    }

    return null;
  };

  const colDefOverrides: ColDefOverride[] = [
    {
      field: "begin_date_description",
      colDef: {
        cellRenderer: (props: ICellRendererParams) => {
          return formatDate(props.value?.toString()?.replace(/^"|"$/g, ""));
        },
      },
    },
    {
      field: "end_date_description",
      colDef: {
        cellRenderer: (props: ICellRendererParams) => {
          return formatDate(props.value?.toString()?.replace(/^"|"$/g, ""));
        },
      },
    },
    {
      field: "run_in_batch_mode",
      colDef: {
        cellRenderer: (params: ICellRendererParams) =>
          params.value ? "Yes" : "No",
      },
    },
    {
      field: "display_order",
      colDef: {
        rowDrag: true,
        editable: true,
        cellEditor: NumericCellEditor,
        cellEditorParams: {
          // make "dataType" value available to cell editor
          dataType: "string",
        },
        cellStyle: { "text-align": "right" },
        cellRenderer: DisplayOrderCellRenderer,
        valueGetter: (params) =>
          params?.data?.display_order != null
            ? Number(params.data.display_order)
            : null,
        comparator: caseInsensitiveComparator,
        onCellValueChanged: (params) => {
          const newValue = params.newValue;
          const oldValue = params.oldValue;
          const record = params.data;

          if (newValue !== oldValue) {
            updateOrderValue(record, newValue);
          }
        },
      },
    },
  ];

  const deps = useCallback(
    () =>
      modelId && portfolioId && refreshDetails
        ? [modelId, portfolioId, refreshDetails]
        : [],
    [modelId, portfolioId, refreshDetails]
  );

  const onRowDragEnd = async (event: RowDragEvent) => {
    const movingNode = event.node;
    const overNode = event.overNode;

    if (
      movingNode !== overNode &&
      movingNode?.data?.display_order &&
      overNode?.data?.display_order
    ) {
      updateTestsOrder(movingNode, overNode);
    }
  };

  const { fetchData: updateData } = useFetch<Test>({
    url: "",
    method: "PATCH",
    deps: deps(),
    autoFetch: false,
  });

  const updateTestsOrder = async (movingNode: IRowNode, overNode: IRowNode) => {
    const ComplianceTestDisplayOrderUpdateRequest = {
      url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/tests/${movingNode.data.id}?operation_confirmed=1`,
      requestObj: {
        display_order: overNode.data.display_order,
        etag: movingNode.data.etag,
      },
    };

    try {
      const displayOrderUpdateResp = await updateData(
        ComplianceTestDisplayOrderUpdateRequest?.url,
        ComplianceTestDisplayOrderUpdateRequest?.requestObj
      );
      if (displayOrderUpdateResp?.status === 200) refresh ? refresh() : null;
    } catch (error) {
      messageAnnouncer.error(`Failed to update Display Order: ${error}`, error);
    }

    return null;
  };

  useRefreshNeedReviewOnChildGrid(agGridApiRef, "DTP");
  useRefreshNeedReviewOnParentGrid(finalModelId, "PSM", "DT", agGridApiRef);

  const onGridReady = (event: GridReadyEvent) => {
    agGridApiRef.current = event.api;

    if (rowId) {
      const rowNode = agGridApiRef.current.getRowNode(rowId);

      if (rowNode) {
        rowNode.setSelected(true);
        agGridApiRef.current.ensureIndexVisible(rowNode.sourceRowIndex, "top");
      }
    }
  };

  return isParameterValid(finalModelId) ? (
    <AsyncDataGridPanel
      rowSelectionMode={rowSelectionMode}
      dataSource={complianceTestsDataSource}
      sx={{ ...gridSx, ...agGridCustomSx }}
      onSelectionChanged={onSelectionChanged}
      colDefOverrides={rowSelectionMode == "multi" ? colDefOverrides : []}
      titleComponent={titleComponent}
      refreshToken={refreshToken}
      gridPersistOptions={{
        key: `CT`,
        enabled: true,
      }}
      agGridProps={{
        defaultColDef: {
          autoHeaderHeight: true,
          minWidth: 30, // to allow for the vertical 3 dot kebab icon to show
          wrapHeaderText: true, // css rules limit the max rows to 3 and add ellipsis (see gridSx definition above)
        },
        enableBrowserTooltips: true,
        onRowDragEnd: onRowDragEnd,
        singleClickEdit: true,
        skipHeaderOnAutoSize: true,
        stopEditingWhenCellsLoseFocus: true,
        onGridReady: (e: GridReadyEvent) => {
          onGridReady?.(e);
        },
      }}
    >
      <ComplianceTestsGridActionContext.Provider
        value={{
          portfolioId: portfolioId as string,
          modelId: modelId as string,
          refreshDetails: refreshDetails,
          refresh: refresh,
          editButtonRef: editButtonRef,
          disableActions: disableActions,
          complianceTestDeleteOperation: complianceTestDeleteOperation,
          complianceTestsDataSource: complianceTestsDataSource,
        }}
      >
        {children}
      </ComplianceTestsGridActionContext.Provider>
    </AsyncDataGridPanel>
  ) : null;
};

export const ComplianceTestsGridActions = () => {
  const {
    refresh,
    refreshDetails,
    disableActions,
    editButtonRef,
    complianceTestDeleteOperation,
    complianceTestsDataSource,
  } = useContext(ComplianceTestsGridActionContext);

  const iconButtonProps = useMemo<IconButtonProps>(() => {
    return disableActions ? { disabled: true } : {};
  }, [disableActions]);

  const handleUpdateUi = (agGridApi: GridApi<any>, ids: ActionTargetIds) => {
    const id = ids ? ids[0] : null;
    const childNode = agGridApi?.getRowNode(id);

    if (childNode) {
      const updatedRecord = { ...childNode.data };

      const expandedNodes: { [key: string]: boolean } = {};
      agGridApi?.forEachNode((node) => {
        if (node.expanded && node.id) {
          expandedNodes[node.id] = true;
          node.setExpanded(false);
        }
      });
      agGridApi?.applyTransaction({ remove: [childNode.data] });
      agGridApi?.applyTransaction({
        add: [updatedRecord],
        addIndex: Number(updatedRecord.order) - 1,
      });

      Object.keys(expandedNodes).forEach((nodeId) => {
        const node = agGridApi?.getRowNode(nodeId);
        if (node) {
          node.setExpanded(true);
        }
      });
      agGridApi?.getRowNode(updatedRecord.id)?.setSelected(true, true);
    }
  };
  return (
    <>
      <DataGridQuickSearch></DataGridQuickSearch>
      <DataGridActionAdd
        iconButtonProps={iconButtonProps}
        dialog={<ComplianceTestFormDialog />}
        onUpdateUi={(data, agGridApi, ids) => {
          handleUpdateUi(agGridApi, ids);
        }}
      ></DataGridActionAdd>
      <DataGridActionEdit
        dialog={<ComplianceTestFormDialog />}
         onUpdateUi={(data, agGridApi, ids) => {
            handleUpdateUi(agGridApi, ids);
            refreshDetails?.();
          }}
        iconButtonProps={{ ...iconButtonProps, ref: editButtonRef }}
      ></DataGridActionEdit>
      <DataGridActionDelete
        confirmationDialogProps={{ confirmButtonLabel: "Delete" }}
        iconButtonProps={iconButtonProps}
        operation={complianceTestDeleteOperation}
        rowSelectionMode="multi"
      />
      <DataGridAsyncDialogAction
        actionCode="duplicate"
        label="Duplicate"
        level="grid"
        type="icon"
        icon={<DuplicateIcon size={24} />}
        iconButtonProps={iconButtonProps}
        loadOnOpen={false}
        onUpdateUi={refresh}
        dialog={<ComplianceTestImportDialog />}
      />
      <ActionMenu>
        <DownloadActionMenu isPopover={true} />
        <DataGridAsyncDialogAction
          actionCode="bulkedit"
          label="Bulk Edit"
          level="grid"
          type="menuitem"
          iconButtonProps={iconButtonProps}
          loadOnOpen={false}
          onUpdateUi={refresh}
          dialog={<ComplianceTestsBulkEditFormDialog />}
        />
        <DataGridActionRefresh
          type="menuitem"
          icon={null}
        ></DataGridActionRefresh>
        <DataGridActionViewSource
          datasource={complianceTestsDataSource}
          type="menuitem"
        />
      </ActionMenu>
    </>
  );
};

