};

const SubmitButton = forwardRef<HTMLButtonElement, SubmitButtonProps>(
  (props: SubmitButtonProps, ref) => {
    const { isLoading, children, ...other } = props;

    const { isSubmitting } = useFormikContext();

    return (
      <Button
        ref={ref}
        type="submit"
        variant="contained"
        disabled={isLoading || isSubmitting}
        {...other}
      >
        {children}
      </Button>
    );
  }
);

interface AddEditComplianceTestParametersFormDialog {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  testParameterHistory: any;
  testId?: string;
  parameterId?: string;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  agGridApiRef?: React.MutableRefObject<GridApi<any> | null>;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  ddxData?: any;
}

export const AddEditComplianceTestParametersFormDialog: FunctionComponent<
  AddEditComplianceTestParametersFormDialog
> = ({ testParameterHistory, agGridApiRef, testId, parameterId, ddxData }) => {
  const [open, setOpen] = useState(false);
  const [mode, setMode] = useState<"add" | "edit">("add");
  const { portfolioId, modelId } = useParams<AppRouteParams>();
  const { sharedAppContextManager } = useStaticAppContext();
  const { state: disableActions } = sharedAppContextManager.useContext<
    string | null
  >("app.selectedModelState");
  const theme = useTheme();
  const axiosFactory = useAxiosFactory();

  const hideGridActions = useMemo(
    () => disableActions === "L",
    [disableActions]
  );
  const [isLoading, setIsLoading] = useState(true);
  const [submitButtonElement, setSubmitButtonElement] =
    useState<HTMLElement | null>(null);

  const handleSubmitButtonClick = (event: MouseEvent<HTMLElement>) => {
    setSubmitButtonElement(event.currentTarget);
  };

  const formTestParameterHistoryDataSource = useMemo(
    () => ({
      idField: "id",
      mode: mode,
      get: {
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/tests/${testId}/parameters/${parameterId}/historicalValues`,
      },
      save: {
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/tests/${testId}/parameters/${parameterId}/historicalValues`,
        queryParams: { operation_confirmed: "1" },
        method: mode === "add" ? "post" : "patch",
      },
      targetIds: [testParameterHistory.id],
    }),
    [mode, portfolioId, modelId, testId, parameterId, testParameterHistory.id]
  );

  const formTestParameterHistoryAddDataSource = useMemo(
    () => ({
      idField: "id",
      mode: mode,
      get: {
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/tests/${testId}/parameters/${parameterId}`,
      },
      save: {
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/tests/${testId}/parameters/${parameterId}/historicalValues`,
        method: "post",
      },
    }),
    [mode, portfolioId, modelId, testId, parameterId]
  );

  const formTestParameterDataSource = useMemo(
    () => ({
      idField: "id",
      mode: mode,
      get: {
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/tests/${testId}/parameters`,
      },
      save: {
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/tests/${testId}/parameters`,
        method: "patch",
      },
      targetIds: [testParameterHistory.id],
    }),
    [mode, portfolioId, modelId, testId, testParameterHistory.id]
  );

  const handleClose = useCallback(() => {
    setOpen(false);
  }, []);

  const handleOnClose = useCallback(
    (_event: object, reason: string) => {
      if (reason !== "backdropClick") {
        handleClose?.();
      }
    },
    [handleClose]
  );

  const gridUpdate = useCallback(async () => {
    const axios = await axiosFactory.createAxiosInstance();
    try {
      const response = await axios.get(
        `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/tests/${testId}/parameters/${parameterId}`
      );
      const updatedData = response.data;
      if (agGridApiRef?.current && parameterId) {
        const rowNode = agGridApiRef.current.getRowNode(parameterId);
        if (rowNode) {
          rowNode.setData(updatedData);
        }
      }
    } catch (error) {
      console.error("Failed to update row:", error);
    }
  }, [axiosFactory, portfolioId, modelId, testId, parameterId, agGridApiRef]);

  const handleOnSubmitComplete = useCallback(() => {
    setIsLoading(false);
    handleClose();
    gridUpdate();
  }, [gridUpdate, handleClose]);

  const handleClickOpen = (mode: "add" | "edit") => {
    setMode(mode);
    setOpen(true);
  };
  const modelExpr = useRef<ModelExpression | null | undefined>();

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const onBeforeSave = async (
    data: Partial<
      CalculationBlockParameter & TestParameter & ParameterValueHistory
    >
  ) => {
    setIsLoading(true);
    data.value_type = data.form_value_type
      ? data.form_value_type.toUpperCase()
      : data.value_type;
    hydrateParameterBeforeSave(
      data as CalculationBlockParameter,
      data.data_source_values ?? [],
      data.lookup_codes ?? []
    );
    if (
      !(
        testParameterHistory.effective_date_description === "Default" &&
        mode === "edit"
      )
    ) {
      /* eslint-disable @typescript-eslint/no-unused-vars */
      const {
        id,
        lid,
        value,
        value_description,
        parameter_value,
        parameter_id,
        historical_value,
        formula_friendly_description,
        applicability_expression_friendly_description,
        effective_date_description,
        effective_date,
        effective_date_reference,
        code,
        etag,
        created_at,
        created_by,
        modified_at,
        modified_by,
        parameter_code,
        action_masks,
        name,
        ...rest
      } = data;
      return {
        id: data.id,
        value: {
          ...rest,
          lookup_codes: [],
          data_source_values: [],
        },
        action_masks: action_masks,
        effective_date: data.effective_date,
        etag: data.etag,
      };
    } else {
      return {
        ...data,
        data_source_values: [],
        lookup_codes: [],
      };
    }
  };

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const onBeforeParameterFormPopulate = (record: any) => {
    setIsLoading(false);
    hydrateParameterBeforePopulate(record);
    modelExpr.current = record.applicability_value;
    if (
      mode === "edit" &&
      testParameterHistory.effective_date_description !== "Default"
    ) {
      record = {
        ...record,
        ...record.value,
      };
    }
    if (record.table_value) {
      record.table_value = parseTableParameterValue(
        record.table_value as string[]
      );
    }
    return mode === "add"
      ? {
          ...record,
          id: null,
          code: null,
          boolean_value: null,
          string_value: null,
          numeric_value: null,
          date_time_value: null,
          field_name_value: null,
          formula_value: null,
          applicability_value: null,
          table_value: [],
          comments: null,
          lid: null,
          value_type: "VAL",
          reference_value: "",
          effective_date: new Date().toISOString(),
        }
      : record;
  };
  const tableValuesData = testParameterHistory.value?.table_value?.length
    ? parseTableParameterValue(testParameterHistory.value.table_value)
    : [];

  return (
    <Fragment>
      <Typography sx={dateFieldTextSx}>
        {testParameterHistory.effective_date_description === "Default"
          ? testParameterHistory.effective_date_description
          : formatDate(testParameterHistory.effective_date, "MM/DD/YYYY")}
      </Typography>
      {hideGridActions ? (
        testParameterHistory.value?.parameter_value_type == "T" &&
        testParameterHistory.value?.value_type &&
        testParameterHistory.value.value_type.toUpperCase() === "VAL" &&
        tableValuesData.length > 0 ? (
          <TableGrid
            tableValues={tableValuesData}
            dataSource={testParameterHistory.value?.data_source}
          ></TableGrid>
        ) : (
          <Typography variant="caption">
            {testParameterHistory.value_description}
          </Typography>
        )
      ) : (
        <Stack
          sx={{
            flexDirection: "row",
            display: "flex",
            alignItems: "center",
            gap: 0.5,
          }}
        >
          {testParameterHistory.value?.parameter_value_type == "T" &&
          testParameterHistory.value?.value_type &&
          testParameterHistory.value.value_type.toUpperCase() === "VAL" &&
          tableValuesData.length > 0 ? (
            <Stack display="flex" flexDirection={"column"} gap={0.5}>
              <Link
                sx={valueFieldTextSx}
                onClick={() => handleClickOpen("edit")}
              >
                <Typography variant="caption">Update Table</Typography>
              </Link>
              <TableGrid
                tableValues={tableValuesData}
                dataSource={testParameterHistory.value?.data_source}
              ></TableGrid>
            </Stack>
          ) : (
            <Typography sx={valueFieldTextSx}>
              <Link
                sx={{
                  color:
                    testParameterHistory.value_description ===
                    "[Parameter Value Required]"
                      ? theme.palette.error.main
                      : "none",
                  fontSize: "0.75rem",
                }}
                onClick={() => handleClickOpen("edit")}
              >
                {testParameterHistory.value.parameter_value_type == "E" &&
                testParameterHistory.value_description !== "{Not Specified}" ? (
                  <RuleDisplayComponent
                    value={ddxFormatter.format(
                      testParameterHistory.value_description ?? ""
                    )}
                    ddxData={ddxData}
                    sx={{cursor: "pointer", "&:hover": { textDecoration: "underline" }}}
                  />
                ) : (
                  testParameterHistory.value_description
                )}
              </Link>
            </Typography>
          )}
          <Box sx={iconsBoxSx}>
            {testParameterHistory.effective_date_description === "Default" ? (
              <Tooltip title="Add">
                <IconButton onClick={() => handleClickOpen("add")}>
                  <AddItemIcon size={16}></AddItemIcon>
                </IconButton>
              </Tooltip>
            ) : (
              <ComplianceTestDeleteOperation
                onAfterDelete={gridUpdate}
                targetId={testParameterHistory.id}
                testId={testId}
                parameterId={parameterId}
              />
            )}
          </Box>
        </Stack>
      )}
      {open ? (
        <Dialog
          onClose={handleOnClose}
          open={open}
          fullScreen={false}
          fullWidth={true}
          draggable={true}
          PaperProps={{ sx: getDialogResizePaperPropsSx("md") }}
        >
          <Form
            dataSource={
              mode === "add"
                ? formTestParameterHistoryAddDataSource
                : testParameterHistory.effective_date_description ===
                    "Default" && mode === "edit"
                ? formTestParameterDataSource
                : formTestParameterHistoryDataSource
            }
            loadOnMount={true}
            confirmationPopoverAnchorElement={submitButtonElement}
            onSubmitComplete={handleOnSubmitComplete}
            onBeforePopulate={onBeforeParameterFormPopulate}
            onBeforeSave={onBeforeSave}
            sx={formSx}
            defaultData={{
              parameter_name: "",
              parameter_description: "",
              field_name_value: "",
              reference_value: "",
              description: "",
              ...(mode === "add" ? { effective_date: null } : {}),
              comments: "",
              applicability_value: null,
              numeric_value: null,
              boolean_value: null,
              formula_value: null,
              string_value: null,
              table_value: [],
              date_time_value: null,
            }}
          >
            <DialogTitle height={64} display={"flex"}>
              Edit Compliance Test Parameter
              <Box sx={{ flexGrow: 1 }} />
              <IconButton
                color="inherit"
                onClick={() => setOpen(false)}
                aria-label="close"
                sx={{ height: "20px", width: "20px", color: "white", pr: 2 }}
              >
                <CloseIcon size={20} />
              </IconButton>
            </DialogTitle>
            <ProgressOrDivider isLoading={isLoading} />
            <DialogContent>
              <Box sx={dialogBoxSx}>
                <ParameterValueFormComponent
                  mode={mode}
                ></ParameterValueFormComponent>
              </Box>
            </DialogContent>
            <Divider></Divider>
            <DialogActions sx={{ gap: 2 }}>
              <Button variant="outlined" onClick={handleClose}>
                Cancel
              </Button>
              <SubmitButton
                isLoading={isLoading}
                onClick={handleSubmitButtonClick}
              >
                Save
              </SubmitButton>
            </DialogActions>
          </Form>
        </Dialog>
      ) : null}
    </Fragment>
  );
};

const boxSx: SxProps = { px: 2, pt: 2, pb: 1 };

export interface ComplianceTestDeleteOperationProps {
  targetId: string;
  testId?: string;
  parameterId?: string;
  onAfterDelete?: () => void;
}

const ComplianceTestDeleteOperation: FunctionComponent<
  ComplianceTestDeleteOperationProps
> = ({ targetId, testId, parameterId, onAfterDelete }) => {
  const buttonRef = useRef<HTMLButtonElement>(null);
  const axiosFactory = useAxiosFactory();
  const { setIsDetailCellUpdate, CellUpdateProgress } = useDetailCellProgress();

  const [openPopover, setOpenPopover] = useState(false);
  const onClose = useCallback(() => {
    setOpenPopover(false);
  }, []);
  const { portfolioId, modelId } = useParams<AppRouteParams>();
  const onContinueClick = useCallback(
    async (targetId: string) => {
      const updateState: cellUpdateState = {
        message: "Deleting...",
        isError: false,
      };
      setIsDetailCellUpdate(updateState);
      const axios = await axiosFactory.createAxiosInstance();
      try {
        const response = await axios({
          url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/tests/${testId}/parameters/${parameterId}/historicalValues/${targetId}?operation_confirmed=1`,
          method: "delete",
        });
        setIsDetailCellUpdate({
          ...updateState,
          isError: false,
          message: "Deleted",
        });
        onAfterDelete?.();
        return response;
      } catch (error) {
        setIsDetailCellUpdate({
          ...updateState,
          isError: true,
          message: "Delete failed",
        });
      }
      return updateState.isError ? undefined : 0;
    },
    [
      setIsDetailCellUpdate,
      axiosFactory,
      portfolioId,
      modelId,
      testId,
      parameterId,
      onAfterDelete,
    ]
  );

  const handleActionClick = useCallback(async () => {
    setOpenPopover(true);
  }, []);

  const handlePopoverContinueClick = useCallback(async () => {
    await onContinueClick(targetId);
  }, [onContinueClick, targetId]);

  return (
    <Fragment>
      <Tooltip title="Delete">
        <IconButton ref={buttonRef} onClick={handleActionClick}>
          <DeleteIcon size={16}></DeleteIcon>
        </IconButton>
      </Tooltip>
      <CellUpdateProgress />
      <Popover
        anchorEl={buttonRef.current}
        anchorOrigin={{
          horizontal: "left",
          vertical: "bottom",
        }}
        open={openPopover}
        onClose={onClose}
      >
        <Box sx={boxSx}>
          <DialogContentText>Delete 1 item(s)?</DialogContentText>
        </Box>
        <DialogActions>
          <Button
            onClick={handlePopoverContinueClick}
            startIcon={<CheckCircleFilledIcon size={20} />}
            variant="text"
          >
            Delete
          </Button>
        </DialogActions>
      </Popover>
    </Fragment>
  );
};

const agGridCustomSx: SxProps = {
  ".ag-center-cols-viewport": {
    minHeight: "unset !important",
  },
};

export const TableGrid: FunctionComponent<{
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  tableValues: any[];
  dataSource: string;
}> = ({ tableValues, dataSource }) => {
  const autoHeight = tableValues.length < 10 ? true : false;
  return (
    <Stack
      sx={{
        flexGrow: 1,
        height: "100%",
        ...(autoHeight ? agGridCustomSx : {}),
        pb: 0.5,
      }}
    >
      <Paper
        sx={{
          flex: "1 1 0px",
          ...(autoHeight ? {} : { minHeight: "350px" }),
        }}
      >
        <CustomDataGrid
          meta={getSchema(dataSource ?? "")}
          data={{
            rowData: tableValues,
          }}
          agGridProps={autoHeight ? { domLayout: "autoHeight" } : {}}
          gridPersistOptions={{
            key: "CT-FORM-TABLE",
            enabled: true,
          }}
        ></CustomDataGrid>
      </Paper>
    </Stack>
  );
};

