                  selectedModelId={selectedModel?.id}
                  rowSelectionMode="singleRow"
                  titleComponent={
                    <TitleWithIcon
                      title={"Priority of Payments Groups"}
                      tolink={`/compliance-modeling-ui/compliance/modeling/${selectedPortfolioId}/${selectedModel?.id}/priorityofpayments?tab=pg`}
                    ></TitleWithIcon>
                  }
                >
                  <DownloadActionMenu />
                  <DataGridActionViewSource datasource={tabDataSource ?? {}} />
                </PaymentGroupGrid>
              ) : selectedTab === "eligilibility_criteria_tests" ? (
                <EligibilityCriteriaGrid
                  modelId={selectedModel?.id}
                  refreshDetails={refresh}
                  selectedPortfolioId={selectedPortfolioId ?? ""}
                  editButtonRef={editButtonRef}
                  rowSelectionMode="single"
                  titleComponent={
                    <TitleWithIcon
                      title={"Eligibility Criteria"}
                      tolink={`/compliance-modeling-ui/compliance/modeling/${selectedPortfolioId}/${selectedModel?.id}/tests/eligibilitycriteria`}
                    ></TitleWithIcon>
