                      title={"Compliance Tests"}
                      tolink={`/compliance-modeling-ui/compliance/modeling/${selectedPortfolioId}/${selectedModel?.id}/tests/compliancetests`}
                    ></TitleWithIcon>
                  }
                >
                  <DownloadActionMenu />
                  <DataGridActionViewSource datasource={tabDataSource ?? {}} />
                </ComplianceTestGrid>
              ) : null}
            </Stack>
          ) : null}
        </Splitter>
      </Stack>
    </Screen>
  );
};

interface TitleWithIconProps {
