import { Screen } from "@textile/common";
import { CustomScreenHeader } from "@solvasam/bizcomponents";
import { Box, SxProps, Tab, Tabs, useMediaQuery, useTheme } from "@textile/mui";
import { FunctionComponent } from "react";
import {
  Link,
  Navigate,
  Route,
  Routes,
  useMatch,
  useResolvedPath,
} from "react-router-dom";
import { ScreenProps } from "../screen.types";
import { PgLayoutScreen } from "./payment-groups/payment-group-step.component";
import { PopLayoutScreen } from "./waterfalls/priority-of-payments-step.component";

const screenSx: SxProps = {
  display: "flex",
  flexDirection: "column",
  height: "100%",
};
const routesBoxSx: SxProps = {
  display: "flex",
  flexDirection: "column",
  flexGrow: 1,
};

export const PriorityOfPaymentTabs = () => {
  const theme = useTheme();
  const fullScreen = useMediaQuery(theme.breakpoints.down("md"));
  const tabpath = useResolvedPath("../:tab/*");
  const match = useMatch(tabpath.pathname);

  return (
    <Tabs
      variant={fullScreen ? "fullWidth" : "standard"}
      value={match?.params.tab ?? "pop"}
    >
      <Tab
        value="pop"
        label="Priority Of Payments"
        to={`../pop`}
        component={Link}
      ></Tab>
      <Tab
        value="pg"
        label="Payment Groups"
        to={`../pg`}
        component={Link}
      ></Tab>
    </Tabs>
  );
};

export const PriorityOfPaymentsLayoutScreen: FunctionComponent<
  ScreenProps
> = () => {
  return (
    <Screen
      sx={screenSx}
      navigationId={
        "compliance-modeling-ui-compliance-modeling-portfolioId-modelId-priorityofpayments"
      }
    >
      <CustomScreenHeader />
      <Box sx={routesBoxSx}>
        <Routes>
          <Route path="pop" element={<PopLayoutScreen />}></Route>
          <Route path="pg" element={<PgLayoutScreen />}></Route>
          <Route index element={<Navigate to="pop" replace></Navigate>} />
        </Routes>
      </Box>
    </Screen>
  );
};

