import {
  AddExpressionMenu,
  CopyExpression,
  DataDictionaryField,
  DeleteExpression,
  FieldsMeta,
  FormExpressionBuilder,
  FormFormulaEditor,
  FormValueSelector,
  PasteMenu,
  FormCustomDatePicker,
} from "@solvasam/bizcomponents";
import {
  ColDefOverride,
  DataGridField,
  DataGridMeta,
  DropdownTransferList,
  FormAutocomplete,
  FormFieldGroup,
  FormSelect,
  FormTextField,
  useField,
} from "@textile/biz-components";
import { Box, Stack, TextFieldProps, Tooltip, useTheme } from "@textile/mui";
import {
  Fragment,
  FunctionComponent,
  useContext,
  useEffect,
  useMemo,
  useState,
} from "react";

import { defaultDdx } from ".";
import { CodePair, DdxDataContext } from "./common-types";
import { InfoIcon, useAxiosFactory } from "@textile/common";
import { FormFieldWithGrid } from "./form-autocomplete-with-grid";

export const dataTypeDictionary: Record<string, string> = {
  M: "CURRENCY",
  D: "DATE",
  N: "NUMERIC",
  P: "PERCENT",
  V: "VARIANT",
  T: "TABLE",
  B: "BOOLEAN",
};

export const assignValueFieldName = (
  parameterValueType: string,
  dataType: string
) => {
  switch (parameterValueType) {
    case "E":
      return "applicability_value";
    case "R":
      return "numeric_value";
    case "B":
      return "boolean_value";
    case "C":
      return "formula_value";
    case "L":
      return "string_value";
    case "F":
      return "field_name_value";
    case "T":
      return "table_value";
    case "M":
      switch (dataType) {
        case "C":
        case "N":
          return "string_value";
        default:
          return "string_value";
      }
    case "P":
      switch (dataType) {
        case "C":
        case "M":
          return "string_value";
        case "N":
          return "numeric_value";
        default:
          return "string_value";
      }
    case "V":
      switch (dataType) {
        case "C":
          return "string_value";
        case "N":
        case "P":
          return "numeric_value";
        case "D":
          return "date_time_value";
        default:
          return "string_value";
      }
    default:
      return "string_value";
  }
};
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export const stringifyJSONObject = (tableValueObject: Record<string, any>) => {
  return tableValueObject.map(JSON.stringify);
};

export const getSchema = (dataSource: string) => {
  const gridFields: DataGridField[] = [];
  const columns = dataSource.split(";");
  columns.forEach((column: string) => {
    const field = {
      name: column.replaceAll(".", "").replaceAll(" ", ""),
      dataType: column === "Effective Date" ? "date" : "string",
      header: column.replace(/\w/, (firstLetter: string) =>
        firstLetter.toUpperCase()
      ),
      visible: true,
    };
    gridFields.push(field);
  });

  return {
    idField: "id",
    gridFields: [
      ...gridFields,
      {
        name: "id",
        dataType: "string",
        header: "Id",
        visible: false,
      },
    ],
  };
};

const convertDataType = (dataType: string) => {
  return dataTypeDictionary[dataType] != null
    ? dataTypeDictionary[dataType]
    : "TEXT";
};

interface ParameterValueFormComponentProps {
  mode?: "add" | "edit";
  parameterName: string;
  dataSourceValues?: CodePair[] | null;
  valueType: string;
  dataType: string;
  parameterType: string;
  purpose?: string | null;
  parameterValueType: string;
  lookupCodes?: CodePair[] | null;
  predefinedTable?: boolean | null;
  dataSource?: string | null;
  parameterId: string;
  parameterDescription?: string | null;
  isInvokedFromPop?: boolean;
  parameterValueRequired?: boolean | null;
  isFilterExpression?: boolean | null;
}

const colDefOverrides: ColDefOverride[] = [
  {
    field: "aggregation_level_description",

    colDef: { filter: "agSetColumnFilter" },
  },
  {
    field: "category_description",

    colDef: { filter: "agSetColumnFilter" },
  },
  {
    field: "data_type_description",

    colDef: { filter: "agSetColumnFilter" },
  },
  {
    field: "lookup_type_description",

    colDef: { filter: "agSetColumnFilter" },
  },
  {
    field: "field_name",

    colDef: { filter: "agTextColumnFilter" },
  },
  {
    field: "currency_type_description",

    colDef: { filter: "agSetColumnFilter" },
  },
];

export const ParameterValueForBulkEditFormComponent: FunctionComponent<
  ParameterValueFormComponentProps
> = ({
  mode,
  parameterName,
  dataSourceValues,
  valueType,
  dataType,
  parameterType,
  parameterValueType,
  lookupCodes,
  predefinedTable,
  dataSource,
  parameterId,
  parameterDescription,
  isInvokedFromPop,
  parameterValueRequired,
  isFilterExpression,
  purpose,
}) => {
  const theme = useTheme();

  const [{ value: fieldValue }, , { setValue: setFieldValue }] =
    useField(parameterId);

  useEffect(() => {
    if (fieldValue !== undefined && fieldValue !== null && fieldValue !== "")
      return;
    if (parameterValueType === "L" || parameterValueType === "B") {
      if (
        ((dataType === "C" && parameterType === "INP") ||
          parameterValueRequired) &&
        lookupCodes?.length
      ) {
        setFieldValue(lookupCodes![0].code);
      } else if (
        dataType === "N" &&
        parameterValueRequired &&
        parameterType === "INP"
      ) {
        setFieldValue(true);
      }
    } else if (
      (parameterValueType === "P" || parameterValueType === "R") &&
      parameterValueRequired &&
      dataSourceValues?.length
    ) {
      setFieldValue(dataSourceValues[0].code);
    } else if (
      parameterValueType === "V" &&
      parameterValueRequired &&
      parameterName === "Percentage Allowed"
    ) {
      setFieldValue("100");
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [
    parameterValueType,
    lookupCodes,
    dataSourceValues,
    parameterValueRequired,
    parameterName,
    parameterType,
    fieldValue,
    dataType,
  ]);

  const dataSourceTextFieldProps = useMemo<TextFieldProps>(
    () => ({
      label: !isInvokedFromPop ? (
        parameterName
      ) : (
        <>
          <Box
            component="span"
            sx={{ display: "inline-flex", alignItems: "center", gap: 0.5 }}
          >
            {`${parameterName}${parameterType === "OUTP" ? "(Output) " : ""}`}

            <Tooltip
              children={
                <span aria-hidden="true">
                  <InfoIcon
                    sx={{
                      color: theme.palette.info.main,
                    }}
                    size={16}
                  ></InfoIcon>
                </span>
              }
              title={parameterDescription}
            />
          </Box>
        </>
      ),
      variant: "outlined",
      required: parameterValueRequired ?? false,
    }),
    [
      isInvokedFromPop,
      parameterDescription,
      parameterName,
      parameterType,
      parameterValueRequired,
      theme.palette.info.main,
    ]
  );

  const [fields, setFields] = useState<DataDictionaryField[]>([]);
  const axiosFactory = useAxiosFactory();

  useEffect(() => {
    const abortController = new AbortController();

    const loadDataDictionaryFields = async () => {
      const axios = await axiosFactory.createAxiosInstance();
      const { data } = await axios.get<{
        data_dictionary_fields: DataDictionaryField[];
      } | null>("/solvasam-bff/v1/dataDictionaryFields", {
        signal: abortController.signal,
      });
      setFields(data?.data_dictionary_fields ?? []);
    };
    if (parameterValueType === "F") loadDataDictionaryFields();

    return () => abortController.abort();
  }, [axiosFactory, parameterValueType]);

  let valDataType = convertDataType(dataType);
  let tableValueSchema: DataGridMeta = { idField: "id", gridFields: [] };

  const ddxDataForFieldFormula =
    useContext(DdxDataContext)?.ddxDataForFieldFormula ?? defaultDdx;
  const ddxDataForFilterExpression =
    useContext(DdxDataContext)?.ddxDataForFilterExpression ?? defaultDdx;

  if (parameterValueType === "B") {
    valDataType = "BOOLEAN";
  }

  if (parameterValueType === "T") {
    valDataType = "TABLE";
    tableValueSchema = getSchema(dataSource ?? "");
  }

  return (
    <Fragment>
      {(() => {
        switch (parameterValueType) {
          case "C":
            return (
              <FormFieldGroup sx={{ flexDirection: "column" }}>
                <FormFormulaEditor
                  id={parameterId}
                  errors={[]}
                  sx={{ flexDirection: "column" }}
                  ddxData={
                    isFilterExpression
                      ? ddxDataForFilterExpression
                      : ddxDataForFieldFormula
                  }
                  purpose={
                    purpose === "VARIABLE_FORMULA"
                      ? "VARIABLE_FORMULA"
                      : "FIELD_FORMULA"
                  }
                  label={parameterName}

