import {
  AddExpressionMenu,
  CopyExpression,
  DataDictionaryField,
  DeleteExpression,
  FieldsMeta,
  FormExpressionBuilder,
  FormFormulaEditor,
  FormValueSelector,
  PasteMenu,
  FormCustomDatePicker,
} from "@solvasam/bizcomponents";
import {
  ColDefOverride,
  DataGridField,
  DataGridMeta,
  DropdownTransferList,
  FormAutocomplete,
  FormFieldGroup,
  FormSelect,
  FormTextField,
  useField,
} from "@textile/biz-components";
import { Box, Stack, TextFieldProps, Tooltip, useTheme } from "@textile/mui";
import {
  Fragment,
  FunctionComponent,
  useContext,
  useEffect,
  useMemo,
  useState,
} from "react";

import { defaultDdx } from ".";
import { CodePair, DdxDataContext } from "./common-types";
import { InfoIcon, useAxiosFactory } from "@textile/common";
import { FormFieldWithGrid } from "./form-autocomplete-with-grid";

export const dataTypeDictionary: Record<string, string> = {
  M: "CURRENCY",
  D: "DATE",
  N: "NUMERIC",
  P: "PERCENT",
  V: "VARIANT",
  T: "TABLE",
  B: "BOOLEAN",
};

export const assignValueFieldName = (
  parameterValueType: string,
  dataType: string
) => {
  switch (parameterValueType) {
    case "E":
      return "applicability_value";
    case "R":
      return "numeric_value";
    case "B":
      return "boolean_value";
    case "C":
      return "formula_value";
    case "L":
      return "string_value";
    case "F":
      return "field_name_value";
    case "T":
      return "table_value";
    case "M":
      switch (dataType) {
        case "C":
        case "N":
          return "string_value";
        default:
          return "string_value";
      }
    case "P":
      switch (dataType) {
        case "C":
        case "M":
          return "string_value";
        case "N":
          return "numeric_value";
        default:
          return "string_value";
      }
    case "V":
      switch (dataType) {
        case "C":
          return "string_value";
        case "N":
        case "P":
          return "numeric_value";
        case "D":
          return "date_time_value";
        default:
          return "string_value";
      }
    default:
      return "string_value";
  }
};
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export const stringifyJSONObject = (tableValueObject: Record<string, any>) => {
  return tableValueObject.map(JSON.stringify);
};

export const getSchema = (dataSource: string) => {
  const gridFields: DataGridField[] = [];
  const columns = dataSource.split(";");
  columns.forEach((column: string) => {
    const field = {
      name: column.replaceAll(".", "").replaceAll(" ", ""),
      dataType: column === "Effective Date" ? "date" : "string",
      header: column.replace(/\w/, (firstLetter: string) =>
        firstLetter.toUpperCase()
      ),
      visible: true,
    };
    gridFields.push(field);
  });

  return {
    idField: "id",
    gridFields: [
      ...gridFields,
      {
        name: "id",
        dataType: "string",
        header: "Id",
        visible: false,
      },
    ],
  };
};

const convertDataType = (dataType: string) => {
  return dataTypeDictionary[dataType] != null
    ? dataTypeDictionary[dataType]
    : "TEXT";
};

interface ParameterValueFormComponentProps {
  mode?: "add" | "edit";
  parameterName: string;
  dataSourceValues?: CodePair[] | null;
  valueType: string;
  dataType: string;
  parameterType: string;
  purpose?: string | null;
  parameterValueType: string;
  lookupCodes?: CodePair[] | null;
  predefinedTable?: boolean | null;
  dataSource?: string | null;
  parameterId: string;
  parameterDescription?: string | null;
  isInvokedFromPop?: boolean;
  parameterValueRequired?: boolean | null;
  isFilterExpression?: boolean | null;
}

const colDefOverrides: ColDefOverride[] = [
  {
    field: "aggregation_level_description",

    colDef: { filter: "agSetColumnFilter" },
  },
  {
    field: "category_description",

    colDef: { filter: "agSetColumnFilter" },
  },
  {
    field: "data_type_description",

    colDef: { filter: "agSetColumnFilter" },
  },
  {
    field: "lookup_type_description",

    colDef: { filter: "agSetColumnFilter" },
  },
  {
    field: "field_name",

    colDef: { filter: "agTextColumnFilter" },
  },
  {
    field: "currency_type_description",

    colDef: { filter: "agSetColumnFilter" },
  },
];

export const ParameterValueForBulkEditFormComponent: FunctionComponent<
  ParameterValueFormComponentProps
> = ({
  mode,
  parameterName,
  dataSourceValues,
  valueType,
  dataType,
  parameterType,
  parameterValueType,
  lookupCodes,
  predefinedTable,
  dataSource,
  parameterId,
  parameterDescription,
  isInvokedFromPop,
  parameterValueRequired,
  isFilterExpression,
  purpose,
}) => {
  const theme = useTheme();

  const [{ value: fieldValue }, , { setValue: setFieldValue }] =
    useField(parameterId);

  useEffect(() => {
    if (fieldValue !== undefined && fieldValue !== null && fieldValue !== "")
      return;
    if (parameterValueType === "L" || parameterValueType === "B") {
      if (
        ((dataType === "C" && parameterType === "INP") ||
          parameterValueRequired) &&
        lookupCodes?.length
      ) {
        setFieldValue(lookupCodes![0].code);
      } else if (
        dataType === "N" &&
        parameterValueRequired &&
        parameterType === "INP"
      ) {
        setFieldValue(true);
      }
    } else if (
      (parameterValueType === "P" || parameterValueType === "R") &&
      parameterValueRequired &&
      dataSourceValues?.length
    ) {
      setFieldValue(dataSourceValues[0].code);
    } else if (
      parameterValueType === "V" &&
      parameterValueRequired &&
      parameterName === "Percentage Allowed"
    ) {
      setFieldValue("100");
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [
    parameterValueType,
    lookupCodes,
    dataSourceValues,
    parameterValueRequired,
    parameterName,
    parameterType,
    fieldValue,
    dataType,
  ]);

  const dataSourceTextFieldProps = useMemo<TextFieldProps>(
    () => ({
      label: !isInvokedFromPop ? (
        parameterName
      ) : (
        <>
          <Box
            component="span"
            sx={{ display: "inline-flex", alignItems: "center", gap: 0.5 }}
          >
            {`${parameterName}${parameterType === "OUTP" ? "(Output) " : ""}`}

            <Tooltip
              children={
                <span aria-hidden="true">
                  <InfoIcon
                    sx={{
                      color: theme.palette.info.main,
                    }}
                    size={16}
                  ></InfoIcon>
                </span>
              }
              title={parameterDescription}
            />
          </Box>
        </>
      ),
      variant: "outlined",
      required: parameterValueRequired ?? false,
    }),
    [
      isInvokedFromPop,
      parameterDescription,
      parameterName,
      parameterType,
      parameterValueRequired,
      theme.palette.info.main,
    ]
  );

  const [fields, setFields] = useState<DataDictionaryField[]>([]);
  const axiosFactory = useAxiosFactory();

  useEffect(() => {
    const abortController = new AbortController();

    const loadDataDictionaryFields = async () => {
      const axios = await axiosFactory.createAxiosInstance();
      const { data } = await axios.get<{
        data_dictionary_fields: DataDictionaryField[];
      } | null>("/solvasam-bff/v1/dataDictionaryFields", {
        signal: abortController.signal,
      });
      setFields(data?.data_dictionary_fields ?? []);
    };
    if (parameterValueType === "F") loadDataDictionaryFields();

    return () => abortController.abort();
  }, [axiosFactory, parameterValueType]);

  let valDataType = convertDataType(dataType);
  let tableValueSchema: DataGridMeta = { idField: "id", gridFields: [] };

  const ddxDataForFieldFormula =
    useContext(DdxDataContext)?.ddxDataForFieldFormula ?? defaultDdx;
  const ddxDataForFilterExpression =
    useContext(DdxDataContext)?.ddxDataForFilterExpression ?? defaultDdx;

  if (parameterValueType === "B") {
    valDataType = "BOOLEAN";
  }

  if (parameterValueType === "T") {
    valDataType = "TABLE";
    tableValueSchema = getSchema(dataSource ?? "");
  }

  return (
    <Fragment>
      {(() => {
        switch (parameterValueType) {
          case "C":
            return (
              <FormFieldGroup sx={{ flexDirection: "column" }}>
                <FormFormulaEditor
                  id={parameterId}
                  errors={[]}
                  sx={{ flexDirection: "column" }}
                  ddxData={
                    isFilterExpression
                      ? ddxDataForFilterExpression
                      : ddxDataForFieldFormula
                  }
                  purpose={
                    purpose === "VARIABLE_FORMULA"
                      ? "VARIABLE_FORMULA"
                      : "FIELD_FORMULA"
                  }
                  label={parameterName}
                  required={parameterValueRequired ?? false}
                ></FormFormulaEditor>
              </FormFieldGroup>
            );
          case "E":
            return (
              <Fragment>
                <FormExpressionBuilder
                  id={parameterId}
                  ddxProps={ddxDataForFilterExpression}
                  label={parameterName}
                  required={parameterValueRequired ?? false}
                >
                  <AddExpressionMenu />
                  <DeleteExpression />
                  <CopyExpression />
                  <PasteMenu />
                </FormExpressionBuilder>
              </Fragment>
            );
          case "L":
            return (
              <FormFieldGroup>
                <FormAutocomplete
                  fieldName={parameterId}
                  valueField="code"
                  labelField="description"
                  options={lookupCodes ?? []}
                  textFieldProps={dataSourceTextFieldProps}
                ></FormAutocomplete>
              </FormFieldGroup>
            );
          case "P":
          case "R":
            return (
              <FormFieldGroup>
                <FormAutocomplete
                  fieldName={parameterId}
                  valueField={"code"}
                  labelField={"description"}
                  options={dataSourceValues ?? []}
                  textFieldProps={dataSourceTextFieldProps}
                ></FormAutocomplete>
              </FormFieldGroup>
            );
          case "F":
            return (
              <FormFieldWithGrid
                fieldName={parameterId}
                labelField="display_name"
                valueField="field_name"
                textFieldProps={{
                  required: parameterValueRequired ?? false,
                  label: parameterName,
                }}
                meta={FieldsMeta}
                data={{
                  rowData: fields,
                }}
                colDefOverrides={colDefOverrides}
              ></FormFieldWithGrid>
            );
          case "M":
            return (
              <FormFieldGroup>
                <Stack sx={{ flex: "1 1 0px" }}>
                  <FormSelect
                    fieldName={parameterId}
                    label={parameterName}
                    labelId={undefined} //aria-labelledby takes precedence over aria-label; removing labelId avoids the bad computed name source
                    SelectDisplayProps={{ "aria-label": parameterName }} // applies aria-label directly to the role=combobox element.
                    labelField={"description"}
                    options={dataSourceValues ?? []}
                    valueField={"code"}
                    multiple
                    required={parameterValueRequired ?? false}
                  >
                    <DropdownTransferList
                      label={"Datasource List"}
                      autoFocusSearch
                    />
                  </FormSelect>
                </Stack>
              </FormFieldGroup>
            );
          case "V":
          case "B":
          case "T":
            return (
              <FormValueSelector
                valFieldId={parameterId}
                refFieldId={parameterId + "_reference_value"}
                valueTypeId={parameterId + "_value_type"}
                textFieldProps={dataSourceTextFieldProps}
                dataType={valDataType}
                lockValueType={
                  parameterType === "OUTP" || (predefinedTable ?? undefined)
                }
                valueType={valueType?.toLowerCase()}
                tableValueSchema={tableValueSchema ?? {}}
                isCalculated={
                  parameterType === "OUTP" || predefinedTable ? true : undefined
                }
                predefinedTable={predefinedTable}
                parameterValueType={parameterValueType}
              ></FormValueSelector>
            );
          default:
            return (
              <FormFieldGroup>
                <FormTextField
                  fieldName={parameterId}
                  label={parameterName}
                  variant="outlined"
                  required={parameterValueRequired ?? false}
                ></FormTextField>
              </FormFieldGroup>
            );
        }
      })()}
      {mode === "add" ? (
        <FormCustomDatePicker
          fieldName="effective_date"
          label="Effective Date"
          textFieldProps={{
            variant: "outlined",
          }}
        />
      ) : null}
    </Fragment>
  );
};

import { SxProps, Theme } from "@textile/mui";

import { CodePair } from "./common-types";
import {
  assignValueFieldName,
  stringifyJSONObject,
} from "./parameter-value-form.component";
import { CalculationBlockParameter } from "../calculations/calculations.types";
import { StepParameter } from "../priority-of-payments/priority-of-payments.types";

export const detailsContainerSx: SxProps<Theme> = (theme) => ({
  flex: "1 1 0",
  backgroundColor: theme.palette.grey[200],
  px: 1.5,
  borderRadius: "4px 4px 4px 0",
});

const INVALID_DATE = "Invalid Date";

export const formatDate = (
  utcDate: string,
  format?: "MM/DD/YYYY" | "M/D/YYYY" | "DD MMM YYYY"
) => {
  //if date is of type reference and has spaces in it, it should return the string.
  const invalidDateRegex = /[^\d\s]\s+\d+$/;

  if (!utcDate || invalidDateRegex.test(utcDate)) {
    return utcDate;
  }

  const date = new Date(utcDate);
  if (isNaN(date.getTime())) return utcDate;

  if (format === "MM/DD/YYYY") {
    return date.toLocaleDateString("en-US", {
      day: "2-digit",
      month: "2-digit",
      year: "numeric",
    });
  } else if (format === "M/D/YYYY") {
    return date.toLocaleDateString("en-US", {
      day: "numeric",
      month: "numeric",
      year: "numeric",
    });
  } else if (format === "DD MMM YYYY") {
    const currentLocale = navigator.language || "en-US";
    const monthNames = new Intl.DateTimeFormat(currentLocale, {
      month: "short",
    }).format(date);
    const day = String(date.getDate()).padStart(2, "0"); // Pad day with leading zero
    const year = date.getFullYear();
    return `${day} ${monthNames} ${year}`;
  } else {
    return date.toLocaleDateString("en-GB", {
      day: "numeric",
      month: "short",
      year: "numeric",
    });
  }
};

export const formatDateTime = (strDateTime: string) => {
  if (!strDateTime) return null;
  const date = new Date(strDateTime);
  if (date.toString() === INVALID_DATE) return strDateTime;
  return date.toLocaleString("sv-SE"); //format - yyyy-MM-dd HH:mm:ss
};

export const parseTableParameterValue = (tableValues: string[]) => {
  return tableValues?.map((i, j) => {
    const arr = JSON.parse(i);
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const obj: any = {};
    Object.keys(arr).forEach((key) => {
      const formatedKey = key.replaceAll(".", "").replaceAll(" ", "");
      obj[formatedKey] = arr[key];
    });
    obj["id"] = j;
    return obj;
  });
};

export const populateMissingDataSourceValues = (
  dataSourceMeta: string,
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  dataSourceValue: any[]
) => {
  const formattedMeta: string[] = dataSourceMeta?.split(";").map((val) => {
    return val.replaceAll(".", "").replaceAll(" ", "");
  });

  for (let index = 0; index < dataSourceValue?.length; index++) {
    const element = dataSourceValue[index];
    formattedMeta?.forEach((meta) => {
      element[meta] = element[meta] ?? " ";
    });
    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    const { id, ...rest } = element;
    dataSourceValue[index] = rest;
  }
  return dataSourceValue;
};

export const hydrateParameterBeforePopulate = (
  data: Partial<CalculationBlockParameter | StepParameter>
) => {
  if (data.parameter_value_type === "B" && data.boolean_value !== null) {
    data.description = data.boolean_value ? "Yes" : "No";
  }
  if (
    data.value_type?.toUpperCase() !== "REF" &&
    ["M"].includes(data?.parameter_value_type?.toUpperCase() ?? "")
  ) {
    data.string_value =
      typeof data.string_value === "string"
        ? (data.string_value
            ?.split(",")
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            ?.map((s) => s.replaceAll("'", "")) as any)
        : data.string_value;
  }
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  data.numeric_value = data.numeric_value?.toString() as any;
};

export const hydrateParameterBeforeSave = (
  data: Partial<CalculationBlockParameter | StepParameter>,
  dataSourceValues: CodePair[],
  lookup_codes: CodePair[]
) => {
  data.string_value = data.string_value ?? null;
  data.boolean_value = data.boolean_value ?? null;
  data.numeric_value =
    data.numeric_value?.toString() === "" ? null : data.numeric_value ?? null;
  data.field_name_value = data.field_name_value ?? null;
  data.date_time_value = data.date_time_value ?? null;
  data.reference_value = data.reference_value ?? null;
  data.formula_value = data.formula_value ?? null;
  data.applicability_value = data.applicability_value ?? null;

  data.description =
    data.value_type?.toUpperCase() !== "REF"
      ? data.numeric_value?.toString() ??
        data.string_value ??
        data.date_time_value?.toString() ??
        data.field_name_value ??
        ""
      : "";
  if (
    data.value_type?.toUpperCase() !== "REF" &&
    ["P", "M", "L"].includes(data?.parameter_value_type?.toUpperCase() ?? "")
  ) {
    if (Array.isArray(data.string_value)) {
      const descriptions: string[] = [];
      data.string_value.forEach((val) => {
        let selectedValue = dataSourceValues?.find((x) => x.code === val);
        selectedValue = !selectedValue
          ? lookup_codes?.find((x) => x.code === val)
          : selectedValue;
        if (selectedValue) {
          descriptions.push(selectedValue.description);
        }
      });
      data.string_value = data.string_value.join(",");
      data.description = descriptions.join(",");
    } else {
      let selectedValue = dataSourceValues?.find((x) =>
        x.code === data.string_value ? data.string_value : data.numeric_value
      );
      selectedValue = !selectedValue
        ? lookup_codes?.find((x) =>
            x.code === data.string_value
              ? data.string_value
              : data.numeric_value
          )
        : selectedValue;
      if (selectedValue) {
        data.description = selectedValue.description;
      }
    }
  } else if (data.parameter_value_type === "B") {
    data.description = data.boolean_value ? "Yes" : "No";
  } else if (data.parameter_value_type === "V") {
    data.description = !data.parameter_value_type
      ? (data[
          assignValueFieldName(data.parameter_value_type, data.data_type ?? "")
        ] as string)
      : data.string_value;
  } else if (data.parameter_value_type === "T") {
    if (data.table_value && data.table_value.length > 0) {
      data.description = "";
      data.table_value =
        data.table_value && data.data_source
          ? populateMissingDataSourceValues(data.data_source, data.table_value)
          : data.table_value;

      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      data.table_value = data.table_value.filter((ele: any) => {
        const nonEmptyValues = Object.values(ele).filter((val) => val !== "");
        return nonEmptyValues.length > 0;
      });

      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      data.table_value.map((ele: any) => {
        data.description += Object.values(ele).join(";") + ";|";
        return ele;
      });

      data.table_value = stringifyJSONObject(data?.table_value ?? []);
    }
  }
};

/**
 * Checks if a given parameter is valid.
 * This function checks for null, undefined, and their string representations ("null" and "undefined"),
 * as these values can be received from URL parameters.
 */
export const isParameterValid = (parameter: string | null | undefined) => {
  return !(
    parameter === null ||
    parameter === undefined ||
    parameter === "null" ||
    parameter === "undefined"
  );
};

