        &gt;
          {data.value}
        &lt;/Box&gt;
      ) : [&quot;E&quot;].includes(data?.parameter_value_type) &amp;&amp;
        data.value !== &quot;{Not Specified}&quot; ? (
        // expression builder
        &lt;Stack
          direction=&quot;row&quot;
          justifyContent=&quot;space-between&quot;
          spacing={1}
          alignItems=&quot;flex-start&quot;
