          parameter.value_type?.toUpperCase() === "REF"
            ? parameter.reference_value
            : null;
        record[parameter.id + "_value_type"] = parameter.value_type ?? null;
      }
    });
    record["calculation_block_parameters"] =
      data.calculation_block_parameters ?? [];
    return record;
  }, []);

  const handleOnBeforeSave = useCallback(async (data: BlockParameters) => {
    const requests = [] as UpdateCalculationBlockParameterRequest[];
    data.calculation_block_parameters?.forEach((parameter) => {
      const fieldName = assignValueFieldName(
        parameter.parameter_value_type ?? "",
        parameter.data_type
      );

      parameter[fieldName] = data[parameter.id];

      if (
        ["V", "B", "T"].includes(
          parameter?.parameter_value_type?.toUpperCase() ?? ""
        ) &&
        data[parameter.id + "_value_type"] &&
        data[parameter.id + "_value_type"].toUpperCase() === "REF" &&
        data[parameter.id + "_reference_value"] !== undefined
      ) {
        parameter.reference_value = data[parameter.id + "_reference_value"];
        parameter.value_type = data[parameter.id + "_value_type"];
      }

      if (
        ["V", "B", "T"].includes(
          parameter?.parameter_value_type?.toUpperCase() ?? ""
        ) &&
        data[parameter.id + "_value_type"] &&
        data[parameter.id + "_value_type"].toUpperCase() === "VAL"
      ) {
        parameter.value_type = data[parameter.id + "_value_type"];
      }

      if (parameter.parameter_value_type === "C" && !parameter.formula_value) {
        parameter.formula_value = {
          ddx: null,
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
        } as any;
      }
      if (
        parameter.parameter_value_type === "E" &&
        !parameter.applicability_value
      ) {
        parameter.applicability_value = {
          ddx: null,
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
        } as any;
      }

      hydrateParameterBeforeSave(
        parameter,
        parameter.data_source_values ?? [],
        parameter.lookup_codes ?? []
      );
      parameter.lookup_codes = [];
      parameter.data_source_values = [];
      requests.push({ calculation_block_parameter: parameter });
    });
    return { requests };
  }, []);

  const handleOnSubmitComplete = useCallback(() => {
    setParameters([]);
  }, []);

  const handleOnClose = useCallback(() => {
    setParameters([]);
  }, []);

  return (
    <DdxDataContext.Provider
      value={{
        ddxDataForFieldFormula: ddxDataForFieldFormula,
        ddxDataForFilterExpression: ddxDataForFilterExpression,
      }}
    >
      <AsyncFormDialog
        dataSource={parameterValueDataSource}
        title={"Edit Calculation Block Parameters"}
        fullScreen={fullScreen}
        enableFullScreenToggle={true}
        fullWidth
        onBeforePopulate={handleOnBeforePopulate}
        onBeforeSave={handleOnBeforeSave}
        onSubmitComplete={handleOnSubmitComplete}
        validationSchema={validationSchema}
        draggable={true}
        PaperProps={{ sx: getDialogResizePaperPropsSx("lg") }}
        defaultData={{} as BlockParameters}
        onClose={handleOnClose}
      >
        {parameters?.map((parameter: CalculationBlockParameter) => (
          <ParameterValueForBulkEditFormComponent
            key={parameter.id}
            parameterName={`${parameter.order}. ${parameter.parameter_name}`}
            dataSourceValues={parameter.data_source_values}
            valueType={parameter.value_type}
            dataType={parameter.data_type}
            parameterType={parameter.type}
            purpose={parameter.purpose}
            parameterValueType={parameter.parameter_value_type}
            lookupCodes={parameter.lookup_codes}
            predefinedTable={parameter.predefined_table}
            dataSource={parameter.data_source}
            parameterId={parameter.id}
            parameterValueRequired={!!parameter.value_required}
            isFilterExpression={
              parameters?.findIndex((p) => p.parameter_value_type === "F") > -1
                ? true
