import { useSelectedPortfolioId } from &quot;../../hooks/selected-portfolio-id.hook&quot;;
import { FormCustomDatePicker } from &quot;./form-custom-date-picker.component&quot;;

interface FormTableGridProps {
  id: string;
  tableValueSchema?: DataGridMeta;
  label: React.ReactNode;
}

const agGridCustomSx: SxProps = {
  &quot;.ag-cell-wrapper&quot;: {
    paddingTop: 0.25,
    paddingLeft: 1.25,
  },
  &quot;.ag-cell&quot;: {
    padding: 0.75,
  },
};

const tableGridSxProps: SxProps = {
  height: &quot;400px&quot;,
  flexGrow: 1,
  ...agGridCustomSx,
};

export const CustomCellRenderer = (params: ICellRendererParams) =&gt; {
  return (
    &lt;Box
      sx={{
        borderRadius: &quot;4px&quot;,
        border: &quot;1px solid rgba(0, 0, 0, 0.23)&quot;,
        py: 0.25,
        px: 1,
        &quot;&amp;:hover&quot;: {
          borderColor: &quot;rgba(0, 0, 0, 0.87)&quot;,
        },
        height: &quot;100%&quot;,
      }}
    &gt;
      &lt;Typography
        variant=&quot;inherit&quot;
        noWrap
        sx={{
          overflow: &quot;hidden&quot;,
          textOverflow: &quot;ellipsis&quot;,
        }}
      &gt;
        {params.valueFormatted}
