  const { setFieldValue } = useFormikContext();
  const [{ value: tableValues }] = useField(id);
  const [disableDelete, setDisableDelete] = useState&lt;boolean&gt;(true);
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const [selectedTableRecords, setSelectedRecords] = useState&lt;any&gt;([]);
  const [colDefOverrides, setColDefOverrides] = useState&lt;ColDefOverride[]&gt;([]);

  useEffect(() =&gt; {
    if (tableValueSchema?.gridFields) {
      const overrides = tableValueSchema.gridFields.map((field) =&gt; ({
        field: field.name,
        colDef: {
          editable: true,
          cellRenderer: CustomCellRenderer,
        },
      }));
      setColDefOverrides(overrides);
    }
  }, [tableValueSchema?.gridFields]);

  const handleAdd = useCallback(() =&gt; {
    const newRecord: Record&lt;string, string&gt; = {};

    tableValueSchema?.gridFields?.forEach((field) =&gt; {
      newRecord[field.name] = field.name === &quot;id&quot; ? uuid() : &quot;&quot;;
    });

    setFieldValue(id, [...(tableValues ?? []), newRecord]);
  }, [id, setFieldValue, tableValueSchema?.gridFields, tableValues]);

  const handleDelete = useCallback(() =&gt; {
    if (selectedTableRecords.length &gt; 0)
      setFieldValue(id, [
        ...tableValues.filter(
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          (value: any) =&gt;
