  };
}

export const FormValueField: FunctionComponent&lt;FormValueFieldProps&gt; = ({
  id,
  dataType,
  textFieldProps,
  tableValueSchema,
  textFieldInputProps,
}) =&gt; {
  const { label, variant, required, disabled } = textFieldProps;
  switch (dataType) {
    case &quot;BOOLEAN&quot;:
      return (
        &lt;FormFieldGroup&gt;
          &lt;FormAutocomplete
            fieldName={id}
            valueField={&quot;id&quot;}
            labelField={&quot;value&quot;}
            options={[
              { id: true, value: &quot;Yes&quot; },
              { id: false, value: &quot;No&quot; },
            ]}
            textFieldProps={textFieldProps}
          &gt;&lt;/FormAutocomplete&gt;
        &lt;/FormFieldGroup&gt;
      );
    case &quot;DATE&quot;:
      return (
        &lt;FormFieldGroup sx={{ flexDirection: &quot;column&quot; }}&gt;
          &lt;FormCustomDatePicker
            fieldName={id}
            label={label}
            textFieldProps={{
              ...textFieldProps,
              helperText: &quot;&quot;,
            }}
          &gt;&lt;/FormCustomDatePicker&gt;
        &lt;/FormFieldGroup&gt;
      );
    case &quot;CURRENCY&quot;:
    case &quot;NUMERIC&quot;:
    case &quot;PERCENT&quot;:
      return (
        &lt;FormFieldGroup sx={{ gap: 0.5 }}&gt;
