import {
  DataGridActionViewSource,
  ddxFormatter,
  DownloadActionMenu,
  formatFormula,
  getDialogResizePaperPropsSx,
  RuleDisplayComponent,
  useDdxValues,
} from "@solvasam/bizcomponents";
import { GridApi, GridReadyEvent, ICellRendererParams } from "@textile/ag-grid";
import {
  AsyncDataGridPanel,
  AsyncFormDialog,
  ColDefOverride,
  DataGridActionRefresh,
  DataGridAsyncDialogAction,
  DataGridDataServiceSource,
  DataGridPanel,
  DataGridQuickSearch,
  FormDataServiceSource,
  useRefreshToken,
} from "@textile/biz-components";
import { EditIcon, useStaticAppContext } from "@textile/common";
import { Box, Stack, SxProps, useMediaQuery, useTheme } from "@textile/mui";
import * as yup from "yup";
import {
  Fragment,
  FunctionComponent,
  useCallback,
  useMemo,
  useRef,
  useState,
} from "react";
import { useParams } from "react-router-dom";

import { CalculationGroupsProps } from "./calculation-group-grid.component";
import {
  assignValueFieldName,
  DdxDataContext,
  getSchema,
  hydrateParameterBeforePopulate,
  hydrateParameterBeforeSave,
  parseTableParameterValue,
} from "../../common";
import { AppRouteParams } from "../../screen.types";
import { ParameterValueForBulkEditFormComponent } from "../../common/parameter-value-for-bulk-edit-form.component";
import { CalculationBlockParameter } from "../calculations.types";
import { useRefreshNeedReviewOnParentGrid } from "../../common/refresh-need-review.hook";

interface CalculationBlockParameterBulkEditFormProps {
  portfolioId: string;
  modelId: string;
  groupId: string;
  blockId: string;
}

type UpdateCalculationBlockParameterRequest = {
  calculation_block_parameter?: CalculationBlockParameter;
};

interface BlockParameters {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  [key: string]: any;
  calculation_block_parameters?: CalculationBlockParameter[];
}

export const CalculationBlockParameterBulkEditForm: FunctionComponent<
  Partial<CalculationBlockParameterBulkEditFormProps>
> = ({ portfolioId, modelId, groupId, blockId }) => {
  const theme = useTheme();
  const fullScreen = useMediaQuery(theme.breakpoints.down("md"));
  const ddxDataForFieldFormula = useDdxValues("VARIABLE_FORMULA");
  const ddxDataForFilterExpression = useDdxValues("FILTER_EXPRESSION");
  const [parameters, setParameters] = useState<
    CalculationBlockParameter[] | null
  >([]);

  const parameterValueDataSource = useMemo<FormDataServiceSource>(
    () => ({
      idField: "id",
      mode: "edit",
      get: {
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/calculationGroups/${groupId}/blocks/${blockId}/parameters`,
        queryParams: {
          "paging.filter": `hydrate="Full"`,
        },
      },
      save: {
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/calculationGroups/${groupId}/blocks/${blockId}/parameters:batchUpdate`,
        method: "patch",
      },
    }),
    [blockId, portfolioId, groupId, modelId]
  );

  const validationSchema = useMemo(() => {
    const shape: Record<string, yup.AnySchema> = {};
    parameters?.forEach((parameter) => {
      if (
        !!parameter.value_required &&
        parameter.parameter_value_type === "E"
      ) {
        shape[parameter.id] = yup
          .mixed()
          .nullable()
          .required(`${parameter.parameter_name} is required`);
      }
      if (
        ["V", "B", "T"].includes(
          parameter?.parameter_value_type?.toUpperCase() ?? ""
        )
      ) {
        shape[parameter.id + "_reference_value"] = yup.mixed().nullable();
        shape[parameter.id + "_value_type"] = yup.mixed().nullable();
      }
    });
    return yup.object().shape(shape);
  }, [parameters]);

  const handleOnBeforePopulate = useCallback(async (data: BlockParameters) => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const record: { [key: string]: any } = {};
    setParameters(data.calculation_block_parameters ?? []);
    data.calculation_block_parameters?.forEach((parameter) => {
      hydrateParameterBeforePopulate(parameter);
      const tableValue = parameter?.table_value
        ? parseTableParameterValue(parameter?.table_value as string[])
        : [];

      const fieldName = assignValueFieldName(
        parameter.parameter_value_type ?? "",
        parameter.data_type
      );

      record[parameter.id] =
        fieldName === "table_value" ? tableValue : parameter[fieldName] ?? null;

      if (
        ["V", "B", "T"].includes(
          parameter?.parameter_value_type?.toUpperCase() ?? ""
        )
      ) {
        record[parameter.id + "_reference_value"] =
          parameter.value_type?.toUpperCase() === "REF"
            ? parameter.reference_value
            : null;
        record[parameter.id + "_value_type"] = parameter.value_type ?? null;
      }
    });
    record["calculation_block_parameters"] =
      data.calculation_block_parameters ?? [];
    return record;
  }, []);

  const handleOnBeforeSave = useCallback(async (data: BlockParameters) => {
    const requests = [] as UpdateCalculationBlockParameterRequest[];
    data.calculation_block_parameters?.forEach((parameter) => {
      const fieldName = assignValueFieldName(
        parameter.parameter_value_type ?? "",
        parameter.data_type
      );

      parameter[fieldName] = data[parameter.id];

      if (
        ["V", "B", "T"].includes(
          parameter?.parameter_value_type?.toUpperCase() ?? ""
        ) &&
        data[parameter.id + "_value_type"] &&
        data[parameter.id + "_value_type"].toUpperCase() === "REF" &&
        data[parameter.id + "_reference_value"] !== undefined
      ) {
        parameter.reference_value = data[parameter.id + "_reference_value"];
        parameter.value_type = data[parameter.id + "_value_type"];
      }

      if (
        ["V", "B", "T"].includes(
          parameter?.parameter_value_type?.toUpperCase() ?? ""
        ) &&
        data[parameter.id + "_value_type"] &&
        data[parameter.id + "_value_type"].toUpperCase() === "VAL"
      ) {
        parameter.value_type = data[parameter.id + "_value_type"];
      }

      if (parameter.parameter_value_type === "C" && !parameter.formula_value) {
        parameter.formula_value = {
          ddx: null,
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
        } as any;
      }
      if (
        parameter.parameter_value_type === "E" &&
        !parameter.applicability_value
      ) {
        parameter.applicability_value = {
          ddx: null,
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
        } as any;
      }

      hydrateParameterBeforeSave(
        parameter,
        parameter.data_source_values ?? [],
        parameter.lookup_codes ?? []
      );
      parameter.lookup_codes = [];
      parameter.data_source_values = [];
      requests.push({ calculation_block_parameter: parameter });
    });
    return { requests };
  }, []);

  const handleOnSubmitComplete = useCallback(() => {
    setParameters([]);
  }, []);

  const handleOnClose = useCallback(() => {
    setParameters([]);
  }, []);

  return (
    <DdxDataContext.Provider
      value={{
        ddxDataForFieldFormula: ddxDataForFieldFormula,
        ddxDataForFilterExpression: ddxDataForFilterExpression,
      }}
    >
      <AsyncFormDialog
        dataSource={parameterValueDataSource}
        title={"Edit Calculation Block Parameters"}
        fullScreen={fullScreen}
        enableFullScreenToggle={true}
        fullWidth
        onBeforePopulate={handleOnBeforePopulate}
        onBeforeSave={handleOnBeforeSave}
        onSubmitComplete={handleOnSubmitComplete}
        validationSchema={validationSchema}
        draggable={true}
        PaperProps={{ sx: getDialogResizePaperPropsSx("lg") }}
        defaultData={{} as BlockParameters}
        onClose={handleOnClose}
      >
        {parameters?.map((parameter: CalculationBlockParameter) => (
          <ParameterValueForBulkEditFormComponent
            key={parameter.id}
            parameterName={`${parameter.order}. ${parameter.parameter_name}`}
            dataSourceValues={parameter.data_source_values}
            valueType={parameter.value_type}
            dataType={parameter.data_type}
            parameterType={parameter.type}
            purpose={parameter.purpose}
            parameterValueType={parameter.parameter_value_type}
            lookupCodes={parameter.lookup_codes}
            predefinedTable={parameter.predefined_table}
            dataSource={parameter.data_source}
            parameterId={parameter.id}
            parameterValueRequired={!!parameter.value_required}
            isFilterExpression={
              parameters?.findIndex((p) => p.parameter_value_type === "F") > -1
                ? true
                : false
            }
          />
        ))}
      </AsyncFormDialog>
    </DdxDataContext.Provider>
  );
};

