}

const SubmitButton: FunctionComponent&lt;SubmitButtonProps&gt; = ({
  isLoading,
  children,
  component,
  disabled,
  ...props
}) =&gt; {
  const { isSubmitting } = useFormikContext();

  const ButtonComponent = component ?? Button;

  return (
