/**
 * The `AsyncFormDialog` is a customizable dialog designed to handle asynchronous form submissions and data management. It integrates with Formik for form handling and
 * provides a structured way to manage loading states, validation, and user interactions. This component is particularly useful for CRUD operations and can be easily
 * extended with additional action components.
 *
 * ## Features
 * &gt; - __Dependency on Parent Context__: The component relies on several hooks, which must be wrapped in their corresponding parent context providers:
 *     - useFormikContext
 *     - useAsyncActionDialog
 *     - useActionDialog
 *
 * - __Asynchronous Data Handling__: Supports loading and submitting data asynchronously.
 * - __Customizable Buttons__: Includes submit and close buttons that can be customized with labels and styles.
 * - __Dynamic Content__: Allows for rendering additional action components and children within the dialog.
 * - __Integration with Formik__: Utilizes Formik for form management, enabling validation and submission handling.
 * - __Loading Indicators__: Displays loading indicators during form submission to inform users of ongoing processes.
 * - __Notification Support__: Integrates with notification components to provide user feedback on actions.
 *
 * ## Exports
 *
 * #### Components
 * - `AsyncFormDialog`: Main component that handles asynchronous form submissions within a dialog. It integrates with Formik for form management and provides a structured way to manage loading states, validation, and user interactions.
 * - `ProgressOrDivider`: Renders either a loading indicator or a divider based on the `isLoading` prop. It integrates with Formik&#39;s context to determine if the form is currently submitting.
 *
 * #### Interfaces
 * - `AsyncFormDialogProps`: Defines the props that can be passed to the `AsyncFormDialog` component. It extends the standard `DialogProps` to include additional properties specific to the asynchronous form dialog.
 * - `CloseButtonProps`: Defines the props for the `CloseButton` component, which represents a button that closes the dialog.
 * - `ProgressOrDivider`: Defines the props for the `ProgressOrDivider` component, which conditionally displays a loading indicator or a divider based on the loading state.
 * - `SubmitButtonProps`: Defines the props for the `SubmitButton` component, which is a wrapper around the Material UI Button.
 * It extends the standard `ButtonProps` to include additional properties specific to the submit button.
 */
export function AsyncFormDialog&lt;
  R extends FormikValues = Record&lt;string, unknown&gt;,
&gt;({
  dataSource,
  defaultData,
  title,
  submitButtonLabel = &quot;Save&quot;,
  closeButtonLabel = &quot;Cancel&quot;,
  onClose,
  onSubmitComplete,
  onBeforePopulate,
  onBeforeSave,
  buttonOrder = &quot;cancelok&quot;,
  validationSchema,
  children,
  extraActionComponents,
  extraActionComponentsSx,
  extraSlotProps = {},
  extraSlots = {},
  submitButtonDisabled = false,
  sx,
  PaperProps,
  enableFullScreenToggle = false,
  fullScreen,
  ...other
}: AsyncFormDialogProps&lt;R&gt;) {
  const [isLoading, setIsLoading] = useState(false);
  const [submitButtonElement, setSubmitButtonElement] =
    useState&lt;HTMLElement | null&gt;(null);
  const { closeDialog, completeDialogAction, open, targetIds } =
    useActionDialog();
  const { loadOnOpen } = useAsyncActionDialog();
  const [isFullScreen, setIsFullScreen] = useState(fullScreen ?? false);

  const handleOnSubmitComplete = (response: SaveResponse) =&gt; {
    // Invoke the completeDialogAction callback passed in from the ActionDialogContext wrapped around this dialog.
    // This will trigger the action&#39;s UI update.
    // Note that the finalTargetIds are not necessarily the same as the selectedTargetIds.
    // In case of an Add operation, for example, finalTargetIds will contain the IDs of newly added items which are different
    // from the currently selected items.
    completeDialogAction(response.targetIds);
    onSubmitComplete?.(response);
  };

  const extraActionsBoxSx: SxProps&lt;Theme&gt; = {
    p: 1,
    display: &quot;flex&quot;,
    flexDirection: &quot;row&quot;,
    flex: &quot;1 1 0px&quot;,
    gap: 2,
    ml: 1.5,
    ...extraActionComponentsSx,
  };

  const handleOnCloseButtonClick = () =&gt; {
    closeDialog();
    onClose?.();
    setIsFullScreen(false);
  };

  const handleOnClose = (event: object, reason: string) =&gt; {
    // We want to allow closing the dialog box through Esc button,
    // but we want to prevent it from closing on clicking somewhere in the background.
    if (reason !== &quot;backdropClick&quot;) {
      closeDialog();
      onClose?.();
      setIsFullScreen(false);
    }
  };

  const handleSubmitButtonClick = (event: MouseEvent&lt;HTMLElement&gt;) =&gt; {
    setSubmitButtonElement(event.currentTarget);
  };

  const handleIsLoadingChange = useCallback(
    (isLoading: boolean) =&gt; {
      setIsLoading(isLoading);
    },
    [setIsLoading],
  );

  // Inject the selected target Ids into the data source object passed to the form.
  // This should be interpreted by the registered FormDataProvider to query and post
  // data for the specific entities being selected.
  // Note that when AsyncFormDialog is used in CRUD operations, there will only be one selected id.
  const formDataSource = useMemo(() =&gt; {
    return {
      ...dataSource,
      targetIds: targetIds,
    };
  }, [dataSource, targetIds]);

  const AsyncFormDialogSubmitButton = (
    &lt;SubmitButton
      isLoading={isLoading}
      disabled={submitButtonDisabled}
      onClick={handleSubmitButtonClick}
      {...(extraSlots.submitButton
        ? { component: extraSlots.submitButton }
        : {})}
    &gt;
      {submitButtonLabel}
    &lt;/SubmitButton&gt;
  );
  const AsyncFormDialogCloseButton = (
    &lt;CloseButton onClick={handleOnCloseButtonClick}&gt;
      {closeButtonLabel}
    &lt;/CloseButton&gt;
  );

  // Decide the order of submit-close button based on the buttonOrder prop.
  const ActionButtons =
    buttonOrder === &quot;okcancel&quot; ? (
      &lt;Fragment&gt;
        {AsyncFormDialogSubmitButton}
        {AsyncFormDialogCloseButton}
      &lt;/Fragment&gt;
    ) : (
      &lt;Fragment&gt;
        {AsyncFormDialogCloseButton}
        {AsyncFormDialogSubmitButton}
      &lt;/Fragment&gt;
    );

  const Wrapper = extraSlots.wrapper ?? Fragment;
  const wrapperProps = extraSlotProps.wrapper ?? {};
  const dialogSx = {
    &quot;&amp; .MuiDialog-paperScrollPaper&quot;: { overflowY: &quot;hidden&quot; },
    ...sx,
  };

  return (
    &lt;Dialog
      sx={dialogSx}
      PaperProps={isFullScreen ? undefined : PaperProps}
      onClose={handleOnClose}
      open={open}
      fullScreen={isFullScreen}
      {...other}
    &gt;
      &lt;NotificationProvider&gt;
        &lt;NotificationMessageAnnouncer&gt;
          &lt;Form&lt;R&gt;
            dataSource={formDataSource}
            defaultData={defaultData}
            loadOnMount={loadOnOpen}
            confirmationPopoverAnchorElement={submitButtonElement}
            onSubmitComplete={handleOnSubmitComplete}
            onIsLoadingChange={handleIsLoadingChange}
            validationSchema={validationSchema}
            onBeforePopulate={onBeforePopulate}
            onBeforeSave={onBeforeSave}
            sx={formSx}
          &gt;
            &lt;Wrapper {...wrapperProps}&gt;
              &lt;DialogTitle height={64} display={&quot;flex&quot;}&gt;
                {title}
                &lt;Box sx={shimBox} /&gt;
                {enableFullScreenToggle ? (
                  &lt;IconButton
                    sx={closeButtonSx}
                    aria-label={
                      isFullScreen ? &quot;Exit full screen&quot; : &quot;Enter full screen&quot;
                    }
                    onClick={() =&gt; setIsFullScreen((prev) =&gt; !prev)}
                    size=&quot;small&quot;
                  &gt;
                    {isFullScreen ? (
                      &lt;CollapseIcon size={20} /&gt;
                    ) : (
                      &lt;ExpandIcon size={20} /&gt;
                    )}
                  &lt;/IconButton&gt;
                ) : null}
                &lt;IconButton
                  sx={closeButtonSx}
                  aria-label=&quot;close&quot;
                  onClick={handleOnCloseButtonClick}
                &gt;
                  &lt;CloseIcon size={20} /&gt;
                &lt;/IconButton&gt;
              &lt;/DialogTitle&gt;
              &lt;Box&gt;
                {isLoading ? &lt;ProgressOrDivider isLoading={isLoading} /&gt; : null}
              &lt;/Box&gt;
              &lt;DialogContent
                sx={isFullScreen ? { height: &quot;100vh&quot; } : undefined}
              &gt;
                &lt;DialogContentText sx={dialogContentTextSx}&gt;
                  &lt;Box sx={boxSx}&gt;{children}&lt;/Box&gt;
                &lt;/DialogContentText&gt;
              &lt;/DialogContent&gt;
              &lt;Divider&gt;&lt;/Divider&gt;
              &lt;NotificationBanner&gt;&lt;/NotificationBanner&gt;
              &lt;Box sx={actionsBoxSx}&gt;
                &lt;Box sx={extraActionsBoxSx}&gt;{extraActionComponents}&lt;/Box&gt;
                &lt;Box sx={shimBox}&gt;&lt;/Box&gt;
                &lt;DialogActions&gt;{ActionButtons}&lt;/DialogActions&gt;
              &lt;/Box&gt;
            &lt;/Wrapper&gt;
          &lt;/Form&gt;
        &lt;/NotificationMessageAnnouncer&gt;
      &lt;/NotificationProvider&gt;
    &lt;/Dialog&gt;
  );
}

