// The following component marks all fields of its containing form as &quot;touched&quot; on submit.
// Addresses issue https://github.com/formium/formik/issues/445
const FormikPatchTouched: FunctionComponent = () =&gt; {
  const { errors, setFieldTouched, isSubmitting, isValidating } =
    useFormikContext();

  useEffect(() =&gt; {
    if (isSubmitting &amp;&amp; !isValidating) {
      for (const path of Object.keys(flatten(errors))) {
        setFieldTouched(path, true, false);
      }
    }
  }, [isSubmitting, isValidating, errors, setFieldTouched]);

  return null;
};

