interface FormValidateFieldProps {
  children?: ReactNode;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  validationSchema?: any;
}

/**
 * We implement custom field-level validation to replace the inefficient Formik&#39;s
 * default validate-the-whole-form-on-each-key-stroke validation
 */
export const FormValidateField: FunctionComponent&lt;FormValidateFieldProps&gt; = ({
  validationSchema,
  children,
}) =&gt; {
  /**
   * Implement our own custom field-level validation function to replace Formik&#39;s
   * innefficient validate-the-whole-form-on-each-key-stroke validation.
   */
  const validateField: FormValidateFieldFunc = useCallback(
    (field, values) =&gt; {
      // Use Yup&#39;s validation schema to perform client side validation for the given field.
      if (validationSchema) {
        if (field) {
          return { [field]: validationSchema?.validateSyncAt?.(field, values) };
        }
      }

      return {};
    },
    [validationSchema],
  );

  return (
    &lt;FormValidateFieldProvider validateField={validateField}&gt;
      {children}
    &lt;/FormValidateFieldProvider&gt;
  );
};

