        dataSource,
        confirmationPromptContinueValues,
        OperationConfirmation.OperationConfirmed,
      );

      onSubmitComplete?.(response ?? null);
    } catch (error) {
      if (isOperationError(error)) {
        const formErrors = filterFieldErrorsFromOperationError(
          error,
          confirmationPromptContinueValues,
        );

        if (formErrors) {
          formErrors.forEach(({ message }) =&gt; {
            messageAnnouncer.error(`Failed to save form data: ${message}`);
          });
        }
      } else {
