            Cancel
          &lt;/Button&gt;
          &lt;Button
            onClick={onConfirmationPromptContinueClick}
            variant=&quot;contained&quot;
          &gt;
            Proceed
          &lt;/Button&gt;
        &lt;/DialogActions&gt;
      &lt;/Dialog&gt;
    &lt;/&gt;
  );
}

const isErrorOperationItem = ({
  severity = OperationSeverity.Info,
}: OperationItem) =&gt; {
  return severity &gt;= OperationSeverity.Error;
};

const isConfirmationRequiredOperationItem = ({
  severity = OperationSeverity.Info,
}: OperationItem) =&gt; {
  return (
    severity &gt; OperationSeverity.Info &amp;&amp;
    severity &lt;= OperationSeverity.ConfirmationRequired
  );
};

const isFieldErrorOperationItem = (
  { subject }: OperationItem,
  formValues: Record&lt;string, unknown&gt;,
) =&gt; {
  return subject !== undefined &amp;&amp; formValues.hasOwnProperty(subject);
};

const hasOperationItemMessage = ({ message }: OperationItem) =&gt; {
  return message !== undefined &amp;&amp; message !== &quot;&quot;;
};

/**
 * Given an Operation Error, collect the form field errors.
 */
export function collectFieldErrorsFromOperationError&lt;
  R extends FormikValues = Record&lt;string, unknown&gt;,
&gt;(operationError: OperationError, formValues: R): FormikErrors&lt;R&gt; | null {
  const fieldErrorOperationItems = operationError.operationResult.filter(
    (operationItem) =&gt; {
      const isError = isErrorOperationItem(operationItem);
      const isFieldError = isFieldErrorOperationItem(operationItem, formValues);
      const hasErrorMessage = hasOperationItemMessage(operationItem);

      return isError &amp;&amp; isFieldError &amp;&amp; hasErrorMessage;
    },
  );

  if (fieldErrorOperationItems.length === 0) {
    return null;
  }

  const fieldErrors = fieldErrorOperationItems.reduce(
    (errors: FormikErrors&lt;R&gt;, { message, subject }) =&gt; {
      const updatedError: FormikErrors&lt;R&gt; = {
        ...errors,
        ...(subject ? { [subject]: message } : {}),
      };

      return updatedError;
    },
    {},
  );

  return fieldErrors;
}

/**
 * Given an Operation Error, filters out field specific errors.
 */
export function filterFieldErrorsFromOperationError&lt;
  R extends FormikValues = Record&lt;string, unknown&gt;,
&gt;(operationError: OperationError, formValues: R) {
  const operationItems = operationError.operationResult.filter(
    (operationItem) =&gt; {
      const isError = isErrorOperationItem(operationItem);
      const isNotFieldError = !isFieldErrorOperationItem(
        operationItem,
        formValues,
      );
      const hasErrorMessage = hasOperationItemMessage(operationItem);

      return isError &amp;&amp; isNotFieldError &amp;&amp; hasErrorMessage;
    },
  );

  if (operationItems.length === 0) {
    return null;
  }

  return operationItems;
}

/**
 * Check if the Operation Error contains a warning with no form field.
 * This would be an operation confirmation prompt message.
 */
export function getConfirmationMessageFromOperationError&lt;
  R extends FormikValues = Record&lt;string, unknown&gt;,
&gt;(
  operationError: OperationError,
  formValues: R,
): { message: string | null; subject: string | null } {
  const { message, subject } =
    operationError.operationResult.find((operationItem) =&gt; {
      const isConfirmationRequired =
        isConfirmationRequiredOperationItem(operationItem);
      const isNotFieldConfirmation = !isFieldErrorOperationItem(
        operationItem,
        formValues,
      );
      const hasConfirmationMessage = hasOperationItemMessage(operationItem);

      return (
        isConfirmationRequired &amp;&amp;
        isNotFieldConfirmation &amp;&amp;
        hasConfirmationMessage
      );
    }) ?? {};

  return {
    message: message ?? null,
    subject: subject ?? null,
  };
}
