            });
        } else {
          messageAnnouncer.error(
            `Failed to load form data: ${error instanceof Error ? error.message : error}`,
          );
        }
      } finally {
        onIsLoadingChange?.(false);
      }
    }
  };

  useEffect(() =&gt; {
    const abortController = new AbortController();

    if (initialValuesLoaded === false) {
      populateForm(abortController);
    }

    return () =&gt; {
      abortController.abort();
    };
  }, [
    loadOnMount,
    defaultData,
    dataService,
    dataSource,
    onIsLoadingChange,
    onBeforePopulate,
    messageAnnouncer,
  ]);

  const onSubmit = useCallback(
    async (formValues: R, { setErrors, setSubmitting }: FormikHelpers&lt;R&gt;) =&gt; {
      // Clone the data in case we have an onBeforeSave interceptor.
      // We don&#39;t want to mutate the original values object passed in by Formik.
      // The purpose of onBeforeSave is to mod the values sent to the server,
      // not the values of the form itself.
      let values = cloneDeep(formValues);

      try {
        if (onBeforeSave) {
          const onBeforeSaveResult = await onBeforeSave(values);

          // Explicitly cancel if we are asked to do so from within onBeforeSave.
          if (onBeforeSaveResult === false) {
            return;
          }

          // If the resolved value is not a boolean false then it
          // must be the new values object.
          values = onBeforeSaveResult;
        }

        // Save data to the data source.
        const response = await dataService.saveData(
          dataSource,
          values,
          OperationConfirmation.NeedConfirmation,
        );

        onSubmitComplete?.(response ?? null);
      } catch (error) {
        if (isOperationError(error)) {
          const fieldErrors = collectFieldErrorsFromOperationError(
            error,
            formValues,
          );
          const formErrors = filterFieldErrorsFromOperationError(
            error,
            formValues,
          );
          const operationConfirmationPrompt =
            getConfirmationMessageFromOperationError(error, formValues);

          if (fieldErrors) {
            setErrors(fieldErrors);
          }

          if (formErrors) {
            formErrors
              .filter(({ severity }) =&gt; {
                return severity === OperationSeverity.Error;
              })
              .forEach(({ message }) =&gt; {
                messageAnnouncer.error(`Failed to save form data: ${message}`);
              });
          }

          if (operationConfirmationPrompt?.message) {
            setConfirmationPromptMessage(operationConfirmationPrompt.message);
            setConfirmationPromptTitle(operationConfirmationPrompt.subject);
            setConfirmationPromptContinueValues(values);
            setConfirmationPromptOpen(true);
          }
        } else {
          messageAnnouncer.error(
            `Failed to save form data: ${error instanceof Error ? error.message : error}`,
          );
        }
      } finally {
        setSubmitting(false);
      }
    },
    [dataService, dataSource, onBeforeSave, onSubmitComplete, messageAnnouncer],
  );

  const onConfirmationPromptContinueClick = useCallback(async () =&gt; {
    try {
      const response = await dataService.saveData(
        dataSource,
        confirmationPromptContinueValues,
        OperationConfirmation.OperationConfirmed,
      );

      onSubmitComplete?.(response ?? null);
    } catch (error) {
      if (isOperationError(error)) {
        const formErrors = filterFieldErrorsFromOperationError(
          error,
          confirmationPromptContinueValues,
        );

        if (formErrors) {
          formErrors.forEach(({ message }) =&gt; {
            messageAnnouncer.error(`Failed to save form data: ${message}`);
          });
        }
      } else {
        messageAnnouncer.error(
          `Failed to save form data: ${error instanceof Error ? error.message : error}`,
        );
      }

      setConfirmationPromptOpen(false);
    }
  }, [
    confirmationPromptContinueValues,
    dataService,
    dataSource,
    messageAnnouncer,
    onSubmitComplete,
  ]);

  return (
    &lt;&gt;
      &lt;Formik
        initialValues={initialValues}
        onSubmit={onSubmit}
        // Enable re-initialization to be able to asynchronously populate the form
        // through an imperative call to setInitialValues(...) after it&#39;s been mounted.
        enableReinitialize={true}
        validationSchema={validationSchema}
        // Turn off stock validation - we replace the validation infrastructure with our own.
        // The standard validation of Formik is inefficient as it performs full form validation
        // on every keystroke: https://github.com/formium/formik/issues/512#issuecomment-643788203
        // We replace the validation with the solution suggested in the above comment.
        // See implementation of validateField and how it is placed in our custom FormValidateFieldFuncContext
        // which is then used by the underlying fields to invoke field-level validation on change.
        validateOnChange={false}
        validateOnBlur={false}
      &gt;
        {(props) =&gt; (
          &lt;FormValidateField validationSchema={validationSchema}&gt;
            &lt;FormikPatchTouched /&gt;
            &lt;FormBase sx={sx} onSubmit={props.handleSubmit}&gt;
              {children}
            &lt;/FormBase&gt;
          &lt;/FormValidateField&gt;
        )}
      &lt;/Formik&gt;
      &lt;Dialog
        open={confirmationPromptOpen}
        onClose={hideConfirmationPrompt}
        fullWidth
        maxWidth=&quot;sm&quot;
      &gt;
        &lt;DialogTitle sx={confirmationDialogTitleSx}&gt;
          &lt;WarningAmber&gt;&lt;/WarningAmber&gt;
          {confirmationPromptTitle || &quot;Alert Title&quot;}
        &lt;/DialogTitle&gt;

        &lt;DialogContent&gt;
          &lt;DialogContentText
            sx={{
              color: &quot;common.black&quot;,
              margin: 0,
              typography: &quot;subtitle2&quot;,
            }}
          &gt;
            {confirmationPromptMessage}
          &lt;/DialogContentText&gt;
        &lt;/DialogContent&gt;

        &lt;Divider&gt;&lt;/Divider&gt;
        &lt;DialogActions&gt;
          &lt;Button onClick={hideConfirmationPrompt} variant=&quot;outlined&quot;&gt;
            Cancel
          &lt;/Button&gt;
          &lt;Button
            onClick={onConfirmationPromptContinueClick}
            variant=&quot;contained&quot;
          &gt;
            Proceed
          &lt;/Button&gt;
        &lt;/DialogActions&gt;
      &lt;/Dialog&gt;
    &lt;/&gt;
  );
}

const isErrorOperationItem = ({
  severity = OperationSeverity.Info,
}: OperationItem) =&gt; {
  return severity &gt;= OperationSeverity.Error;
};

const isConfirmationRequiredOperationItem = ({
  severity = OperationSeverity.Info,
}: OperationItem) =&gt; {
  return (
    severity &gt; OperationSeverity.Info &amp;&amp;
    severity &lt;= OperationSeverity.ConfirmationRequired
  );
};

const isFieldErrorOperationItem = (
  { subject }: OperationItem,
  formValues: Record&lt;string, unknown&gt;,
) =&gt; {
  return subject !== undefined &amp;&amp; formValues.hasOwnProperty(subject);
};

const hasOperationItemMessage = ({ message }: OperationItem) =&gt; {
  return message !== undefined &amp;&amp; message !== &quot;&quot;;
};

/**
 * Given an Operation Error, collect the form field errors.
 */
export function collectFieldErrorsFromOperationError&lt;
  R extends FormikValues = Record&lt;string, unknown&gt;,
&gt;(operationError: OperationError, formValues: R): FormikErrors&lt;R&gt; | null {
  const fieldErrorOperationItems = operationError.operationResult.filter(
    (operationItem) =&gt; {
      const isError = isErrorOperationItem(operationItem);
      const isFieldError = isFieldErrorOperationItem(operationItem, formValues);
      const hasErrorMessage = hasOperationItemMessage(operationItem);

      return isError &amp;&amp; isFieldError &amp;&amp; hasErrorMessage;
    },
  );

  if (fieldErrorOperationItems.length === 0) {
    return null;
  }

  const fieldErrors = fieldErrorOperationItems.reduce(
    (errors: FormikErrors&lt;R&gt;, { message, subject }) =&gt; {
      const updatedError: FormikErrors&lt;R&gt; = {
        ...errors,
        ...(subject ? { [subject]: message } : {}),
      };

      return updatedError;
    },
    {},
  );

  return fieldErrors;
}

/**
 * Given an Operation Error, filters out field specific errors.
 */
export function filterFieldErrorsFromOperationError&lt;
  R extends FormikValues = Record&lt;string, unknown&gt;,
&gt;(operationError: OperationError, formValues: R) {
  const operationItems = operationError.operationResult.filter(
    (operationItem) =&gt; {
      const isError = isErrorOperationItem(operationItem);
      const isNotFieldError = !isFieldErrorOperationItem(
        operationItem,
        formValues,
      );
      const hasErrorMessage = hasOperationItemMessage(operationItem);

      return isError &amp;&amp; isNotFieldError &amp;&amp; hasErrorMessage;
    },
  );

  if (operationItems.length === 0) {
    return null;
  }

  return operationItems;
}

/**
 * Check if the Operation Error contains a warning with no form field.
 * This would be an operation confirmation prompt message.
 */
export function getConfirmationMessageFromOperationError&lt;
  R extends FormikValues = Record&lt;string, unknown&gt;,
&gt;(
  operationError: OperationError,
  formValues: R,
): { message: string | null; subject: string | null } {
  const { message, subject } =
    operationError.operationResult.find((operationItem) =&gt; {
      const isConfirmationRequired =
        isConfirmationRequiredOperationItem(operationItem);
      const isNotFieldConfirmation = !isFieldErrorOperationItem(
        operationItem,
        formValues,
      );
      const hasConfirmationMessage = hasOperationItemMessage(operationItem);

      return (
        isConfirmationRequired &amp;&amp;
        isNotFieldConfirmation &amp;&amp;
        hasConfirmationMessage
      );
    }) ?? {};

  return {
    message: message ?? null,
    subject: subject ?? null,
  };
}

