import {
  FormPortfolioSelectorDataServiceProvider,
  DdxValuesProvider,
  GridCacheProvider,
  injectContextGates,
  installNavigationGuard,
} from "@solvasam/bizcomponents";
import {
  AIPFormDataServiceProvider,
  AutocompleteDataServiceProvider,
  DataGridDataServiceProvider,
  DataTypeManagerProvider,
  FabricAsyncOperationRunnerProvider,
  FormatManagerProvider,
} from "@textile/biz-components";
import {
  AxiosFactoryProvider,
  SnackbarMessageAnnouncerProvider,
  SnackbarProvider,
  StaticAppContextProvider,
} from "@textile/common";
import { TextileProps } from "@textile/runtime";
import {
  Fragment,
  FunctionComponent,
  ReactNode,
  StrictMode,
  useEffect,
  useState,
} from "react";
import { RouterProvider, createHashRouter } from "react-router-dom";

import { createSharedAppContextManager } from "./contexts";
import { createRoutes } from "./routes";

interface MockServiceWorkerProps {
  children?: ReactNode;
}

/**
 * A mock service worker component which dynamically imports the in-browser mock code
 * only if the custom webpack environment variable "mocks" is set.
 */
const MockServiceWorker: FunctionComponent<MockServiceWorkerProps> = ({
  children,
}) => {
  const [ready, setReady] = useState(process.env.MOCKS ? false : true);

  useEffect(() => {
    // Enable mock service worker
    if (process.env.MOCKS) {
      import("./mocks/browser")
        .then(({ mockApiWorker }) => {
          return mockApiWorker.start({
            onUnhandledRequest: "bypass",
          });
        })
        .then(() => {
          setReady(true);
        });
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return (
    <Fragment>
      {ready ? children : <div>Loading Service Worker...</div>}
    </Fragment>
  );
};

// Create a window into the shared Textile app context.
const sharedAppContextManager = createSharedAppContextManager();
// Get a reference to the shared app context provider.
const SharedAppContextProvider =
  sharedAppContextManager.createRootContextProvider();

export interface RootProps {
  textile: TextileProps;
  name: string;
}

installNavigationGuard({
  routerType: "hash",
  fallbackHash: "#/compliance-modeling-ui",
});

export const Root: FunctionComponent<RootProps> = (props) => {
  const routes = injectContextGates(createRoutes(props), [
    { routeParam: ":portfolioId", contextKey: "app.selectedPortfolio" },
    { routeParam: ":modelId", contextKey: "app.selectedModel" },
  ]);

  return (
    <StrictMode>
      <StaticAppContextProvider
        textileProps={props.textile}
        sharedAppContextManager={sharedAppContextManager}
      >
        <SharedAppContextProvider>
          <MockServiceWorker>
            <AxiosFactoryProvider>
              <SnackbarProvider SnackbarProps={{ style: { top: "20px" } }}>
                <SnackbarMessageAnnouncerProvider>
                  <GridCacheProvider>
                    <DataTypeManagerProvider>
                      <FormatManagerProvider>
                        <FabricAsyncOperationRunnerProvider>
                          <DataGridDataServiceProvider>
                            <AIPFormDataServiceProvider>
                              <AutocompleteDataServiceProvider>
                                <FormPortfolioSelectorDataServiceProvider>
                                  <DdxValuesProvider>
                                    <RouterProvider
                                      router={createHashRouter(routes)}
                                    ></RouterProvider>
                                  </DdxValuesProvider>
                                </FormPortfolioSelectorDataServiceProvider>
                              </AutocompleteDataServiceProvider>
                            </AIPFormDataServiceProvider>
                          </DataGridDataServiceProvider>
                        </FabricAsyncOperationRunnerProvider>
                      </FormatManagerProvider>
                    </DataTypeManagerProvider>
                  </GridCacheProvider>
                </SnackbarMessageAnnouncerProvider>
              </SnackbarProvider>
            </AxiosFactoryProvider>
          </MockServiceWorker>
        </SharedAppContextProvider>
      </StaticAppContextProvider>
    </StrictMode>
  );
};

