    useMemo<DataGridDataServiceSource>(
      () => ({
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/calculationGroups/${groupId}/blocks/${blockId}/parameters:view`,
      }),
      [portfolioId, modelId, groupId, blockId]
    );

  const colDefOverrides: ColDefOverride[] = useMemo(
    () => [
      {
        field: "value",
        colDef: {
          cellRenderer: CalculationBlockParameterCellRenderer,
          headerName: "Value",
          wrapText: true,
          autoHeight: true,
        },
      },
    ],
    []
  );
  const agGridApiRef = useRef<GridApi | null>(null);

  useRefreshNeedReviewOnParentGrid(blockId, "CB", undefined, agGridApiRef);

  return (
    <AsyncDataGridPanel
      dataSource={calculationBlockParameterDataSource}
      rowSelectionMode="single"
      sx={groupGridSx}
      colDefOverrides={colDefOverrides}
      refreshToken={refreshToken}
      gridPersistOptions={{
        key: "CBP",
        enabled: true,
      }}
      agGridProps={{
        onGridReady: (e: GridReadyEvent) => {
          agGridApiRef.current = e.api;
        },
      }}
    >
      <Fragment>
        <DataGridQuickSearch></DataGridQuickSearch>
        <DataGridAsyncDialogAction
          actionCode="editparametervalue"
          label="Edit"
          level="grid"
          loadOnOpen={true}
          type="icon"
          icon={<EditIcon size={24} />}
          iconButtonProps={
            selectedModelstate === "L"
              ? {
                disabled: true,
              }
              : undefined
          }
          dialog={
            <CalculationBlockParameterBulkEditForm
              portfolioId={portfolioId}
              modelId={modelId}
              groupId={groupId}
              blockId={blockId}
            ></CalculationBlockParameterBulkEditForm>
          }
          onUpdateUi={refresh}
        ></DataGridAsyncDialogAction>
        {!isRenderedByCalSeq && <DataGridActionRefresh></DataGridActionRefresh>}
        <DownloadActionMenu />
        <DataGridActionViewSource
          datasource={calculationBlockParameterDataSource}
        />
      </Fragment>
    </AsyncDataGridPanel>
  );
};

const gridSx: SxProps = {
  display: "flex",
  flexGrow: 1,
  height: "15vmax",
};

const CalculationBlockParameterCellRenderer = (props: ICellRendererParams) => {
  const { data } = props;
  const theme = useTheme();
  const ddxData = useDdxValues();
  return (
    <Fragment>
      {data.value === "[Parameter Value Required]" ? (
        <Box
          sx={{
            color: theme.palette.error.main,
          }}
        >
          {data.value}
        </Box>
      ) : ["E"].includes(data?.parameter_value_type) &&
        data.value !== "{Not Specified}" ? (
        // expression builder
        <Stack
          direction="row"
          justifyContent="space-between"
          spacing={1}
          alignItems="flex-start"
        >
          <Box sx={{ flexGrow: 1, overflow: "auto" }}>
            <RuleDisplayComponent
              value={ddxFormatter.format(data?.value ?? "")}
              ddxData={ddxData}
            />
          </Box>
        </Stack>
      ) : ["C"].includes(data?.parameter_value_type) ? ( // formula builder
        formatFormula(data?.value)
      ) : data?.parameter_value_type === "T" &&
        data?.value_type &&
        data?.value_type.toUpperCase() === "VAL" ? (
        (() => {
          const tableValues = data?.table_value
            ? parseTableParameterValue(data?.table_value as string[])
            : [];
          return (
            <DataGridPanel
              meta={getSchema(data?.data_source ?? "")}
              data={{
                rowData: tableValues,
              }}
              sx={gridSx}
              gridPersistOptions={{
                key: `CBP-TABLE`,
                enabled: true,
              }}
            ></DataGridPanel>
          );
        })()
      ) : (
        data.value
      )}
    </Fragment>
  );
};

