import {
  ActionMenu,
  AsyncDataGridPanel,
  ColDefOverride,
  DataGridActionAdd,
  DataGridActionDelete,
  DataGridActionEdit,
  DataGridActionRefresh,
  DataGridAsyncDialogAction,
  DataGridDataServiceSource,
  DataGridQuickSearch,
  FabricAsyncOperation,
  useRefreshToken,
} from "@textile/biz-components";
import {
  Screen,
  ToolGroup,
  useAxiosFactory,
  useStaticAppContext,
  EditIcon,
  DuplicateIcon,
  Splitter,
} from "@textile/common";
import {
  Box,
  IconButton,
  IconButtonProps,
  Stack,
  SxProps,
  Tooltip,
  Typography,
} from "@textile/mui";
import React, {
  FunctionComponent,
  useEffect,
  useMemo,
  useRef,
  useState,
  useCallback,
  ReactNode,
  createContext,
  useContext,
} from "react";
import { useParams, useSearchParams } from "react-router-dom";
import { EligibilityCriteriaFormDialog } from "./eligibility-criteria-form-dialog.component";
import { EligibilityCriteriaTest } from "../tests.types";
import { EligibilityCriteriaCopyDialog } from "./eligibility-criteria-copy-dialog.component";
import { CommonGridProps, formatDate, isParameterValid } from "../../common";
import { AppRouteParams, ScreenProps } from "../../screen.types";
import {
  CodePair,
  DataGridActionViewSource,
  ddxFormatter,
  DownloadActionMenu,
  NumericCellEditor,
  RuleDisplayComponent,
  SummaryComponent,
  SummaryDownloadActionMenu,
  SummaryRow,
  useCustomMessageAnnouncer,
  useDdxValues,
  ViewCustomSourceActionDialog,
  CustomScreenHeader,
} from "@solvasam/bizcomponents";
import {
  GridApi,
  GridReadyEvent,
  IRowNode,
  RowDragEvent,
} from "@textile/ag-grid";
import { useFetch } from "../../common/useFetch";
import { DisplayOrderCellRenderer } from "../common/display-order-cell-renderer.component";
import { useRefreshNeedReviewOnParentGrid } from "../../common/refresh-need-review.hook";
import { detailsContainerSx } from "../../common/common.component";

const screenSx: SxProps = {
  display: "flex",
  flexDirection: "column",
};
const gridSx: SxProps = { flexGrow: 1, height: "100%" };

type EligibilityGridActionContextType = {
  portfolioId: string;
  modelId: string;
  selectedModelstate: string | null;
  refreshDetails: (() => void) | undefined;
  refreshGrid: (() => void) | undefined;
  editButtonRef: React.RefObject<HTMLButtonElement>;
  testsEligibilityCriteriaDelete: FabricAsyncOperation;
  eligibilityCriteriaDataSource: DataGridDataServiceSource;
};

const EligibilityGridActionContext =
  createContext<EligibilityGridActionContextType>({
    portfolioId: "",
    modelId: "",
    selectedModelstate: null,
    refreshDetails: undefined,
    refreshGrid: undefined,
    editButtonRef: React.createRef<HTMLButtonElement>(),
    testsEligibilityCriteriaDelete: {
      url: "",
      operationConfirmedParamLocation: "query",
      method: "delete",
    },
    eligibilityCriteriaDataSource: {},
  });

export const EligibilityCriteriaScreen: FunctionComponent<ScreenProps> = () => {
  const [refreshToken, refresh] = useRefreshToken();
  const { portfolioId, modelId } = useParams<AppRouteParams>();
  const [ecTestId, setEcTestId] = useState<string | null>(null);
  const ecTestSelectionChanged = (
    selectedRecords: EligibilityCriteriaTest[]
  ) => {
    setEcTestId(selectedRecords.length === 1 ? selectedRecords[0]?.id : null);
  };
  const editButtonRef = useRef<HTMLButtonElement>(null);
  return (
    <Screen
      sx={screenSx}
      navigationId={
        "compliance-modeling-ui-compliance-modeling-portfolioId-modelId-tests-eligibilitycriteria"
      }
    >
      <CustomScreenHeader />
      <Stack sx={gridSx} direction={"row"}>
        <Splitter expandable={true}>
          <Stack sx={{ flex: "1 1 0px" }} direction={"column"}>
            {portfolioId && modelId ? (
              <EligibilityCriteriaGrid
                modelId={modelId}
                refreshDetails={refresh}
                selectedPortfolioId={portfolioId}
                onSelectionChanged={ecTestSelectionChanged}
                editButtonRef={editButtonRef}
              >
                <EligibilityTestsGridActions></EligibilityTestsGridActions>
              </EligibilityCriteriaGrid>
            ) : null}
          </Stack>
          {ecTestId !== null ? (
            <EligibilityCriteriaTestSummary
              ecTestId={ecTestId}
              portfolioId={portfolioId}
              modelId={modelId}
              refreshToken={refreshToken}
              editButtonRef={editButtonRef}
            />
          ) : null}
        </Splitter>
      </Stack>
    </Screen>
  );
};

export const EligibilityCriteriaGrid: FunctionComponent<
  CommonGridProps<EligibilityCriteriaTest> & {
    editButtonRef: React.RefObject<HTMLButtonElement>;
    refreshDetails?: () => void;
    children?: ReactNode;
    titleComponent?: React.ReactElement<
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      any,
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      string | React.JSXElementConstructor<any>
    >;
    rowSelectionMode?: "single" | "multi";
  }
> = (props) => {
  const {
    modelId,
    selectedPortfolioId,
    refreshDetails,
    onSelectionChanged,
    editButtonRef,
    children: children,
    titleComponent,
    rowSelectionMode = "multi",
  } = props;
  const { sharedAppContextManager } = useStaticAppContext();
  const { state: selectedModelstate } = sharedAppContextManager.useContext<
    string | null
  >("app.selectedModelState");

  const [refreshGridToken, refreshGrid] = useRefreshToken();
  const messageAnnouncer = useCustomMessageAnnouncer();

  const agGridApiRef = useRef<GridApi | null>(null);
  const [searchParams] = useSearchParams();
  const rowId = searchParams.get("rowId");
  const eligibilityCriteriaDataSource = useMemo<DataGridDataServiceSource>(
    () => ({
      url: `/compliance-bff/v1/portfolios/${selectedPortfolioId}/models/${modelId}/eligibilityCriteriaTests:view`,
    }),
    [selectedPortfolioId, modelId]
  );

  const testsEligibilityCriteriaDelete: FabricAsyncOperation = {
    url: `/compliance-bff/v1/portfolios/${selectedPortfolioId}/models/${modelId}/eligibilityCriteriaTests:batchDelete`,
    method: "post",
    operationConfirmedParamLocation: "body",
    idsField: "names",
  };

  const agGridCustomSx: SxProps = {
    ".ag-cell-focus": {
      border: "none !important",
    },
  };

  const updateOrderValue = async (
    test: EligibilityCriteriaTest,
    display_order: number
  ) => {
    if (test) {
      const EligibilityCriteriaTestDisplayOrderUpdate = {
        url: `/compliance-bff/v1/portfolios/${selectedPortfolioId}/models/${modelId}/eligibilityCriteriaTests/${test.id}?operation_confirmed=1`,
        requestObj: {
          order: Number(display_order),
          etag: test.etag,
        },
      };
      try {
        const displayOrderUpdateResp = await updateData(
          EligibilityCriteriaTestDisplayOrderUpdate.url,
          EligibilityCriteriaTestDisplayOrderUpdate.requestObj
        );
        if (displayOrderUpdateResp?.status === 200)
          refreshGrid ? refreshGrid() : null;
      } catch (error) {
        messageAnnouncer.error(
          `Failed to update Display Order: ${error}`,
          error
        );
      }
    }

    return null;
  };

  const colDefOverrides: ColDefOverride[] = [
    {
      field: "order",
      colDef: {
        rowDrag: true,
        editable: true,
        cellEditor: NumericCellEditor,
        cellEditorParams: {
          // make "dataType" value available to cell editor
          dataType: "number",
        },
        cellRenderer: DisplayOrderCellRenderer,
        onCellValueChanged: (params) => {
          const newValue = params.newValue;
          const oldValue = params.oldValue;
          const record = params.data;

          if (newValue !== oldValue) {
            updateOrderValue(record, newValue);
          }
        },
      },
    },
  ];
  const deps = useCallback(
    () =>
      modelId && selectedPortfolioId && refreshDetails
        ? [modelId, selectedPortfolioId, refreshDetails]
        : [],
    [modelId, selectedPortfolioId, refreshDetails]
  );

  const onRowDragEnd = async (event: RowDragEvent) => {
    if (rowSelectionMode == "multi") {
      const movingNode = event.node;
      const overNode = event.overNode;

      if (
        movingNode !== overNode &&
        movingNode?.data?.order &&
        overNode?.data?.order
      ) {
        updateEligibilityCriteriaOrder(movingNode, overNode);
      }
    }
  };

  const { fetchData: updateData } = useFetch<EligibilityCriteriaTest>({
    url: "",
    method: "PATCH",
    deps: deps(),
    autoFetch: false,
  });

  const updateEligibilityCriteriaOrder = async (
    movingNode: IRowNode,
    overNode: IRowNode
  ) => {
    const EligibilityCriteriaTestDisplayOrderUpdate = {
      url: `/compliance-bff/v1/portfolios/${selectedPortfolioId}/models/${modelId}/eligibilityCriteriaTests/${movingNode.data.id}?operation_confirmed=1`,
      requestObj: {
        order: overNode.data.order,
        etag: movingNode.data.etag,
      },
    };

    try {
      const displayOrderUpdateResp = await updateData(
        EligibilityCriteriaTestDisplayOrderUpdate.url,
        EligibilityCriteriaTestDisplayOrderUpdate.requestObj
      );
      if (displayOrderUpdateResp?.status === 200)
        refreshGrid ? refreshGrid() : null;
    } catch (error) {
      messageAnnouncer.error(`Failed to update Display Order: ${error}`, error);
    }

    return null;
  };

  const onGridReady = (event: GridReadyEvent) => {
    agGridApiRef.current = event.api;

    if (rowId) {
      const rowNode = agGridApiRef.current.getRowNode(rowId);

      if (rowNode) {
        rowNode.setSelected(true);
        agGridApiRef.current.ensureIndexVisible(rowNode.sourceRowIndex, "top");
      }
    }
  };
  useRefreshNeedReviewOnParentGrid(modelId, "PSM", "EC", agGridApiRef);

  return isParameterValid(modelId) ? (
    <AsyncDataGridPanel
      rowSelectionMode={rowSelectionMode}
      sx={{ ...gridSx, ...agGridCustomSx }}
      dataSource={modelId ? eligibilityCriteriaDataSource : null}
      onSelectionChanged={onSelectionChanged}
      refreshToken={refreshGridToken}
      colDefOverrides={rowSelectionMode == "multi" ? colDefOverrides : []}
      titleComponent={titleComponent}
      agGridProps={{
        onRowDragEnd: onRowDragEnd,
        onGridReady: onGridReady,
        singleClickEdit: true,
        stopEditingWhenCellsLoseFocus: true,
      }}
      gridPersistOptions={{
        key: `EC-SCREEN`,
        enabled: true,
      }}
    >
      <EligibilityGridActionContext.Provider
        value={{
          portfolioId: selectedPortfolioId as string,
          modelId: modelId as string,
          refreshDetails: refreshDetails,
          refreshGrid: refreshGrid,
          selectedModelstate: selectedModelstate,
          editButtonRef: editButtonRef,
          testsEligibilityCriteriaDelete: testsEligibilityCriteriaDelete,
          eligibilityCriteriaDataSource: eligibilityCriteriaDataSource,
        }}
      >
        {children}
      </EligibilityGridActionContext.Provider>
    </AsyncDataGridPanel>
  ) : null;
};

interface EligibilityCriteriaTestProps {
  portfolioId?: string;
  modelId?: string;
  ecTestId: string;
  editButtonRef?: React.RefObject<HTMLButtonElement> | null;
  refreshToken?: symbol;
}

export const EligibilityCriteriaTestSummary: FunctionComponent<
  EligibilityCriteriaTestProps
> = ({ ecTestId, portfolioId, modelId, editButtonRef, refreshToken }) => {
  const axiosFactory = useAxiosFactory();
  const [ecTestDetail, setECTestDetail] =
    useState<EligibilityCriteriaTest | null>(null);
  const messageAnnouncer = useCustomMessageAnnouncer();
  const { sharedAppContextManager } = useStaticAppContext();
  const ddxData = useDdxValues();
  const { state: modelstate } = sharedAppContextManager.useContext<
    string | null
  >("app.selectedModelState");
  const urlToLoadEligibilityCriteriaTest = `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/eligibilityCriteriaTests/${ecTestId}`;

  useEffect(() => {
    const abortController = new AbortController();
    const loadEligibilityCriteriaTest = async () => {
      try {
        const axios = await axiosFactory.createAxiosInstance();
        const { data } = await axios.get<EligibilityCriteriaTest>(
          urlToLoadEligibilityCriteriaTest,
          { signal: abortController.signal }
        );
        setECTestDetail(data);
      } catch (error) {
        messageAnnouncer.error(
          `Failed to load Eligibility Criteria Test: ${error}`,
          error
        );
      }
    };
    loadEligibilityCriteriaTest();

    return () => abortController.abort();
  }, [
    axiosFactory,
    portfolioId,
    modelId,
    ecTestId,
    refreshToken,
    messageAnnouncer,
    urlToLoadEligibilityCriteriaTest,
  ]);

  const summaryRows: CodePair[] = useMemo(
    () => [
      {
        code: "Display Order",
        description: ecTestDetail?.order?.toString() ?? "",
      },
      { code: "EC Test ID", description: ecTestDetail?.id ?? "" },
      { code: "EC Test Name", description: ecTestDetail?.test_name ?? "" },
      {
        code: "Document Reference",
        description: ecTestDetail?.document_reference ?? "",
      },
      {
        code: "Report Reference",
        description: ecTestDetail?.report_reference ?? "",
      },
      {
        code: "Effective Begin Date",
        description: formatDate(
          ecTestDetail?.effective_begin_date ?? "",
          "M/D/YYYY"
        ),
      },
      {
        code: "Effective End Date",
        description: formatDate(
          ecTestDetail?.effective_end_date ?? "",
          "M/D/YYYY"
        ),
      },
      {
        code: "Criteria Expression",
        description: ddxFormatter.format(
          ecTestDetail?.criteria_expression?.friendly_description ?? ""
        ),
      },
      {
        code: "Copy Source",
        description: ecTestDetail?.copy_source_description ?? "",
      },
      { code: "Comments", description: ecTestDetail?.comments ?? "" },
    ],
    [ecTestDetail]
  );

  return (
    <Stack gap={0.5} direction="column" sx={detailsContainerSx}>
      <ToolGroup
        display="flex"
        sx={{ height: "32px", gap: 1, alignItems: "center" }}
        aria-label="Eligibility Criteria Information"
      >
        <Typography color="textPrimary" variant="subtitle2" fontWeight={600}>
          {"Eligibility Criteria Information"}
        </Typography>
        <Box sx={{ flexGrow: 1 }} />
        {editButtonRef ? (
          <Tooltip title="Edit">
            <span>
              <IconButton
                aria-label="Edit Eligibility Criteria Test"
                onClick={(event: React.MouseEvent<HTMLButtonElement>) => {
                  event.stopPropagation();
                  editButtonRef?.current?.click();
                }}
                disabled={modelstate === "L"}
              >
                <EditIcon size={24} />
              </IconButton>
            </span>
          </Tooltip>
        ) : null}
        <SummaryDownloadActionMenu
          filename={"Eligibility Criteria"}
          rows={summaryRows}
        />
        <ViewCustomSourceActionDialog url={urlToLoadEligibilityCriteriaTest} />
      </ToolGroup>
      {ecTestDetail ? (
        <SummaryComponent cardSx={{ mb: 1.5 }}>
          {summaryRows.map((row, index) => (
            <SummaryRow
              key={index}
              Key={row.code}
              Value={
                row.code === "Criteria Expression" ? (
                  <RuleDisplayComponent
                    value={row.description}
                    ddxData={ddxData}
                  />
                ) : (
                  row.description
                )
              }
            />
          ))}
        </SummaryComponent>
      ) : null}
    </Stack>
  );
};

export const EligibilityTestsGridActions = () => {
  const {
    modelId,
    portfolioId,
    refreshGrid,
    refreshDetails,
    editButtonRef,
    selectedModelstate,
    testsEligibilityCriteriaDelete,
    eligibilityCriteriaDataSource,
  } = useContext(EligibilityGridActionContext);

  const iconButtonProps = useMemo<IconButtonProps>(() => {
    return selectedModelstate === "L" ? { disabled: true } : {};
  }, [selectedModelstate]);
  return (
    <>
      <DataGridQuickSearch></DataGridQuickSearch>
      <DataGridActionAdd
        iconButtonProps={iconButtonProps}
        dialog={
          <EligibilityCriteriaFormDialog
            modelId={modelId}
            portfolioId={portfolioId}
          ></EligibilityCriteriaFormDialog>
        }
      ></DataGridActionAdd>
      <DataGridActionEdit
        iconButtonProps={{
          ...iconButtonProps,
          ref: editButtonRef,
        }}
        onUpdateUi={refreshDetails}
        dialog={
          <EligibilityCriteriaFormDialog
            modelId={modelId}
            portfolioId={portfolioId}
          ></EligibilityCriteriaFormDialog>
        }
      ></DataGridActionEdit>
      <DataGridActionDelete
        confirmationDialogProps={{ confirmButtonLabel: "Delete" }}
        iconButtonProps={iconButtonProps}
        operation={testsEligibilityCriteriaDelete}
        rowSelectionMode="multi"
      ></DataGridActionDelete>
      <DataGridAsyncDialogAction
        actionCode="duplicate"
        label="Duplicate"
        level="grid"
        loadOnOpen={false}
        type="icon"
        icon={<DuplicateIcon size={24} />}
        iconButtonProps={iconButtonProps}
        dialog={
          <EligibilityCriteriaCopyDialog
            modelId={modelId}
            portfolioId={portfolioId}
            refreshGrid={refreshGrid}
          ></EligibilityCriteriaCopyDialog>
        }
      />

      <ActionMenu>
        <DownloadActionMenu isPopover={true} />
        <DataGridActionRefresh
          type="menuitem"
          icon={null}
        ></DataGridActionRefresh>
        <DataGridActionViewSource
          datasource={eligibilityCriteriaDataSource}
          type="menuitem"
        />
      </ActionMenu>
    </>
  );
};

