import {
  AddExpressionMenu,
  CopyExpression,
  DeleteExpression,
  FormExpressionBuilder,
  FormFormulaEditor,
  FormLookupAutocomplete,
  getDialogResizePaperPropsSx,
  LookupItem,
  LookupItemOption,
  PasteMenu,
  useDdxValues,
  useExpressionValidator,
} from "@solvasam/bizcomponents";
import {
  AsyncFormDialog,
  AsyncFormDialogProps,
  FormCheckbox,
  FormDataServiceSource,
  FormFieldGroup,
  FormTextField,
  useDialogActionCode,
  useField,
} from "@textile/biz-components";
import { InputAdornment, useMediaQuery, useTheme } from "@textile/mui";
import { Fragment, FunctionComponent, useCallback, useMemo } from "react";
import { useParams } from "react-router-dom";

import { PrincipalBalanceRule } from "../common/dynamic-data-rules.types";
import { AppRouteParams } from "../../screen.types";
import { GridApi } from "@textile/ag-grid";
import { usePopulateSuccessMessage } from "../../common/helpers";

interface PrincipalBalanceRuleFormProps {
  mode: "add" | "edit";
}

const PrincipalBalanceRulesForm: FunctionComponent<
  PrincipalBalanceRuleFormProps
> = ({ mode }) => {
  const [{ value: valuationMethod }] = useField("value_data_type");
  const [{ value: valuationOption }] = useField("value_type");
  const [{ value: parCalculationMethod }] = useField("par_calculation_method");
  const [{ value: ruleType }] = useField("type");
  const ddxData = useDdxValues();

  const onBeforeParCapitalizedinterestPopulate = useCallback(
    async (options: LookupItem[]) => {
      const useGroupOption: LookupItemOption = {
        code: "",
        description: "Use Group Option",
      };

      return [useGroupOption, ...options];
    },
    []
  );

  return (
    <Fragment>
      <FormFieldGroup>
        <FormTextField<PrincipalBalanceRule>
          fieldName="priority"
          label="Rule Priority"
          variant="outlined"
          required
          type="number"
          InputProps={{
            inputProps: {
              min: 1,
              max: 50,
            },
          }}
        ></FormTextField>
        <FormTextField<PrincipalBalanceRule>
          fieldName="description"
          label="Description"
          variant="outlined"
          required
        ></FormTextField>
      </FormFieldGroup>

      <FormFieldGroup>
        <FormLookupAutocomplete<PrincipalBalanceRule>
          fieldName="type"
          lookupType="PB_RULE_TYPE"
          textFieldProps={{
            label: "Rule Applicability",
            variant: "outlined",
            required: true,
          }}
        ></FormLookupAutocomplete>
        <FormLookupAutocomplete<PrincipalBalanceRule>
          fieldName="value_data_type"
          lookupType="PB_VALUE_DATA_TYPE"
          textFieldProps={{
            label: "Valuation Method",
            variant: "outlined",
            required: true,
          }}
        ></FormLookupAutocomplete>
      </FormFieldGroup>
      <FormFieldGroup>
        <FormLookupAutocomplete<PrincipalBalanceRule>
          fieldName="value_type"
          lookupType="PB_VALUE_TYPE"
          textFieldProps={{
            label: "Valuation Option",
            variant: "outlined",
            required: true,
          }}
        ></FormLookupAutocomplete>
        {["PPAR", "LPMV", "LPPP", "LPWV"].includes(valuationOption) ? (
          <FormTextField<PrincipalBalanceRule>
            fieldName="par_percentage"
            label="Percentage of Par"
            variant="outlined"
            type="number"
            InputProps={{
              endAdornment: <InputAdornment position="end">%</InputAdornment>,
            }}
          ></FormTextField>
        ) : null}
        {["PP", "LPPP", "LPPR"].includes(valuationOption) ? (
          <FormLookupAutocomplete<PrincipalBalanceRule>
            fieldName="purchase_price_option"
            lookupType="PRICE_TYPE"
            textFieldProps={{
              label: "Price Option",
              variant: "outlined",
            }}
          ></FormLookupAutocomplete>
        ) : null}
      </FormFieldGroup>
      {valuationMethod === "PERC" ? (
        <FormFieldGroup>
          <FormLookupAutocomplete<PrincipalBalanceRule>
            fieldName="par_calculation_method"
            lookupType="PB_GROUP_OPTION"
            textFieldProps={{
              label: "Par Capitalized Interest Option",
              variant: "outlined",
            }}
            onBeforePopulate={onBeforeParCapitalizedinterestPopulate}
          ></FormLookupAutocomplete>
        </FormFieldGroup>
      ) : null}
      {valuationOption === "FRML" ? (
        <FormFormulaEditor
          id="formula_expression"
          purpose="FIELD_FORMULA"
          errors={[]}
          ddxData={ddxData}
        ></FormFormulaEditor>
      ) : null}

      {valuationMethod !== "CURR" ? (
        <FormFieldGroup>
          <FormCheckbox<PrincipalBalanceRule>
            fieldName="include_accrued_pik"
            label="Include Accrued PIK Interest"
            disabled={parCalculationMethod === "PECI"}
          />
        </FormFieldGroup>
      ) : null}
      {ruleType === "CUST" ? (
        <FormExpressionBuilder id="applicability_expression" ddxProps={ddxData}>
          <AddExpressionMenu />
          <DeleteExpression />
          <CopyExpression />
          <PasteMenu />
        </FormExpressionBuilder>
      ) : null}
      {mode === "edit" && (
        <FormFieldGroup>
          <FormTextField<PrincipalBalanceRule>
            fieldName="copy_source_description"
            label="Copy Source"
          ></FormTextField>
        </FormFieldGroup>
      )}
      <FormTextField<PrincipalBalanceRule>
        fieldName="comments"
        label="Comments"
        variant="outlined"
        multiline
      ></FormTextField>
    </Fragment>
  );
};

const defaultPrincipalBalanceRuleData: Partial<PrincipalBalanceRule> = {
  value_data_type: "PERC",
  par_calculation_method: "",
  formula_expression: null,
  applicability_expression: null,
  comments: "",
  include_accrued_pik: false,
  purchase_price_option: "",
  par_percentage: null,
  value_type: "",
  type: "",
};

export const PrincipalBalanceRulesFormDialog: FunctionComponent<
  Partial<AsyncFormDialogProps> & {
    pbGroupId: string;
    gridApi?: GridApi | null;
    priority?: number;
  }
> = ({ pbGroupId, gridApi, priority = 0 }) => {
  const { portfolioId, modelId } = useParams<AppRouteParams>();
  const theme = useTheme();
  const fullScreen = useMediaQuery(theme.breakpoints.down("md"));
  const actionCode = useDialogActionCode();

  const mode = actionCode === "edit" ? "edit" : "add";

  const populateSuccessMessage = usePopulateSuccessMessage();
  const handleOnSubmitComplete = () => {
    populateSuccessMessage(
      `Principal Balance Calculation Rule ${
        mode === "add" ? "added." : "updated."
      }`
    );
  };

  const rulesFormSource = useMemo<FormDataServiceSource>(
    () => ({
      idField: "id",
      mode: mode,
      get: {
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/pbRuleGroups/${pbGroupId}/rules`,
      },
      save: {
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/pbRuleGroups/${pbGroupId}/rules`,
        method: mode === "add" ? "post" : "patch",
      },
    }),
    [mode, pbGroupId, modelId, portfolioId]
  );

  const { fetchHydrateExpression } = useExpressionValidator();
  const valueTypes = [
    "PPAR",
    "LPMV",
    "LPPP",
    "LPWV",
    "PAR",
    "AV",
    "RVA",
    "RVD",
    "RVF",
    "RVM",
    "MRVK",
    "RVS",
    "MV",
    "MRVA",
    "MRVD",
    "MRVF",
    "MRVM",
    "MRVS",
    "ZERO",
    "WDV",
    "PP",
    "LMWV",
    "LRWV",
    "RVK",
    "LPPR",
    "FRML",
  ];

  const onBeforeSave = async (data: Partial<PrincipalBalanceRule>) => {
    if (
      data.par_calculation_method === "PECI" ||
      data.value_data_type === "CURR"
    ) {
      data.include_accrued_pik = false;
    }
    if (data.value_data_type === "CURR") {
      data.par_calculation_method = "";
    }
    if (!valueTypes.includes(data.value_type ?? "")) {
      data.par_percentage = 0;
    }

    if (!["PP", "LPPP", "LPPR"].includes(data.value_type ?? "")) {
      data.purchase_price_option = null;
      data.purchase_price_option_description = null;
    }

    if (!["PPAR", "LPMV", "LPPP", "LPMV"].includes(data.value_type ?? "")) {
      data.par_percentage = null;
    }

    if (data.value_type === "FRML") {
      const formulaExp = await fetchHydrateExpression(
        "FIELD_FORMULA",
        data?.formula_expression?.friendly_description,
        "value"
      );
      data.formula_expression = formulaExp;
    }
    if (data.value_type !== "FRML" || !data.formula_expression) {
      data.formula_expression = {
        ...data.formula_expression,
        ddx: null,
        friendly_description: null,
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
      } as any;
    }
    if (data.type !== "CUST" || !data.applicability_expression) {
      data.applicability_expression = {
        ...data.applicability_expression,
        friendly_description: null,
        ddx: null,
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
      } as any;
    }

    return { ...data, priority: Number(data?.priority) };
  };

  const onBeforePopulate = async (data: Partial<PrincipalBalanceRule>) => {
    if (!data.par_calculation_method) {
      data.par_calculation_method = "";
    }
    return data;
  };

  return (
    <AsyncFormDialog
      title={`${mode === "add" ? "Add" : "Edit"} Principal Balance Rule`}
      dataSource={rulesFormSource}
      fullScreen={fullScreen}
      enableFullScreenToggle={true}
      fullWidth
      defaultData={{
        ...defaultPrincipalBalanceRuleData,
        priority: (gridApi?.getDisplayedRowCount() as number) + 1 || priority,
      }}
      onBeforeSave={onBeforeSave}
      onBeforePopulate={onBeforePopulate}
      PaperProps={{
        sx: getDialogResizePaperPropsSx("lg"),
      }}
      draggable={true}
      onSubmitComplete={handleOnSubmitComplete}
    >
      <PrincipalBalanceRulesForm mode={mode} />
    </AsyncFormDialog>
  );
};

