import {
  AddExpressionMenu,
  CopyExpression,
  DeleteExpression,
  FormExpressionBuilder,
  getDialogResizePaperPropsSx,
  PasteMenu,
  FormCustomDatePicker,
} from "@solvasam/bizcomponents";
import {
  AsyncFormDialog,
  AsyncFormDialogProps,
  FormDataServiceSource,
  FormTextField,
  useDialogActionCode,
} from "@textile/biz-components";
import { Stack, useMediaQuery, useTheme } from "@textile/mui";
import { Fragment, FunctionComponent, useMemo } from "react";
import { EligibilityCriteriaTest } from "../tests.types";
export interface EligibilityCriteriaFormDialogProps
  extends Partial<AsyncFormDialogProps> {
  modelId?: string;
  portfolioId?: string;
  refreshGrid?: () => void;
  mode?: string;
  ddxData?: ReturnType<typeof import("@solvasam/bizcomponents").useDdxValues>;
}

interface EligibilityCriteriaFormProps {
  mode: "add" | "edit";
  ddxData?: unknown;
}

const EligibilityCriteriaForm: FunctionComponent<
  EligibilityCriteriaFormProps
> = ({ mode, ddxData }) => {
  return (
    <Fragment>
      <FormTextField<EligibilityCriteriaTest>
        fieldName="test_name"
        label="EC Test Name"
        required={true}
      ></FormTextField>
      <FormTextField<EligibilityCriteriaTest>
        fieldName="order"
        label="Display Order"
        type="number"
        inputProps={{
          min: 1,
        }}
        required={true}
      ></FormTextField>
      <FormTextField<EligibilityCriteriaTest>
        fieldName="document_reference"
        label="Document Reference"
        multiline
      ></FormTextField>
      <FormTextField<EligibilityCriteriaTest>
        fieldName="report_reference"
        label="Report Reference"
        multiline
      ></FormTextField>
      <FormCustomDatePicker<EligibilityCriteriaTest>
        fieldName="effective_begin_date"
        label="Effective Begin Date"
        textFieldProps={{
          required: true,
        }}
      ></FormCustomDatePicker>
      <FormCustomDatePicker<EligibilityCriteriaTest>
        fieldName="effective_end_date"
        label="Effective End Date"
      ></FormCustomDatePicker>
      <Stack>
        <FormExpressionBuilder
          label="Criteria Expression"
          id="criteria_expression"
          ddxProps={ddxData}
        >
          <AddExpressionMenu />
          <DeleteExpression />
          <CopyExpression />
          <PasteMenu />
        </FormExpressionBuilder>
      </Stack>
      {mode === "edit" && (
        <FormTextField<EligibilityCriteriaTest>
          fieldName="copy_source_description"
          label="Copy Source"
        ></FormTextField>
      )}
      <FormTextField<EligibilityCriteriaTest>
        fieldName="comments"
        label="Comments"
        multiline
      ></FormTextField>
    </Fragment>
  );
};

export const EligibilityCriteriaFormDialog: FunctionComponent<
  EligibilityCriteriaFormDialogProps
> = ({ modelId, portfolioId, ddxData, ...props }) => {
  const theme = useTheme();
  const fullScreen = useMediaQuery(theme.breakpoints.down("md"));
  const actionCode = useDialogActionCode();
  const mode = actionCode === "edit" ? "edit" : "add";

  const eligibilityCriteriaTestFormSource = useMemo<FormDataServiceSource>(
    () => ({
      idField: "id",
      mode: mode,
      get: {
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/eligibilityCriteriaTests`,
      },
      save: {
        url: `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/eligibilityCriteriaTests`,
      },
    }),
    [portfolioId, mode, modelId]
  );

  return (
    <AsyncFormDialog
      {...props}
      title={`${mode === "add" ? "Add" : "Edit"} Eligibility Criteria`}
      dataSource={
        portfolioId && modelId ? eligibilityCriteriaTestFormSource : undefined
      }
      onBeforeSave={async (data) => ({
        ...data,
        order: Number(data.order),
      })}
      fullScreen={fullScreen}
      fullWidth
      draggable={true}
      PaperProps={{ sx: getDialogResizePaperPropsSx("md") }}
      defaultData={{
        type: "A",
        comments: "",
        applicability_expression: null,
        criteria_expression: null,
        order: 1,
        effective_end_date: null,
        effective_begin_date: null,
        criteria_id: "",
        description: "",
        test_name: "",
      }}
    >
      <EligibilityCriteriaForm mode={mode} ddxData={ddxData} />
    </AsyncFormDialog>
  );
};

