interface EligibilityCriteriaTestProps {
  portfolioId?: string;
  modelId?: string;
  ecTestId: string;
  editButtonRef?: React.RefObject<HTMLButtonElement> | null;
  refreshToken?: symbol;
}

export const EligibilityCriteriaTestSummary: FunctionComponent<
  EligibilityCriteriaTestProps
> = ({ ecTestId, portfolioId, modelId, editButtonRef, refreshToken }) => {
  const axiosFactory = useAxiosFactory();
  const [ecTestDetail, setECTestDetail] =
    useState<EligibilityCriteriaTest | null>(null);
  const messageAnnouncer = useCustomMessageAnnouncer();
  const { sharedAppContextManager } = useStaticAppContext();
  const ddxData = useDdxValues();
  const { state: modelstate } = sharedAppContextManager.useContext<
    string | null
  >("app.selectedModelState");
  const urlToLoadEligibilityCriteriaTest = `/compliance-bff/v1/portfolios/${portfolioId}/models/${modelId}/eligibilityCriteriaTests/${ecTestId}`;

  useEffect(() => {
    const abortController = new AbortController();
    const loadEligibilityCriteriaTest = async () => {
      try {
        const axios = await axiosFactory.createAxiosInstance();
        const { data } = await axios.get<EligibilityCriteriaTest>(
          urlToLoadEligibilityCriteriaTest,
          { signal: abortController.signal }
        );
        setECTestDetail(data);
      } catch (error) {
        messageAnnouncer.error(
          `Failed to load Eligibility Criteria Test: ${error}`,
          error
        );
      }
    };
    loadEligibilityCriteriaTest();

    return () => abortController.abort();
  }, [
    axiosFactory,
    portfolioId,
    modelId,
    ecTestId,
    refreshToken,
    messageAnnouncer,
    urlToLoadEligibilityCriteriaTest,
  ]);

  const summaryRows: CodePair[] = useMemo(
    () => [
      {
        code: "Display Order",
        description: ecTestDetail?.order?.toString() ?? "",
      },
      { code: "EC Test ID", description: ecTestDetail?.id ?? "" },
      { code: "EC Test Name", description: ecTestDetail?.test_name ?? "" },
      {
        code: "Document Reference",
        description: ecTestDetail?.document_reference ?? "",
      },
      {
        code: "Report Reference",
        description: ecTestDetail?.report_reference ?? "",
      },
      {
        code: "Effective Begin Date",
        description: formatDate(
          ecTestDetail?.effective_begin_date ?? "",
          "M/D/YYYY"
        ),
      },
      {
        code: "Effective End Date",
        description: formatDate(
          ecTestDetail?.effective_end_date ?? "",
          "M/D/YYYY"
        ),
      },
      {
        code: "Criteria Expression",
        description: ddxFormatter.format(
          ecTestDetail?.criteria_expression?.friendly_description ?? ""
        ),
      },
      {
        code: "Copy Source",
        description: ecTestDetail?.copy_source_description ?? "",
      },
      { code: "Comments", description: ecTestDetail?.comments ?? "" },
    ],
    [ecTestDetail]
  );

  return (
    <Stack gap={0.5} direction="column" sx={detailsContainerSx}>
      <ToolGroup
        display="flex"
        sx={{ height: "32px", gap: 1, alignItems: "center" }}
        aria-label="Eligibility Criteria Information"
      >
        <Typography color="textPrimary" variant="subtitle2" fontWeight={600}>
          {"Eligibility Criteria Information"}
        </Typography>
        <Box sx={{ flexGrow: 1 }} />
        {editButtonRef ? (
          <Tooltip title="Edit">
            <span>
              <IconButton
                aria-label="Edit Eligibility Criteria Test"
                onClick={(event: React.MouseEvent<HTMLButtonElement>) => {
                  event.stopPropagation();
                  editButtonRef?.current?.click();
                }}
                disabled={modelstate === "L"}
              >
                <EditIcon size={24} />
              </IconButton>
            </span>
          </Tooltip>
        ) : null}
        <SummaryDownloadActionMenu
          filename={"Eligibility Criteria"}
          rows={summaryRows}
        />
        <ViewCustomSourceActionDialog url={urlToLoadEligibilityCriteriaTest} />
      </ToolGroup>
      {ecTestDetail ? (
        <SummaryComponent cardSx={{ mb: 1.5 }}>
          {summaryRows.map((row, index) => (
            <SummaryRow
              key={index}
              Key={row.code}
              Value={
                row.code === "Criteria Expression" ? (
                  <RuleDisplayComponent
                    value={row.description}
                    ddxData={ddxData}
                  />
                ) : (
                  row.description
                )
              }
            />
          ))}
        </SummaryComponent>
      ) : null}
    </Stack>
  );
};

export const EligibilityTestsGridActions = () => {
  const {
    modelId,
    portfolioId,
    refreshGrid,
    refreshDetails,
    editButtonRef,
    selectedModelstate,
    testsEligibilityCriteriaDelete,
    eligibilityCriteriaDataSource,
  } = useContext(EligibilityGridActionContext);
  const ddxData = useDdxValues();

  const iconButtonProps = useMemo<IconButtonProps>(() => {
    return selectedModelstate === "L" ? { disabled: true } : {};
  }, [selectedModelstate]);
  return (
    <>
      <DataGridQuickSearch></DataGridQuickSearch>
      <DataGridActionAdd
        iconButtonProps={iconButtonProps}
        dialog={
          <EligibilityCriteriaFormDialog
            modelId={modelId}
            portfolioId={portfolioId}
            ddxData={ddxData}
          ></EligibilityCriteriaFormDialog>
        }
      ></DataGridActionAdd>
      <DataGridActionEdit
        iconButtonProps={{
          ...iconButtonProps,
          ref: editButtonRef,
        }}
        onUpdateUi={refreshDetails}
        dialog={
          <EligibilityCriteriaFormDialog
            modelId={modelId}
            portfolioId={portfolioId}
            ddxData={ddxData}
          ></EligibilityCriteriaFormDialog>
        }
      ></DataGridActionEdit>
      <DataGridActionDelete
        confirmationDialogProps={{ confirmButtonLabel: "Delete" }}
        iconButtonProps={iconButtonProps}
        operation={testsEligibilityCriteriaDelete}
        rowSelectionMode="multi"
      ></DataGridActionDelete>
      <DataGridAsyncDialogAction
        actionCode="duplicate"
        label="Duplicate"
        level="grid"
        loadOnOpen={false}
        type="icon"
        icon={<DuplicateIcon size={24} />}
        iconButtonProps={iconButtonProps}
        dialog={
          <EligibilityCriteriaCopyDialog
            modelId={modelId}
            portfolioId={portfolioId}
            refreshGrid={refreshGrid}
            ddxData={ddxData}
          ></EligibilityCriteriaCopyDialog>
        }
      />

      <ActionMenu>
        <DownloadActionMenu isPopover={true} />
        <DataGridActionRefresh
          type="menuitem"
          icon={null}
        ></DataGridActionRefresh>
        <DataGridActionViewSource
          datasource={eligibilityCriteriaDataSource}
          type="menuitem"
        />
      </ActionMenu>
    </>
  );
};

